window.DECKS = [{"num": 12, "code": "01", "nameEn": "Basic Electricity", "nameEs": "Electricidad básica", "rune": "⚡", "count": 122}, {"num": 13, "code": "02", "nameEn": "Aircraft Drawings", "nameEs": "Planos y dibujo técnico", "rune": "📐", "count": 59}, {"num": 14, "code": "03", "nameEn": "Weight And Balance", "nameEs": "Peso y balance", "rune": "⚖️", "count": 53}, {"num": 15, "code": "04", "nameEn": "Fluid Lines And Fittings", "nameEs": "Líneas y conexiones de fluidos", "rune": "🔧", "count": 36}, {"num": 16, "code": "05", "nameEn": "Materials And Processes", "nameEs": "Materiales y procesos (NDT)", "rune": "🧪", "count": 95}, {"num": 17, "code": "06", "nameEn": "Ground Operation And Servicing", "nameEs": "Operación en tierra y servicio", "rune": "🛬", "count": 41}, {"num": 18, "code": "07", "nameEn": "Cleaning And Corrosion Control", "nameEs": "Limpieza y control de corrosión", "rune": "🧽", "count": 34}, {"num": 19, "code": "08", "nameEn": "Mathematics", "nameEs": "Matemáticas", "rune": "🔢", "count": 76}, {"num": 20, "code": "09", "nameEn": "Maintenance Forms And Records", "nameEs": "Formularios y registros", "rune": "📋", "count": 37}, {"num": 21, "code": "10", "nameEn": "Basic Physics", "nameEs": "Física básica", "rune": "🌡️", "count": 31}, {"num": 22, "code": "11", "nameEn": "Maintenance Publications", "nameEs": "Publicaciones de mantenimiento", "rune": "📚", "count": 42}, {"num": 23, "code": "12", "nameEn": "Mechanic Privileges And Limitations", "nameEs": "Privilegios y limitaciones del mecánico", "rune": "🛡️", "count": 38}];
window.CARDS = [{"id": "12-0", "deck": 12, "q": "The working voltage of a capacitor in an ac circuit should be", "options": ["equal to the highest applied voltage.", "at least 20 percent greater than the highest applied voltage.", "at least 50 percent greater than the highest applied voltage."], "correctIndex": 2, "explanation": "The working voltage of a capacitor is the highest voltage that can be steadily applied to it without the danger of the dielectric breaking down. The working voltage depends upon the material used as the dielectric and on its thickness. A capacitor used in an AC circuit should have a working voltage at least 50 percent greater than the highest voltage that will be applied to it.", "img": null}, {"id": "12-1", "deck": 12, "q": "The term that describes the combined resistive forces in an ac circuit is", "options": ["resistance.", "reactance.", "impedance."], "correctIndex": 2, "explanation": "Impedance, whose symbol is Z, is the combined resistive force in an AC circuit. There are three types of resistive forces in an AC circuit: inductive reactance, which causes the current to lag the voltage, capacitive reactance, which causes the current to lead the voltage, and resistance, which allows the current and voltage to remain in phase. Inductive and capacitive reactance are 180° out of phase, and they cancel each other. Impedance is the vector sum of the resistance and the total reactance in the circuit; it is expressed in ohms and is found by the formula:\nZ = The square root of (R^2 + X^2)", "img": null}, {"id": "12-2", "deck": 12, "q": "The basis for transformer operation in the use of alternating current is mutual", "options": ["inductance.", "capacitance.", "reactance."], "correctIndex": 0, "explanation": "A transformer operates on the basis of mutual inductance. The changing current in the primary windings produces a changing magnetic field whose flux cuts across the turns of the secondary winding and induces a voltage into it.", "img": null}, {"id": "12-3", "deck": 12, "q": "The opposition offered by a coil to the flow of alternating current is called (disregard resistance)", "options": ["impedance.", "reluctance.", "inductive reactance."], "correctIndex": 2, "explanation": "When alternating current flows in a coil of wire, the changing lines of flux cutting across the turns of wire in the coil induce a voltage in it. The polarity of this voltage (the counter EMF) is opposite to the polarity of the voltage that caused it. The counter EMF decreases the total voltage across the coil, and this decreases the current flowing through it. This opposition to the flow of alternating current is called inductive reactance (X(L)), and it is measured in ohms. It opposes the flow of current, but it does not cause heat nor use any power.", "img": null}, {"id": "12-4", "deck": 12, "q": "An increase in which of the following factors will cause an increase in the inductive reactance of a circuit?", "options": ["Inductance and frequency.", "Resistance and voltage.", "Resistance and capacitive reactance."], "correctIndex": 0, "explanation": "The inductive reactance (X(L)) in an AC circuit is increased when either the frequency of the alternating current or the inductance of the circuit is increased. Resistance, voltage, or capacitive reactance have no effect on the inductive reactance of a circuit. The formula for inductive reactance is: X(L) = 2(pi)fL", "img": null}, {"id": "12-5", "deck": 12, "q": "(Refer to Figure 1.) When different rated capacitors are connected in series in a circuit, the total capacitance is", "options": ["less than the capacitance of the lowest rated capacitor.", "greater than the capacitance of the highest rated capacitor.", "equal to the sum of all the capacitances."], "correctIndex": 0, "explanation": "When capacitors of different values are connected in series, the total capacitance is less than that of the lowest rated capacitor.", "img": "414608_0.jpg"}, {"id": "12-6", "deck": 12, "q": "Capacitors are sometimes used in dc circuits to", "options": ["counteract inductive reactance at specific locations.", "smooth out slight pulsations in current/voltage.", "assist in stepping voltage and current up and/or down."], "correctIndex": 1, "explanation": "Capacitors store electrical charges and are sometimes used in DC circuits to smooth out slight pulsations in the current or voltage. They accept electrons when there is an excess and release them back into the circuit when the values decrease.", "img": null}, {"id": "12-7", "deck": 12, "q": "In an ac circuit, the effective voltage is", "options": ["equal to the maximum instantaneous voltage.", "greater than the maximum instantaneous voltage.", "less than the maximum instantaneous voltage."], "correctIndex": 2, "explanation": "The effective voltage of sine wave alternating current is 0.707 time its peak voltage. The effective voltage, also called the root-mean-square (rms) voltage, is the voltage measured by most of the AC voltmeters. Peak voltage is measured with either a special peak voltmeter or an oscilloscope.", "img": null}, {"id": "12-8", "deck": 12, "q": "The amount of electricity a capacitor can store is directly proportional to the", "options": ["distance between the plates and inversely proportional to the plate area.", "plate area and is not affected by the distance between the plates.", "plate area and inversely proportional to the distance between the plates."], "correctIndex": 2, "explanation": "Three factors affect the amount of electricity a capacitor can store:\n1. The area of the plates. The larger the plate area, the greater the capacity.\n2. The thickness of the dielectric (the distance between the plates). The closer the plates are together, the stronger the electrical field will be and the greater the capacity.\n3. The material from which the dielectric is made (its dielectric constant). The higher the dielectric constant, the greater the capacity.", "img": null}, {"id": "12-9", "deck": 12, "q": "(Refer to Figure 2.) What is the total capacitance of a circuit containing three capacitors with capacitances of .02 microfarad, .05 microfarad, and .10 microfarad, respectively?", "options": [".170 uF.", "0.125 pF.", ".0125 uF."], "correctIndex": 2, "explanation": "When a 0.02-microfarad, a 0.05-microfarad, and a 0.10-microfarad capacitor are connected in series, the total capacitance is 0.0125 microfarad. Using the formula in Figure 2, C(T) = 1 ÷ [(1/.02) + (1/.05) + (1/.1)] = 0.0125 microfarad", "img": "414608_1.jpg"}, {"id": "12-10", "deck": 12, "q": "Unless otherwise specified, any values given for current or voltage in an ac circuit are assumed to be", "options": ["instantaneous values.", "effective values.", "maximum values."], "correctIndex": 1, "explanation": "Almost all measuring instruments used for electrical system servicing measure the effective (rms) values of alternating current. Unless peak values, peak-to-peak values, or average values are specifically called out, effective values are assumed.", "img": null}, {"id": "12-11", "deck": 12, "q": "When different rated capacitors are connected in parallel in a circuit, the total capacitance is\n(Note: C(T) = C(1) + C(2) + C(3) . . .)", "options": ["less than the capacitance of the lowest rated capacitor.", "equal to the capacitance of the highest rated capacitor.", "equal to the sum of all the capacitances."], "correctIndex": 2, "explanation": "When capacitors are connected in parallel, the effective area of the plates add, and the total capacitance is the sum of the individual capacitances.", "img": null}, {"id": "12-12", "deck": 12, "q": "When inductors are connected in series in a circuit, the total inductance is (where the magnetic fields of each inductor do not affect the others)\n(Note: L(T) = L(1) + L(2) + L(3) . . .)", "options": ["less than the inductance of the lowest rated inductor.", "equal to the inductance of the highest rated inductor.", "equal to the sum of the individual inductances."], "correctIndex": 2, "explanation": "When several inductors are connected together in such a way that there is no inductive coupling, the total inductance is the sum of the individual inductances.", "img": null}, {"id": "12-13", "deck": 12, "q": "(Refer to Figure 3.) When more than two inductors of different inductances are connected in parallel in a circuit, the total inductance is", "options": ["less than the inductance of the lowest rated inductor.", "equal to the inductance of the highest rated inductor.", "equal to the sum of the individual inductances."], "correctIndex": 0, "explanation": "When two or more inductors having different inductances are connected in parallel, the total inductance is less than the inductance of the lowest rated inductor.", "img": "414608_29.jpg"}, {"id": "12-14", "deck": 12, "q": "What is the total capacitance of a certain circuit containing three capacitors with capacitances of .25 microfarad, .03 microfarad, and .12 microfarad, respectively?\n(Note: C(T) = C(1) + C(2) + C(3))", "options": [".4 uF.", ".04 pF.", ".04 uF."], "correctIndex": 0, "explanation": "When three capacitors are connected in parallel, their total capacitance is the sum of the individual capacitances.\nC(T) = C(1) + C(2) + C(3)\n= 0.25 + 0.03 = 0.12\n= 0.4 microfarad", "img": null}, {"id": "12-15", "deck": 12, "q": "Which requires the most electrical power during operation?\n(Note: 1 horsepower = 746 watts)", "options": ["A 12-volt motor requiring 8 amperes.", "Four 30-watt lamps in a 12-volt parallel circuit.", "Two lights requiring 3 amperes each in a 24-volt parallel system."], "correctIndex": 2, "explanation": "The 12-volt motor requires 96 watts of power. The four 30-watt lamps require 120 watts of power. The two 24-volt, 3-amp lights require 144 watts of power.", "img": null}, {"id": "12-16", "deck": 12, "q": "How much power must a 24-volt generator furnish to a system which contains the following loads?\nUNIT                                                  RATING\nOne motor (75 percent efficient)       1/5 hp\nThree position lights                          20 watts each\nOne heating element                         5 amp\nOne anticollision light                        3 amp\n(Note: 1 horsepower = 746 watts)", "options": ["402 watts.", "385 watts.", "450 watts."], "correctIndex": 2, "explanation": "The motor is 1/5 hp, therefore 746 watts (1hp) / 5 = 149 watts. This is the output of the engine. It takes more energy to produce 149 watts -- find this with the efficiency rating, 149/X = 75/100; X = 199. Therefore, the 1/5-horsepower motor that is 75 percent efficient requires 199 watts. The three position lights require a total of 60 watts. The heating element requires 120 watts. The anticollision light requires 72 watts. The total power the generator must produce is 451 watts.", "img": null}, {"id": "12-17", "deck": 12, "q": "A 12-volt electric motor has 1,000 watts input and 1 horsepower output. Maintaining the same efficiency, how much input power will a 24-volt, 1-horsepower electric motor require\n(Note: 1 horsepower = 746 watts)", "options": ["1,000 watts.", "2,000 watts.", "500 watts."], "correctIndex": 0, "explanation": "The power produced by an electric motor is the product of its voltage and its current. A 12-volt motor will require 83.3 amps of current for its 1,000 watts of input power to produce 746 watts (1 horsepower) of output power. A 24-volt motor operating at the same efficiency will also require 1,000 watts of input power for its 746 watts of output power, but it will need only 41.7 amps of current.", "img": null}, {"id": "12-18", "deck": 12, "q": "How many amperes will a 28-volt generator be required to supply to a circuit containing five lamps in parallel, three of which have a resistance of 6 ohms each and two of which have a resistance of 5 ohms each?", "options": ["1.11 amperes.", "1 ampere.", "25.23 amperes."], "correctIndex": 2, "explanation": "A current of 4.67 amps flows through each of the three six-ohm lamps. And a current of 5.6 amps flows through each of the five-ohm lamps. Since all of these lamps are in parallel, the total current is the sum of the currents flowing through each lamp. The total current is 25.21 amps.", "img": null}, {"id": "12-19", "deck": 12, "q": "A 1-horsepower, 24-volt dc electric motor that is 80 percent efficient requires 932.5 watts. How much power will a 1-horsepower, 12-volt dc electric motor that is 75 percent efficient require?\n(Note: 1 horsepower = 746 watts)", "options": ["932.5 watts.", "1,305.5 watts.", "994.6 watts."], "correctIndex": 2, "explanation": "When we know the horsepower output and the efficiency of an electric motor, the voltage does not enter into the computation. To find the number of watts required, divide the wattage for the total horsepower by the decimal equivalent of the efficiency.\n746 ÷ 0.75 = 994.6 watts", "img": null}, {"id": "12-20", "deck": 12, "q": "The potential difference between two conductors which are insulated from each other is measured in", "options": ["volts.", "amperes.", "coulombs."], "correctIndex": 0, "explanation": "The potential difference between two conductors is a measure of the electrical pressure difference between the conductors. Electrical pressure is measured in volts.", "img": null}, {"id": "12-21", "deck": 12, "q": "A 24-volt source is required to furnish 48 watts to a parallel circuit consisting of four resistors of equal value. What is the voltage drop across each resistor?", "options": ["12 volts.", "6 volts.", "24 volts."], "correctIndex": 2, "explanation": "Since the resistors are all in parallel across the 24-volt power source, each resistor has the entire 24 volts dropped across it.", "img": null}, {"id": "12-22", "deck": 12, "q": "When calculating power in a reactive or inductive ac circuit, the true power is", "options": ["more than the apparent power.", "less than the apparent power in a reactive circuit and more than the apparent power in an inductive circuit.", "less than the apparent power."], "correctIndex": 2, "explanation": "True power in an AC circuit is the product of the circuit voltage and only that part of the current in phase with the voltage. Apparent power is the circuit voltage multiplied by all of the current. True power is always less than the apparent power in a reactive circuit which is any AC circuit containing either inductance or capacitance.", "img": null}, {"id": "12-23", "deck": 12, "q": "(Refer to Figure 4.) How much power is being furnished to the circuit?", "options": ["575 watts.", "2,875 watts.", "2,645 watts."], "correctIndex": 2, "explanation": "This is a resistive circuit. The power is the product of the square of the current times the resistance.\nP = I^2 x R = 23^2 x 5 = 2,645 watts", "img": "414608_30.jpg"}, {"id": "12-24", "deck": 12, "q": "(Refer to Figure 5.) What is the impedance of an ac-series circuit consisting of an inductor with a reactance of 10 ohms, a capacitor with a reactance of 4 ohms, and a resistor with a resistance of 8 ohms?", "options": ["22 ohms.", "5.29 ohms.", "10 ohms."], "correctIndex": 2, "explanation": "The total reactance in this circuit is the difference between the inductive reactance and the capacitive reactance. Total reactance is 10 - 4 = 6 ohms. The impedance is the square root of the resistance squared plus the reactance squared. This is the square root of 64 plus 36, or the square root of 100. The circuit impedance is 10 ohms.", "img": "414608_4.jpg"}, {"id": "12-25", "deck": 12, "q": "(Refer to Figure 6.) If resistor R(5) is disconnected at the junction of R(4) and R(3) as shown, what will the ohmmeter read?", "options": ["2.76 ohms.", "3 ohms.", "12 ohms."], "correctIndex": 1, "explanation": "With resistor R(5) disconnected, the ohmmeter reads the parallel resistance of R(1) and R(2) in parallel with R(4) and R(3), which are in series. The total resistance is found by the formula:\nRp = 1 / [1/R1 + 1/R2 + 1/(R3 + R4)]\n= 1 / [1/12 + 1/6 + 1/(6 + 6)]\n= 3 ohms.", "img": "414608_5.jpg"}, {"id": "12-26", "deck": 12, "q": "(Refer to Figure 7.) If resistor R(3) is disconnected at terminal D, what will the ohmmeter read?", "options": ["Infinite resistance.", "10 ohms.", "20 ohms."], "correctIndex": 0, "explanation": "When resistor R(3) is disconnected at terminal D, it is isolated from the rest of the circuit, and the ohmmeter will read only the resistance of R(3). Because R(3) is open (it has a break in it), its resistance is infinite.", "img": "414608_6.jpg"}, {"id": "12-27", "deck": 12, "q": "(Refer to Figure 8.) With an ohmmeter connected into the circuit as shown, what will the ohmmeter read?", "options": ["20 ohms.", "Infinite resistance.", "10 ohms."], "correctIndex": 2, "explanation": "The ohmmeter will read the resistance of R(1) and R(2) in parallel; this is 10 ohms. The open circuit (break) in resistor R(3) gives it an infinite resistance, and it does not affect the reading of the ohmmeter.", "img": "414608_7.jpg"}, {"id": "12-28", "deck": 12, "q": "(Refer to Figure 9.) How many instruments (voltmeters and ammeters) are installed correctly?", "options": ["Three.", "One.", "Two."], "correctIndex": 2, "explanation": "The first ammeter is installed across the voltage. This is wrong; the ammeter will burn out. The first voltmeter will measure the source voltage (the voltage of the battery), but its polarity is wrong. It will read backward. The voltmeter across the light bulb is installed correctly. The ammeter in series with the light bulb and the battery is correct. It will read the current flowing through the light bulb.", "img": "414608_8.jpg"}, {"id": "12-29", "deck": 12, "q": "The correct way to connect a test voltmeter in a circuit is", "options": ["in series with a unit.", "between the source voltage and the load.", "in parallel with a unit."], "correctIndex": 2, "explanation": "A voltmeter must always be connected in a circuit in parallel with the unit whose voltage is to be measured.", "img": null}, {"id": "12-30", "deck": 12, "q": "Which term means .001 ampere?", "options": ["Microampere.", "Kiloampere.", "Milliampere."], "correctIndex": 2, "explanation": "The metric prefix 'milli-' means one thousandth. 0.001 ampere is one milliampere.", "img": null}, {"id": "12-31", "deck": 12, "q": "A cabin entry light of 10 watts and a dome light of 20 watts are connected in parallel to a 30-volt source. If the voltage across the 10-watt light is measured, it will be", "options": ["equal to the voltage across the 20-watt light.", "half the voltage across the 20-watt light.", "one-third of the input voltage."], "correctIndex": 0, "explanation": "When lights are connected in parallel across a voltage source, the voltage across each of the lights will be the same as the voltage of the source.", "img": null}, {"id": "12-32", "deck": 12, "q": "A 14-ohm resistor is to be installed in a series circuit carrying .05 ampere. How much power will the resistor be required to dissipate?", "options": ["At least .70 milliwatt.", "At least 35 milliwatts.", "Less than .035 watt."], "correctIndex": 1, "explanation": "Power dissipated in a resistor is found by multiplying its resistance by the square of the current.\nP = I^2 x R = 0.05^2 x 14 = 0.035 watts.\n0.035 watts is 35 milliwatts.", "img": null}, {"id": "12-33", "deck": 12, "q": ".002KV equals", "options": ["20 volts.", "2.0 volts.", ".2 volt."], "correctIndex": 1, "explanation": "A KV is a kilovolt, or 1,000 volts. Two thousandths (.002) of a kilovolt is equal to 2.0 volts.", "img": null}, {"id": "12-34", "deck": 12, "q": "(Refer to Figure 10.) What is the measured voltage of the series-parallel circuit between terminals A and B?", "options": ["1.5 volts.", "3.0 volts.", "4.5 volts."], "correctIndex": 1, "explanation": "The two batteries on the left side are connected in series, and the two batteries on the right side are connected in series. The two pairs of batteries are connected in parallel. The series connections between terminals A and B give this circuit a voltage of 3.0 volts.", "img": "414608_9.jpg"}, {"id": "12-35", "deck": 12, "q": "(Refer to Figure 64.) A 24-volt source is required to furnish 48 watts to a parallel circuit consisting of two resistors of equal value. What is the value of each resistor?\n(Note: R(t) = E^2/P)", "options": ["24 ohms.", "12 ohms.", "6 ohms."], "correctIndex": 0, "explanation": "To solve this problem, first find the total resistance of the circuit.\nR(T) = E^2 ÷ P\n= 24^2 ÷ 48\n= 12 ohms\nThere are two resistors of equal value in parallel that provide this resistance, therefore each resistor must have a resistance of twice this value, or 24 ohms.", "img": "414608_10.jpg"}, {"id": "12-36", "deck": 12, "q": "Which requires the most electrical power?\n(Note: 1 horsepower = 746 watts)", "options": ["A 1/5-horsepower, 24-volt motor which is 75 percent efficient.", "Four 30-watt lamps arranged in a 12-volt parallel circuit.", "A 24-volt anticollision light circuit consisting of two light assemblies which require 3 amperes each during operation."], "correctIndex": 0, "explanation": "The 1/5-horsepower motor operating at 75 percent efficiency uses 198.93 watts of power. The four 30-watt lamps use 120 watts of power. The anticollision light circuit uses 144 watts of power.", "img": null}, {"id": "12-37", "deck": 12, "q": "What unit is used to express electrical power?", "options": ["Volt.", "Watt.", "Ampere."], "correctIndex": 1, "explanation": "The volt is a measure of electrical pressure. The watt is a measure of electrical power. The ampere is a measure of electrical current flow.", "img": null}, {"id": "12-38", "deck": 12, "q": "What is the operating resistance of a 30-watt light bulb designed for a 28-volt system?", "options": ["1.07 ohms.", "26 ohms.", "0.93 ohm."], "correctIndex": 1, "explanation": "A 30-watt light bulb operating in a 28-volt electrical system has a hot resistance (operating resistance) of 26.13 ohms.\nR = E^2 ÷ P\n= 28^2 ÷ 30\n= 26.12 omega", "img": null}, {"id": "12-39", "deck": 12, "q": "Which statement is correct when made in reference to a parallel circuit?", "options": ["The current is equal in all portions of the circuit.", "The total current is equal to the sum of the currents through the individual branches of the circuit.", "The current in amperes can be found by dividing the EMF in volts by the sum of the resistors in ohms."], "correctIndex": 1, "explanation": "According to Kirchhoff's current law, the current flowing in a parallel circuit is equal to the sum of the currents flowing through each of the individual branches of the circuit.", "img": null}, {"id": "12-40", "deck": 12, "q": "Which of the following are commonly used as rectifiers in electrical circuits?|1. Anodes.|2. Cathodes.|3. Diodes", "options": ["3, 1.", "3, 2.", "3."], "correctIndex": 2, "explanation": "Diodes are two element electronic components that act as electron check valves. They allow electrons to pass freely in one direction but block their flow in the opposite direction. They are used as rectifiers in electrical circuits.", "img": null}, {"id": "12-41", "deck": 12, "q": "Diodes are used in electrical power supply circuits primarily as", "options": ["switches.", "rectifiers.", "relays."], "correctIndex": 1, "explanation": "A diode (either a semiconductor diode or an electron-tube diode) is an electron check valve. A diode allows electrons to pass in one direction, but blocks their flow in the reverse direction. This is the action of a rectifier.", "img": null}, {"id": "12-42", "deck": 12, "q": "Transfer of electric energy from one circuit to another without the aid of electrical connections", "options": ["is called induction.", "is called capacitance.", "can cause excessive arcing and heat, and as a result is practical for use only with low voltages/amperages."], "correctIndex": 0, "explanation": "The continually changing current in an AC circuit causes a changing magnetic field to cut across conductors in an adjacent circuit. When the changing field cuts across a conductor, it induces a voltage in it. Induction allows electrical energy to be transferred from one circuit to another without the aid of electrical connections.", "img": null}, {"id": "12-43", "deck": 12, "q": "If three resistors of 3 ohms, 5 ohms, and 22 ohms are connected in series in a 28-volt circuit, how much current will flow through the 3-ohm resistor?", "options": ["9.3 amperes.", "1.05 amperes.", "0.93 ampere."], "correctIndex": 2, "explanation": "In a series circuit, the total resistance is the sum of the individual resistances. In this circuit, the total resistance is 30 ohms. All of the current flows through each resistor. Therefore, the current through each resistor is 0.93 amp.\nI = E ÷ R\n= 28 ÷ 3 + 5 + 22\n= 28 ÷ 30\n= 0.933 amp", "img": null}, {"id": "12-44", "deck": 12, "q": "A circuit has an applied voltage of 30 volts and a load consisting of a 10-ohm resistor in series with a 20-ohm resistor. What is the voltage drop across the 10-ohm resistor?", "options": ["10 volts.", "20 volts.", "30 volts."], "correctIndex": 0, "explanation": "In a series circuit, the voltage drop across each resistor is determined by its resistance. In this circuit, the total resistance is 30 ohms, and the total voltage is 30 volts. One amp of current flows through each resistor and this gives a 10-volt drop across the 10-ohm resistor.\nE = I x R\n= 1 x 10\n= 10 volts", "img": null}, {"id": "12-45", "deck": 12, "q": "(Refer to Figure 11.) Find the total current flowing in the wire between points C and D.", "options": ["6.0 amperes.", "2.4 amperes.", "3.0 amperes."], "correctIndex": 2, "explanation": "The total resistance between points D-E and G-H is 8 ohms. This is the resistance of resistors R(2) and R(3) in parallel. There is a voltage of 24 volts across these two parallel resistors, so the current through the line between C and D is three amps.", "img": "414608_11.jpg"}, {"id": "12-46", "deck": 12, "q": "(Refer to Figure 11.) Find the voltage across the 8-ohm resistor.", "options": ["8 volts.", "20.4 volts.", "24 volts."], "correctIndex": 2, "explanation": "The 8-ohm resistor, R(1), is across the full 24 volts of the battery.", "img": "414608_28.jpg"}, {"id": "12-47", "deck": 12, "q": "(Refer to Figure 12.) Find the total resistance of the circuit.", "options": ["16 ohms.", "2.6 ohms.", "21.2 ohms."], "correctIndex": 0, "explanation": "This problem can be solved in four steps:\n1. Combine resistors R(4) and R(5) in parallel.\n2. Combine resistor R(2) with R(4-5) in series.\n3. Combine resistors R(2-4-5) with R(3) in parallel.\n4. Combine resistors R(2-3-4-5) with R(1) in series.", "img": "414608_12.jpg"}, {"id": "12-48", "deck": 12, "q": "Which is correct in reference to electrical resistance?", "options": ["Two electrical devices will have the same combined resistance if they are connected in series as they will have if connected in parallel.", "If one of three bulbs in a parallel lighting circuit is removed, the total resistance of the circuit will become greater.", "An electrical device that has a high resistance will use more power than one with a low resistance with the same applied voltage."], "correctIndex": 1, "explanation": "In a parallel electrical circuit, each bulb provides a path for current to flow. The more paths there are, the less the circuit resistance will be. When one bulb is removed, the circuit resistance increases.", "img": null}, {"id": "12-49", "deck": 12, "q": "What happens to the current in a voltage step-up transformer with a ratio of 1 to 4?", "options": ["The current is stepped down by a 1 to 4 ratio.", "The current is stepped up by a 1 to 4 ratio.", "The current does not change."], "correctIndex": 0, "explanation": "The power (voltage times current) in the secondary of a transformer is equal to the power in the primary. When the voltage in the secondary is four times that in the primary, the current in the secondary is one fourth of that in the primary.", "img": null}, {"id": "12-50", "deck": 12, "q": "(Refer to Figure 13.) Determine the total current flow in the circuit.", "options": ["0.2 ampere.", "1.4 amperes.", "0.8 ampere."], "correctIndex": 1, "explanation": "The total resistance of this circuit is 8.57 ohms. The total current flowing in this circuit is 1.4 amps.", "img": "414608_13.jpg"}, {"id": "12-51", "deck": 12, "q": "(Refer to Figure 14.) The total resistance of the circuit is", "options": ["25 ohms.", "35 ohms.", "17 ohms."], "correctIndex": 0, "explanation": "The total resistance can be found in two steps:\n1. Combine resistances R(2), R(3), and R(4) in parallel.\n2. Combine resistances R(1), R(2-3-4), and R(5) in series.", "img": "414608_14.jpg"}, {"id": "12-52", "deck": 12, "q": "Which of these will cause the resistance of a conductor to decrease?", "options": ["Decrease the length or the cross-sectional area.", "Decrease the length or increase the cross-sectional area.", "Increase the length or decrease the cross-sectional area."], "correctIndex": 1, "explanation": "The resistance of a conductor varies directly as its length, inversely as its cross-sectional area, and directly with the resistivity of its material. Either decreasing the length or increasing the cross-sectional area of a conductor will cause its resistance to decrease.", "img": null}, {"id": "12-53", "deck": 12, "q": "Through which material will magnetic lines of force pass the most readily?", "options": ["Copper.", "Iron.", "Aluminum."], "correctIndex": 1, "explanation": "The permeability of a material is a measure of the ease with which lines of magnetic force can pass through it. Iron has the highest permeability of all the metals listed in this question.", "img": null}, {"id": "12-54", "deck": 12, "q": "(Refer to Figure 64.) A 48-volt source is required to furnish 192 watts to a parallel circuit consisting of three resistors of equal value. What is the value of each resistor?", "options": ["36 ohms.", "4 ohms.", "12 ohms."], "correctIndex": 0, "explanation": "The total resistance needed to dissipate 192 watts of electrical power from a 48-volt source is 12 ohms.\nR(T) = E^2 ÷ P\n= 48^2 ÷ 192\n= 12 omega\nSince three resistors in parallel give 12 ohms, each resistor must have a resistance three times this value.\nR = R(T) x n\n= 12 x 3\n= 36 omega", "img": "414608_15.jpg"}, {"id": "12-55", "deck": 12, "q": "Which is correct concerning a parallel circuit?", "options": ["Total resistance will be smaller than the smallest resistor.", "Total resistance will decrease when one of the resistances is removed.", "Total voltage drop is the same as the total resistance."], "correctIndex": 0, "explanation": "In a parallel circuit each resistor forms a path for the current to follow and the total resistance is always smaller than that of the smallest resistor.", "img": null}, {"id": "12-56", "deck": 12, "q": "The voltage drop in a circuit of known resistance is dependent on", "options": ["the voltage of the circuit.", "only the resistance of the conductor and does not change with a change in either voltage or amperage.", "the amperage of the circuit."], "correctIndex": 2, "explanation": "The voltage drop across a circuit is determined by two things: the resistance of the conductor and the amount of current flowing through it (the amperage). In this question, the resistance of the circuit is fixed; therefore, the voltage drop is determined by the amperage in the circuit.", "img": null}, {"id": "12-57", "deck": 12, "q": "A thermal switch, or thermal protector, as used in an electric motor, is designed to", "options": ["close the integral fan circuit to allow cooling of the motor.", "open the circuit in order to allow cooling of the motor.", "reroute the circuit to ground."], "correctIndex": 1, "explanation": "A thermal switch is another name for a built-in thermal circuit breaker. This is a circuit protection device that opens the circuit when the windings of the motor get too hot. If the motor overheats for any reason, the thermal switch will open the power circuit to the motor and allow the motor to cool.", "img": null}, {"id": "12-58", "deck": 12, "q": "(Refer to Figure 15.) With the landing gear retracted, the red indicator light will not come on if an open occurs in wire", "options": ["No. 19.", "No. 7.", "No. 17."], "correctIndex": 0, "explanation": "With the landing gear retracted, the red indicator light will not come on if there is an open in wire No. 19. Wire No. 19 supplies power from the bus to the red indicator light, through the up-limit switch and through wire No. 8. Wire No. 7 supplies power to the red indicator light for the press-to-test circuit. Wire No. 17 supplies power to the green indicator light for its press-to-test circuit.", "img": "414608_16.jpg"}, {"id": "12-59", "deck": 12, "q": "(Refer to Figure 15.) The No. 7 wire is used to", "options": ["close the PUSH-TO-TEST circuit.", "open the UP indicator light circuit when the landing gear is retracted.", "close the UP indicator light circuit when the landing gear is retracted."], "correctIndex": 0, "explanation": "Wire No. 7 supplies power to both the red and green indicator lights from the 5-amp circuit breaker. When either of the press-to-test lamps is pushed, the circuit is completed to ground, allowing the lamp to light up as long as it remains pressed. Press-to-test lamps are used to allow the pilot to ascertain that the bulb in the lamp is good.", "img": "414608_16.jpg"}, {"id": "12-60", "deck": 12, "q": "(Refer to Figure 15.) When the landing gear is down, the green light will not come on if an open occurs in wire", "options": ["No. 7.", "No. 6.", "No. 17."], "correctIndex": 1, "explanation": "The green light will not come on when the landing gear is down if there is an open in wire No. 6. (Note: The switches in Figure 15 are shown in the position for the gear down and the airplane on the ground.) Wire No. 7 supplies power to both the red and green indicator lights from the 5-amp circuit breaker for the push-to-test circuit. Wire No. 17 supplies power to the green indicator light for its push-to-test circuit.", "img": "414608_16.jpg"}, {"id": "12-61", "deck": 12, "q": "(Refer to Figure 16.) What will be the effect if the PCO relay fails to operate when the left-hand tank is selected?", "options": ["The fuel pressure crossfeed valve will not open.", "The fuel tank crossfeed valve open light will illuminate.", "The fuel pressure crossfeed valve open light will not illuminate."], "correctIndex": 2, "explanation": "Relay PCO provides 24-volt DC power from the bus through a 5-amp circuit breaker to the Fuel Pressure Crossfeed Valve Open caution warning light in the cockpit. If relay PCO fails to operate, contacts 13 will not complete the circuit and the light will not illuminate, but the rest of the system will operate normally.", "img": "414608_17.jpg"}, {"id": "12-62", "deck": 12, "q": "(Refer to Figure 16.) The TCO relay will operate if 24-volts dc is applied to the bus and the fuel tank selector is in the", "options": ["right-hand tank position.", "crossfeed position.", "left-hand tank position."], "correctIndex": 1, "explanation": "The fuel-selector switch must be in the Crossfeed (X-Feed) position for the relay TCO to close contacts 14. When the tank selector is put in the X-Feed position, contacts 17 of relay FCF close, and current flows from the 24-volt DC bus, through a five-amp circuit breaker, into the 'open' coils of the fuel tank X-feed valve motor. When the motor opens this valve, contacts 19 close and current flows to relay TCO closing contacts 14.", "img": "414608_17.jpg"}, {"id": "12-63", "deck": 12, "q": "(Refer to Figure 16.) With power to the bus and the fuel selector switched to the right-hand tank, how many relays in the system are operating?", "options": ["Three.", "Two.", "Four."], "correctIndex": 0, "explanation": "When the fuel selector switch is in the right-hand tank position and power is supplied from the bus, three relays (RTS, PCO, and TCC) will actuate. Current flowing through the fuel-selector switch energizes the coil for relay RTS. This closes contacts 8 and opens contacts 7. Current from the bus flows through closed contacts 5 of relay LTS, through contacts 8 of relay RTS that has just closed, and through the 'open' winding of the fuel pressure X-Feed valve motor. As soon as this motor fully opens the valve, contacts 12 close and energize relay PCO to close contacts 13 in the circuit for the Fuel Pressure Crossfeed Valve Open light. Current flows from the bus through the right-hand five-amp circuit breaker and through the normally closed contacts 18 of the FCF relay, through contacts 20 in the Fuel Tank crossfeed valve to the coil of relay TCC which opens its contacts 16.", "img": "414608_17.jpg"}, {"id": "12-64", "deck": 12, "q": "(Refer to Figure 16.) When electrical power is applied to the bus, which relays are energized?", "options": ["PCC and TCC.", "TCC and TCO.", "PCO and PCC."], "correctIndex": 0, "explanation": "As soon as electrical power is supplied to the 24-volt bus, two relays, PCC and TCC, are energized. Current flows from the bus through the left-hand, five-amp circuit breaker and through contacts 5, 7, and 9 of the relays controlled by the fuel selector switch. It flows from contacts 9, through contacts 11 in the Fuel Pressure X-Feed valve, to the coil of relay PCC. At the same time, current flows through the right-hand five-amp circuit breaker, through contacts 18 and then through contacts 20 in the Fuel Tank X-Feed valve to the coil of relay TCC.", "img": "414608_17.jpg"}, {"id": "12-65", "deck": 12, "q": "(Refer to Figure 16.) Energize the circuit with the fuel tank selector switch selected to the left-hand position. Using the schematic, identify the switches that will change position.", "options": ["5, 9, 10, 11, 12, 13, 15.", "3, 5, 6, 7, 11, 13.", "5, 6, 11, 12, 13, 15, 16."], "correctIndex": 2, "explanation": "When power is supplied to the bus with the fuel selector switch in the left-hand position, seven switches change their position (5, 6, 11, 12, 13, 15, and 16). Current flows from the bus through the left-hand, five-amp circuit breaker, through the LH Tank position of the fuel selector switch, into the coil of relay LTS. This changes the position of switches 5 and 6.\nSince current can no longer flow through switch 5, the coil of relay PCC is de-energized and this changes the position of switch 15. Current can now flow through switch 6 into the 'open' motor coil of the fuel-pressure X-Feed valve. When this valve is open, switches 11 and 12 change their position. Current now flows through switch 12 to the coil of relay PCO. This closes switch 13.\nAt the same time all of this is happening, current is flowing from the right-hand, five-amp circuit breaker, through switches 18 and 20, to the coil of relay TCC. When relay TCC is energized, it changes the position of switch 16.", "img": "414608_17.jpg"}, {"id": "12-66", "deck": 12, "q": "(Refer to Figure 17.) Which of the components is a potentiometer?", "options": ["5", "3", "11"], "correctIndex": 1, "explanation": "The component identified as 5 is a variable capacitor. The component identified as 3 is a potentiometer. The component identified as 11 is an inductor (choke).", "img": "414608_18.jpg"}, {"id": "12-67", "deck": 12, "q": "(Refer to Figure 17.) The electrical symbol represented at number 5 is a variable", "options": ["inductor.", "resistor.", "capacitor."], "correctIndex": 2, "explanation": "An inductor is shown by symbol 11. A variable resistor (potentiometer) is shown by symbol 3. A variable capacitor is shown by symbol 5.", "img": "414608_18.jpg"}, {"id": "12-68", "deck": 12, "q": "(Refer to Figure 18.) When the landing gears are up and the throttles are retarded, the warning horn will not sound if an open occurs in wire", "options": ["No. 4.", "No. 2.", "No. 9."], "correctIndex": 0, "explanation": "Wire No. 4 is in the landing gear warning horn ground circuit. If it is open, the warning horn cannot sound when the landing gears are up and the throttles are retarded. Wire No. 2 is in the red warning-light circuit and not in the warning horn circuit. Wire No. 9 is in the green light circuit.", "img": "414608_19.jpg"}, {"id": "12-69", "deck": 12, "q": "(Refer to Figure 18.) The control valve switch must be placed in the neutral position when the landing gears are down to", "options": ["permit the test circuit to operate.", "prevent the warning horn from sounding when the throttles are closed.", "remove the ground from the green light."], "correctIndex": 1, "explanation": "If the control-valve switch were not in the neutral position, as shown here, the landing gear warning horn would sound when either throttle is closed and both landing gears are down. The ground for the horn would be supplied through wire 6, the closed throttle switch, wires 5 and 10, the control valve switch, wire 11, the right gear switch, wire 3, the left gear switch, and wire 14 to ground.", "img": "414608_19.jpg"}, {"id": "12-70", "deck": 12, "q": "(Refer to Figure 19.) Under which condition will a ground be provided for the warning horn through both gear switches when the throttles are closed?", "options": ["Right gear up and left gear down.", "Both gears up and the control valve out of neutral.", "Left gear up and right gear down."], "correctIndex": 2, "explanation": "A ground for the landing gear warning horn is provided through both of the gear switches only when the right landing gear is down and the left landing gear is up. Ground current from the warning horn flows through wire 11, through a closed throttle switch, through wire 12, through the left gear switch in its UP position, through wire 5, through the right gear switch in its DOWN position, to ground.", "img": "414608_20.jpg"}, {"id": "12-71", "deck": 12, "q": "(Refer to Figure 19.) When the throttles are retarded with only the right gear down, the warning horn will not sound if an open occurs in wire", "options": ["No. 5.", "No. 13.", "No. 6."], "correctIndex": 0, "explanation": "Wire 5 is in the landing gear warning horn ground circuit. If there is an open in this wire, the warning horn cannot get a ground when the right landing gear is down and the left gear is not down. Wire 13 is not in the warning horn circuit if the left landing gear is not down. Wire 6 is in the warning horn test circuit.", "img": "414608_20.jpg"}, {"id": "12-72", "deck": 12, "q": "(Refer to Figure 19.) When the landing gears are up and the throttles are retarded, the warning horn will not sound if an open occurs in wire", "options": ["No. 5.", "No. 7.", "No. 6."], "correctIndex": 2, "explanation": "Wire 6 is in the ground circuit for the landing gear warning horn. The horn will not sound if there is an open in this wire when the throttles are retarded and the landing gears are up. Wire 5 is not in the warning horn ground circuit when the right landing gear is up. Wire 7 is not in the warning horn ground circuit.", "img": "414608_20.jpg"}, {"id": "12-73", "deck": 12, "q": "When referring to an electrical circuit diagram, what point is considered to be at zero voltage?", "options": ["The circuit breaker.", "The switch.", "The ground reference."], "correctIndex": 2, "explanation": "The ground reference, shown on a schematic diagram as a triangular-shaped series of parallel lines, is the point considered to be at zero voltage. All voltages, both positive and negative, are measured from this ground reference.", "img": null}, {"id": "12-74", "deck": 12, "q": "What is the purpose of the ground symbol used in electrical circuit diagrams?", "options": ["To show that there is common bus for connection of the source of electrical energy to the load.", "To show the source of electrical energy for the load.", "To show that there is a return path for the current between the source of electrical energy and the load."], "correctIndex": 2, "explanation": "The ground symbol used on electrical schematic diagrams indicates that there is a return path for the current between the source of electrical energy and the load.", "img": null}, {"id": "12-75", "deck": 12, "q": "(Refer to Figure 20.) Troubleshooting an open circuit with a voltmeter as shown in this circuit will", "options": ["permit current to flow and illuminate the lamp.", "create a low resistance path and the current flow will be greater than normal.", "permit the battery voltage to appear on the voltmeter."], "correctIndex": 2, "explanation": "An open in the resistor will cause an infinite resistance. No current can flow in the circuit. Since no current flows, there is no voltage drop across the switch or the lamp, and the entire battery voltage is read on the voltmeter.", "img": "414608_21.jpg"}, {"id": "12-76", "deck": 12, "q": "(Refer to Figure 21.) Which symbol represents a variable resistor?", "options": ["2", "1", "3"], "correctIndex": 0, "explanation": "1 is a tapped resistor.\n2 is a variable resistor (rheostat). This is not the most widely used symbol as it can be used only for a rheostat (a variable resistor with only two connections) and not for a potentiometer.\n3 is a tapped resistor -- tapped at two places.", "img": "414608_22.jpg"}, {"id": "12-77", "deck": 12, "q": "In a P-N-P transistor application, the solid state device is turned on when the", "options": ["base is negative with respect to the emitter.", "base is positive with respect to the emitter.", "emitter is negative with respect to the base."], "correctIndex": 0, "explanation": "A P-N-P transistor conducts between the emitter and collector (is turned on) when a small amount of current flows into the base. This current flows when the emitter-base junction is forward biased. It is forward biased when the base is negative with respect to the emitter.", "img": null}, {"id": "12-78", "deck": 12, "q": "In an N-P-N transistor application, the solid state device is turned on when the", "options": ["emitter is positive with respect to the base.", "base is negative with respect to the emitter.", "base is positive with respect to the emitter."], "correctIndex": 2, "explanation": "An N-P-N transistor conducts between the emitter and collector (is turned on) when a small amount of current flows from the base. This current flows when the emitter-base junction is forward biased. It is forward biased when the base is positive with respect to the emitter.", "img": null}, {"id": "12-79", "deck": 12, "q": "Typical application for zener diodes is as", "options": ["full-wave rectifiers.", "half-wave rectifiers.", "voltage regulators."], "correctIndex": 2, "explanation": "A zener diode is a special type of semiconductor diode that is designed to operate with current flowing through it in its reverse direction. When a specific amount of inverse voltage is applied between the cathode and anode, the diode breaks down and conducts in its reverse direction. This principle is used as the voltage-sensing element in a voltage regulator.", "img": null}, {"id": "12-80", "deck": 12, "q": "(Refer to Figure 22.) Which illustration is correct concerning bias application and current (positive charge) flow?", "options": ["1", "2", "3"], "correctIndex": 0, "explanation": "In 1, the base of this N-P-N transistor is positive with respect to the emitter (the emitter-base junction is forward biased). Base-emitter current flows and therefore collector emitter current flows as is shown by the current-flow arrow. In 2, the base and emitter of this N-P-N transistor have the same polarity and no emitter-base current flows. There is no flow between the emitter and the collector. In 3, the base and emitter of this P-N-P transistor have the same polarity, and no emitter-base current flows. There is no flow between the emitter and the collector.", "img": "414608_23.jpg"}, {"id": "12-81", "deck": 12, "q": "Forward biasing of a solid state device will cause the device to", "options": ["conduct via zener breakdown.", "conduct.", "turn off."], "correctIndex": 1, "explanation": "When a solid-state device such as a diode is forward biased, the N-material is negative with respect to the P-material. A forward-biased device will conduct.", "img": null}, {"id": "12-82", "deck": 12, "q": "(Refer to Figure 23.) If an open occurs at R(1), the light", "options": ["cannot be turned on.", "will not be affected.", "cannot be turned off."], "correctIndex": 2, "explanation": "If there is an open circuit in R(1), the base and the collector will have the same voltage. The base current will be maximum, and the light cannot be turned off.", "img": "414608_24.jpg"}, {"id": "12-83", "deck": 12, "q": "(Refer to Figure 23.) If R(2) sticks in the up position, the light will", "options": ["be on full bright.", "be very dim.", "not illuminate."], "correctIndex": 0, "explanation": "An N-P-N transistor circuit such as this conducts the maximum amount of current between the emitter and collector (the lamp is burning brightest) when the maximum amount of current is flowing from the base. This occurs when the base is most positive with respect to the emitter. This would be the case if R(2) were stuck in the up position.", "img": "414608_24.jpg"}, {"id": "12-84", "deck": 12, "q": "(Refer to Figure 24.) Which statement concerning the depicted logic gate is true?", "options": ["Any input being 1 will produce a 0 output.", "Any input being 1 will produce a 1 output.", "All inputs must be 1 to produce a 1 output."], "correctIndex": 1, "explanation": "This is an OR gate. Any time there is a 1 on any of the inputs, there will be a 1 on the output.", "img": "414608_25.jpg"}, {"id": "12-85", "deck": 12, "q": "(Refer to Figure 25.) In a functional and operating circuit, the depicted logic gate's output will be 0", "options": ["only when all inputs are 0.", "when all inputs are 1.", "when one or more inputs are 0."], "correctIndex": 2, "explanation": "This is an AND gate. Any time one or more of the inputs do not have a 1 on them (have a 0 on them), the output will be 0. For the output to be 1, all of the inputs must be 1.", "img": "414608_26.jpg"}, {"id": "12-86", "deck": 12, "q": "(Refer to Figure 26.) Which of the logic gate output conditions is correct with respect to the given inputs?", "options": ["1", "2", "3"], "correctIndex": 1, "explanation": "These are EXCLUSIVE OR gates. There will be a 1 on the output when one, and only one, input has a 1 on it. View 1 is incorrect. It has a 1 on both inputs so the output should be 0. View 2 is correct. Only one of the inputs has a 1 on it and the output is a 1. View 3 is incorrect. It has a 1 on one of its inputs, but the output is shown to be 0.", "img": "414608_27.jpg"}, {"id": "12-87", "deck": 12, "q": "A lead-acid battery with 12 cells connected in series (no-load voltage = 2.1 volts per cell) furnishes 10 amperes to a load of 2-ohms resistance. The internal resistance of the battery in this instance is", "options": ["0.52 ohm.", "2.52 ohms.", "5.0 ohms."], "correctIndex": 0, "explanation": "This battery has a no-load voltage of 12 x 2.1 = 25.2 volts. When it supplies 10 amperes to a 2-ohm load, the loaded voltage is 10 x 2 = 20 volts. The voltage dropped across its internal resistance is 25.2 - 20.0 = 5.2 volts. The internal resistance of the battery is found by dividing the voltage dropped across it by the load current. 5.2 ÷ 10 = 0.52 ohms.", "img": null}, {"id": "12-88", "deck": 12, "q": "If electrolyte from a lead-acid battery is spilled in the battery compartment, which procedure should be followed?", "options": ["Apply boric acid solution to the affected area followed by a water rinse.", "Rinse the affected area thoroughly with clean water.", "Apply sodium bicarbonate solution to the affected area followed by a water rinse."], "correctIndex": 2, "explanation": "The electrolyte in a lead-acid battery is a solution of sulfuric acid and water. If any is spilled in the battery compartment, it should be neutralized with a solution of sodium bicarbonate (baking soda) and water and the area rinsed with fresh water.", "img": null}, {"id": "12-89", "deck": 12, "q": "Which statement regarding the hydrometer reading of a lead-acid storage battery electrolyte is true?", "options": ["The hydrometer reading does not require a temperature correction if the electrolyte temperature is 80ºF.", "A specific gravity correction should be added to the hydrometer reading if the electrolyte temperature is below 59ºF.", "The hydrometer reading will give a true indication of the capacity of the battery regardless of the electrolyte temperature."], "correctIndex": 0, "explanation": "When testing the specific gravity of the electrolyte of a lead-acid battery, the temperature must be taken into consideration. No correction is necessary when the electrolyte temperature is between 70ºF and 90ºF. A correction of 0.4 should be added to the specific gravity reading for each 10º above 80ºF, and 0.4 should be subtracted from the specific gravity reading for each 10º below 80ºF.", "img": null}, {"id": "12-90", "deck": 12, "q": "A fully charged lead-acid battery will not freeze until extremely low temperatures are reached because", "options": ["the acid is in the plates, thereby increasing the specific gravity of the solution.", "most of the acid is in the solution.", "increased internal resistance generates sufficient heat to prevent freezing."], "correctIndex": 1, "explanation": "When a lead-acid battery is charged, the sulfate radicals from both plates join with hydrogen atoms from the water in the electrolyte and form sulfuric acid. Sulfuric acid has a much lower freezing point than water, and the electrolyte in a fully charged battery has a freezing point much lower than that of the electrolyte in a discharged battery.", "img": null}, {"id": "12-91", "deck": 12, "q": "What determines the amount of current which will flow through a battery while it is being charged by a constant voltage source?", "options": ["The total plate area of the battery.", "The state-of-charge of the battery.", "The ampere-hour capacity of the battery."], "correctIndex": 1, "explanation": "When a battery is charged by the constant-voltage method, a voltage somewhat higher than the open-circuit voltage of the battery is placed across the battery terminals. When the battery is in a low state of charge, its voltage is low and the constant-voltage charger will put a large amount of current into it. As the charge continues, the battery voltage rises and the current going into the battery decreases. When the battery is fully charged, only enough current flows into it to compensate for the power lost in its internal resistance.", "img": null}, {"id": "12-92", "deck": 12, "q": "Which of the following statements is/are generally true regarding the charging of several aircraft batteries together?\n1. Batteries of different voltages (but similar capacities) can be connected in series with each other across the charger, and charged using the constant current method.\n2. Batteries of different ampere-hour capacity and same voltage can be connected in parallel with each other across the charger, and charged using the constant voltage method.\n3. Batteries of the same voltage and same ampere-hour capacity must be connected in series with each other across the charger, and charged using the constant current method.", "options": ["3", "2 and 3.", "1 and 2."], "correctIndex": 2, "explanation": "Batteries having different voltages, but similar capacity can be connected in series and charged by the constant-current method. Batteries having the same voltage but different ampere-hour capacity can be connected in parallel and charged at the same time, if they are charged by the constant-voltage method.", "img": null}, {"id": "12-93", "deck": 12, "q": "The method used to rapidly charge a nickel-cadmium battery utilizes", "options": ["constant current and constant voltage.", "constant current and varying voltage.", "constant voltage and varying current."], "correctIndex": 2, "explanation": "Nickel-cadmium batteries can be charged rapidly by using constant voltage and varying current.", "img": null}, {"id": "12-94", "deck": 12, "q": "The purpose of providing a space underneath the plates in a lead acid battery's cell container is to", "options": ["prevent sediment buildup from contacting the plates and causing a short circuit.", "allow for convection flow of the electrolyte in order to provide for cooling of the plates.", "ensure that the electrolyte quantity ratio to the number of plates and plate area is adequate."], "correctIndex": 0, "explanation": "There is a space left below the plates in a lead acid battery cell to allow for the accumulation of sediment, thus preventing the sediment from coming in contact with the plates and causing a short circuit.", "img": null}, {"id": "12-95", "deck": 12, "q": "Which condition is an indication of improperly torqued cell link connections of a nickel-cadmium battery?", "options": ["Light spewing at the cell caps.", "Toxic and corrosive deposits of potassium carbonate crystals.", "Heat or burn marks on the hardware."], "correctIndex": 2, "explanation": "Nickel-cadmium batteries are made differently from lead-acid batteries in that the individual cells are removable and are connected together with metal straps secured to the tops of the cells with nuts. If the cell-link connections are not properly torqued, they will cause a high-resistance path for the current. They will become overheated and will show burn marks.", "img": null}, {"id": "12-96", "deck": 12, "q": "The presence of any small amount of potassium carbonate deposits on the top of nickel-cadmium battery cells in service is an indication of", "options": ["normal operation.", "excessive gassing.", "plate sulfation."], "correctIndex": 0, "explanation": "When a nickel-cadmium battery is fully charged, the battery becomes hot and the electrolyte bubbles. This causes some of the electrolyte to spew out of the top of the cell through the cell vent. When the water evaporates from the spewed-out electrolyte, it leaves a deposit of potassium carbonate, a white powder.", "img": null}, {"id": "12-97", "deck": 12, "q": "What is the likely result of servicing and charging nickel-cadmium and lead acid batteries together in the same service area?", "options": ["Lowered amp-hour capacities, for both types of batteries.", "Reduced battery service life for both types of batteries.", "Contamination of both types of batteries."], "correctIndex": 2, "explanation": "The chemistry of lead-acid and nickel-cadmium batteries is incompatible. Electrolyte from one type of battery will contaminate the other. For this reason, battery shops keep the two types of batteries separated. Separate charging systems, cleaning facilities, and installation tools should be used for each type of battery.", "img": null}, {"id": "12-98", "deck": 12, "q": "The electrolyte of a nickel-cadmium battery is the lowest when the battery is", "options": ["being charged.", "in a discharged condition.", "under a heavy load condition."], "correctIndex": 1, "explanation": "As a nickel-cadmium battery becomes discharged, some of the electrolyte is absorbed by the plates when the battery is fully discharged, its electrolyte level is the lowest.", "img": null}, {"id": "12-99", "deck": 12, "q": "The electrolyte of a nickel cadmium battery is highest when the battery is", "options": ["in a fully charged condition.", "in a discharged condition.", "under a no-load condition."], "correctIndex": 0, "explanation": "As a nickel-cadmium battery is discharged, the plates absorb some of the electrolyte and the electrolyte level is lowered. As the battery is charged, the plates give up some of the electrolyte. The level of the electrolyte is highest when the battery is in a fully charged condition.", "img": null}, {"id": "12-100", "deck": 12, "q": "The end-of-charge voltage of a 19-cell nickel-cadmium battery, measured while still on charge,", "options": ["must be 1.2 to 1.3 volts per cell.", "must be 1.4 volts per cell.", "depends upon its temperature and the method used for charging."], "correctIndex": 2, "explanation": "The end-of-charge voltage, measured while the cell is still on charge, depends upon its temperature and the method used for charging it. A cell of a 19-cell battery being charged at room temperature at 28.5-volt constant voltage would read about 1.5 volts at the end of charge; at a 27.5-volt constant-voltage condition, the cell would read about 1.45 volts. Under constant-current charging conditions, this value would depend upon temperature and charge current; at the end of seven hours charging at the five-hour rate, the voltage of a cell would be about 1.58 volts, at 75ºF.", "img": null}, {"id": "12-101", "deck": 12, "q": "Nickel-cadmium batteries which are stored for a long period of time will show a low liquid level because", "options": ["electrolyte evaporates through the vents.", "of current leakage from individual cells.", "electrolyte becomes absorbed into the plates."], "correctIndex": 2, "explanation": "If a nickel-cadmium battery is stored for a long period of time, some of the electrolyte in the cells will be absorbed into the plates, and the level will drop. The electrolyte level will rise when the battery is given a freshening charge before it is put into service.", "img": null}, {"id": "12-102", "deck": 12, "q": "How can the state-of-charge of a nickel-cadmium battery be determined?", "options": ["By measuring the specific gravity of the electrolyte.", "By a measured discharge.", "By the level of the electrolyte."], "correctIndex": 1, "explanation": "The specific gravity of the electrolyte of a nickel-cadmium battery does not change as the state-of-charge changes. The voltage of a nickel-cadmium battery remains relatively constant as its state-of-charge changes. The only way to know for sure the amount of charge a nickel-cadmium battery has in it (its state-of-charge) is to completely discharge it and then to put back into it a known number of ampere-hours of charge.", "img": null}, {"id": "12-103", "deck": 12, "q": "What may result if water is added to a nickel-cadmium battery when it is not fully charged?", "options": ["Excessive electrolyte dilution.", "Excessive spewing is likely to occur during the charging cycle.", "No adverse effects since water may be added anytime."], "correctIndex": 1, "explanation": "The level of the electrolyte in a nickel-cadmium cell changes as it is discharged and charged. The level is lowest when the cell is discharged and highest at the end of the charging cycle.|If water is added to a cell when some of the electrolyte has been absorbed into the plates, the level will be too high when the cell is fully charged. Some of this excess liquid will spew out of the cell when it is near the end of its charge cycle.", "img": null}, {"id": "12-104", "deck": 12, "q": "In nickel-cadmium batteries, a rise in cell temperature", "options": ["causes an increase in internal resistance.", "causes a decrease in internal resistance.", "increases cell voltage."], "correctIndex": 1, "explanation": "One of the desirable features of a nickel-cadmium battery is its low internal resistance which gives it the ability to discharge at a high rate and to accept a high rate of charge. The voltage and internal resistance of a nickel-cadmium cell vary inversely as the temperature. When the cell temperature increases, the voltage and internal resistance both decrease. This allows the battery to accept an excessive amount of charging current which produces more heat and can cause a thermal runaway.", "img": null}, {"id": "12-105", "deck": 12, "q": "Which of the following best describes the contributing factors to thermal runaway in a nickel-cadmium battery installed in an aircraft?", "options": ["High internal resistance intensified by high cell temperatures and a high current discharge/charge rate in a constant potential (voltage) charging system.", "Low internal resistance intensified by high cell temperatures and a high voltage discharge/charge rate in a constant current charging system.", "Low internal resistance intensified by high cell temperatures and a high current discharge/charge rate in a constant potential (voltage) charging system."], "correctIndex": 2, "explanation": "One of the problems with a nickel-cadmium battery is the danger of a thermal runaway. When the center cells of the battery become overheated, their resistance decreases and allows more current to flow. This increased current causes additional heating and further decreased resistance. This condition can continue until the battery is destroyed and a fire hazard is created. Thermal runaway occurs during a high current discharge/charge rate in a constant potential charging system.", "img": null}, {"id": "12-106", "deck": 12, "q": "When a charging current is applied to a nickel cadmium battery, the cells emit gas", "options": ["toward the end of the charging cycle.", "throughout the charging cycle.", "especially if the electrolyte level is high."], "correctIndex": 0, "explanation": "Gassing occurs in the cells of a nickel-cadmium battery at the end of the charging cycle when all of the oxygen has been removed from the negative plate. This gassing is caused by the decomposition of the electrolyte.", "img": null}, {"id": "12-107", "deck": 12, "q": "What is the total capacitance of a circuit containing three capacitors in parallel with capacitances of .02 microfarad, .05 microfarad, and .10 microfarad, respectively?", "options": [".170 uF.", "0.125 pF.", ".0125 uF."], "correctIndex": 0, "explanation": "Use the formula Ct = C1 + C2 + C3. When capacitors are connected together in parallel, the plate area of all the capacitors add together and the total capacitance is the sum of the individual capacitances. .02 + .05 + .10 = .170 uF.", "img": null}, {"id": "12-108", "deck": 12, "q": "What will a voltmeter read if properly connected across a closed switch in a circuit with electrical power on?", "options": ["Voltage drop in the component(s) the switch is connected to.", "System voltage.", "Zero voltage."], "correctIndex": 2, "explanation": "When a voltmeter is connected across a closed switch in perfect condition or a good fuse, it will read zero voltage. A voltage drop of up to 0.2 volts is acceptable with maximum circuit current flow through the switch.", "img": null}, {"id": "12-109", "deck": 12, "q": "Convert farads to microfarads by", "options": ["multiplying farads by 10 to the power of 6", "multiplying picofarads by 10 to the power of 6", "multiplying microfarads by 10 to the power of 6"], "correctIndex": 0, "explanation": "Each farad is equal to 10^6 microfarads. Example: 2 farads is equal to 2 x 10^6 (2,000,000) microfarads.", "img": null}, {"id": "12-110", "deck": 12, "q": "Convert farads to picofarads by:", "options": ["multiplying farads by 10 to the power of 12.", "multiplying microfarads by 10 to the power of -12.", "multiplying picofarads by 10 to the power of 12."], "correctIndex": 0, "explanation": "Each farad is equal to 10^12 picofarads. Example: 2 farads is equal to 2 x 10^12 (2,000,000,000) picofarads.", "img": null}, {"id": "12-111", "deck": 12, "q": "Which effect does not apply to the movement of electrons flowing in a conductor?", "options": ["Magnetic energy.", "Thermal energy.", "Static energy."], "correctIndex": 2, "explanation": "Current flowing through a conductor produces a magnetic field and also dissipates thermal energy.", "img": null}, {"id": "12-112", "deck": 12, "q": "What is the basic unit of electrical quantity?", "options": ["Electromotive Force.", "Ampere.", "Coulomb."], "correctIndex": 2, "explanation": "The coulomb is the basic unit of electrical quantity. 1 coulomb is equal to 6.28 X 10^18 electrons.", "img": null}, {"id": "12-113", "deck": 12, "q": "What is the opposition to the flow of AC produced by a magnetic field with generated back voltage (EMF) called?", "options": ["Inductive reactance.", "Capacitive reactance.", "Mutual inductance."], "correctIndex": 0, "explanation": "Alternating current is in a constant state of change; the effects of the magnetic fields are a continuously inducted voltage opposition to the current in the circuit. This opposition is called inductive reactance, symbolized by XL, and is measured in ohms just as resistance is measured. Inductance is the property of a circuit to oppose any change in current and it is measured in henries. Inductive reactance is a measure of how much the countering EMF in the circuit will oppose current variations.", "img": null}, {"id": "12-114", "deck": 12, "q": "Electrostatic fields are also known as", "options": ["Dielectric fields.", "Electrostatic fields.", "Static fields."], "correctIndex": 0, "explanation": "A field of force exists around a charged body. This is an electrostatic field (sometimes called a dielectric field) and it is represented by lines that extend in all directions from the charged body which terminate where there is an equal and opposite charge.", "img": null}, {"id": "12-115", "deck": 12, "q": "In a parallel circuit with three 6-ohms resistors across a 12-volt battery, what is the total current (It) value in the circuit?", "options": ["2 amps.", "6 amps.", "12 amps."], "correctIndex": 1, "explanation": "The total resistance of this circuit is 2 ohms. The total current flowing in this circuit is 6 amps.", "img": null}, {"id": "12-116", "deck": 12, "q": "In a parallel circuit with four 6-ohm resistors across a 24-volt battery, what is the total voltage across resistor-three (VR3) in the circuit?", "options": ["6 volts.", "18 volts.", "24 volts."], "correctIndex": 2, "explanation": "In a parallel circuit the source or battery voltage is applied to each of the individual resistors.", "img": null}, {"id": "12-117", "deck": 12, "q": "Which of the following logic gates will provide an active high out only when all inputs are different?", "options": ["XNOR.", "NAND.", "XOR."], "correctIndex": 2, "explanation": "The output of the XOR (Exclusive OR) gate will only be at an active high when one and only one of the two inputs is high. If both inputs are low, or both inputs are high, then the output of the gate will be low.", "img": null}, {"id": "12-118", "deck": 12, "q": "Which of the following best describes the operating principal in a nickel-cadmium battery installed in an aircraft?", "options": ["At full charge, the electrolyte will be at its lowest level and should be filled.", "To completely charge a nickel-cadmium battery, some gassing must take place; thus, some water will be used.", "When positive plates slowly give up oxygen, which is regained by the negative plates, the battery is charging."], "correctIndex": 1, "explanation": "Toward the end of the charging cycle, the cells emit gas. This will also occur if the cells are overcharged. This gas is caused by decomposition of the water in the electrolyte into hydrogen at the negative plates and oxygen at the positive plates. To completely charge a nickel-cadmium battery, some gassing, however slight, must take place; thus, some water will be used.", "img": null}, {"id": "12-119", "deck": 12, "q": "If each cell, connected in series, equals 2 volts, how would a 12-cell lead acid battery be rated?", "options": ["24 volts.", "12 volts.", "6 volts."], "correctIndex": 0, "explanation": "The voltage of a battery is determined by the number of cells connected in series to form the battery. Although the voltage of one lead-acid cell just removed from a charger is approximately 2.2 volts, a lead-acid cell is normally rated at approximately 2 volts. A battery rated at 12 volts consists of 6 lead-acid cells connected in series, and a battery rated at 24 volts is composed of 12 cells.", "img": null}, {"id": "12-120", "deck": 12, "q": "What factors strengthen a coil inductor?", "options": ["Limiting and separating the coils.", "Adding and separating the coils.", "Adding coils close together."], "correctIndex": 2, "explanation": "As more loops are added close together, the strength of the magnetic field increases. Many loops close together will result in a strong electromagnet.", "img": null}, {"id": "12-121", "deck": 12, "q": "What does the letter Q symbolize when measuring electrical charge?", "options": ["Farad.", "Electron.", "Coulomb."], "correctIndex": 2, "explanation": "The general formula for capacitance in terms of charge and voltage is C = Q/E, where:\nC = Capacitance measured in farads\nE = Applied voltage measured in volts\nQ = Charge measured in coulombs.", "img": null}, {"id": "13-122", "deck": 13, "q": "What type of line is normally used in a mechanical drawing or blueprint to represent an edge or object not visible to the viewer?", "options": ["Medium-weight dashed line.", "Medium solid line.", "Alternate short and long light dashes."], "correctIndex": 0, "explanation": "A medium-weight dashed line is called a hidden line and is used to show an edge or object not visible to the viewer. A medium solid line is used as a visible outline or object line. Alternate short and long light dashes are used to show a center line.", "img": null}, {"id": "13-123", "deck": 13, "q": "(Refer to Figure 27.) In the isometric view of a typical aileron balance weight, identify the view indicated by the arrow.", "options": ["1", "3", "2"], "correctIndex": 1, "explanation": "View 3 shows the aileron balance weight as seen from the direction shown by the arrow. This view shows the outline of the weight and the outline of the hole. Both of these are drawn as solid lines. The two bolt holes are shown as light, dashed lines (hidden lines), and there are also two hidden lines that show the break lines where the radius begins for the tip of the weight.", "img": "414609_0.jpg"}, {"id": "13-124", "deck": 13, "q": "(1) A detail drawing is a description of a single part.\n(2) An assembly drawing is a description of an object made up of two or more parts.\nRegarding the above statements,", "options": ["only No. 1 is true.", "neither No. 1 nor No. 2 is true.", "both No. 1 and No. 2 are true."], "correctIndex": 2, "explanation": "Statement (1) is true. A detail drawing is a description of a single part that includes enough information to allow the part to be manufactured (fabricated). Statement (2) is also true. An assembly drawing is a drawing that shows the way various detail parts are put together to form an assembly or a subassembly. Assembly drawings refer to the various parts to be assembled by the drawing number of their detail drawings.", "img": null}, {"id": "13-125", "deck": 13, "q": "(Refer to Figure 28.) Identify the bottom view of the object shown.", "options": ["2", "3", "1"], "correctIndex": 0, "explanation": "View 1 is not a correct orthographic view of this part. View 2 shows the part as it would be seen looking up at it from the bottom. The vertical lines are hidden. View 3 is not a correct orthographic view of this part.", "img": "414609_1.jpg"}, {"id": "13-126", "deck": 13, "q": "A specific measured distance from the datum or some other point identified by the manufacturer, to a point in or on the aircraft is called a", "options": ["zone number.", "reference number.", "station number."], "correctIndex": 2, "explanation": "A station number is a number used to identify the number of inches from the datum or other point identified by the manufacturer to a point in or on the aircraft.", "img": null}, {"id": "13-127", "deck": 13, "q": "Which statement is true regarding an orthographic projection?", "options": ["There are always at least two views.", "It could have as many as eight views.", "One-view, two-view, and three-view drawings are the most common."], "correctIndex": 2, "explanation": "An orthographic projection can show as many as six views of an object. One-view, two-view, and three-view drawings are the most commonly used types of orthographic projections.", "img": null}, {"id": "13-128", "deck": 13, "q": "(Refer to Figure 29.) Identify the left side view of the object shown.", "options": ["1", "2", "3"], "correctIndex": 2, "explanation": "View 1 is the right side. We see the horizontal surface as a visible line. View 2 is the bottom view. The vertical surface is shown as a hidden line. View 3 is the left side. The horizontal surface is shown as a hidden line.", "img": "414609_2.jpg"}, {"id": "13-129", "deck": 13, "q": "A line used to show an edge which is not visible is a", "options": ["phantom line.", "hidden line.", "break line."], "correctIndex": 1, "explanation": "A phantom line is a light line made up of an alternate long dash and two short dashes. A phantom line shows the location of a part that is used as a reference. A hidden line is a medium-weight, dashed line that shows a surface or a part that is not visible from the view in which it appears. A break line is a wavy or a zigzag line used to show that a part has been broken off and only part of it is shown.", "img": null}, {"id": "13-130", "deck": 13, "q": "(Refer to Figure 30.) Identify the bottom view of the object.", "options": ["1", "2", "3"], "correctIndex": 0, "explanation": "View 1 is the bottom. The two vertical surfaces are shown as hidden lines. View 2 is the left side. The two horizontal surfaces are shown as hidden lines. View 3 is the top view. The two vertical surfaces are shown as visible lines.", "img": "414609_3.jpg"}, {"id": "13-131", "deck": 13, "q": "(1) Schematic diagrams indicate the location of individual components in the aircraft.\n(2) Schematic diagrams indicate the location of components with respect to each other within the system.\nRegarding the above statements,", "options": ["only No. 1 is true.", "both No. 1 and No. 2 are true.", "only No. 2 is true."], "correctIndex": 2, "explanation": "Statement (1) is not true. Schematic diagrams do not indicate the location of individual components in the aircraft. Statement (2) is true. Schematic diagrams do show the location of the components with respect to each other within the system.", "img": null}, {"id": "13-132", "deck": 13, "q": "(Refer to Figure 31.) What are the proper procedural steps for sketching repairs and alterations?", "options": ["3, 1, 4, 2.", "4, 2, 3, 1.", "1, 3, 4, 2."], "correctIndex": 0, "explanation": "An easy way to make a sketch of a repair or alteration is to:\n3 Block in the space and basic shape to be used for the sketch;\n1 Add details to the basic block;\n4 Darken the lines that are to show up as visible lines in the finished sketch; and\n2 Add dimensions and any other information that will make the sketch more usable.", "img": "414609_4.jpg"}, {"id": "13-133", "deck": 13, "q": "Which statement is applicable when using a sketch for making a part?", "options": ["The sketch may be used only if supplemented with three-view orthographic projection drawings.", "The sketch must show all information to manufacture the part.", "The sketch need not show all necessary construction details."], "correctIndex": 1, "explanation": "A sketch is a simple, rough drawing made rapidly and without much detail. A sketch is frequently drawn for use in manufacturing a replacement part. Such a sketch must provide all necessary information to those persons who must manufacture the part.", "img": null}, {"id": "13-134", "deck": 13, "q": "(Refer to Figure 32.) What is the next step required for a working sketch of the illustration?", "options": ["Darken the object outlines.", "Sketch extension and dimension lines.", "Add notes, dimensions, title, and date."], "correctIndex": 1, "explanation": "In the sketch shown here, the part has already been blocked in, details have been added, the visible lines darkened, and the hidden lines added. The next step is to sketch in the extension lines and the dimension lines.", "img": "414609_5.jpg"}, {"id": "13-135", "deck": 13, "q": "For sketching purposes, almost all objects are composed of one or some combination of six basic shapes; these include the", "options": ["angle, arc, line, plane, square and circle.", "triangle, circle, cube, cylinder, cone, and sphere.", "triangle, plane, circle, line, square, and sphere."], "correctIndex": 1, "explanation": "Almost all objects are composed of one or some combination of the triangle, circle, cube, cylinder, cone, and sphere.", "img": null}, {"id": "13-136", "deck": 13, "q": "What should be the first step of the procedure in sketching an aircraft wing skin repair?", "options": ["Draw heavy guidelines.", "Lay out the repair.", "Block in the views."], "correctIndex": 2, "explanation": "In making a sketch of a repair, the first thing to do is to block in the views. As you block in the views, you are able to organize the sketch so it will clearly show the most information.", "img": null}, {"id": "13-137", "deck": 13, "q": "A simple way to find the center of a circle on a sketch or drawing, or a circular piece of material is to", "options": ["draw two non-parallel chord lines across the circle and then a corresponding perpendicular bisector lines across each chord line.", "draw two parallel chord lines across the circle and then a corresponding perpendicular bisector line across each chord line.", "draw a single chord line across the circle and then a corresponding perpendicular bisector line across the chord line."], "correctIndex": 0, "explanation": "An easy way to find the center of a circle on a sketch is to draw two non-parallel chord lines across the circle. Then, draw a perpendicular bisector of each of these chord lines. The bisector lines will cross at the center of the circle.", "img": null}, {"id": "13-138", "deck": 13, "q": "(1) According to 14 CFR Part 91, repairs to an aircraft skin should have a detailed dimensional sketch included in the permanent records.\n(2) On occasion, a mechanic may need to make a simple sketch of a proposed repair to an aircraft, a new design, or a modification.\nRegarding the above statements,", "options": ["only No. 1 is true.", "only No. 2 is true.", "both No. 1 and No. 2 are true."], "correctIndex": 1, "explanation": "Statement (1) is not true. 14 CFR Part 91 requires that maintenance records contain 'a description (or reference to data acceptable to the Administrator) of the work performed...' There is no requirement in 14 CFR Part 91 that a detailed dimensional sketch of a repair become a part of the aircraft's permanent records. Statement (2) is true. A simple sketch is often needed to help a mechanic make a repair, a new design, or a modification.", "img": null}, {"id": "13-139", "deck": 13, "q": "Working drawings may be divided into three classes. They are:", "options": ["title drawings, installation drawings, and assembly drawings.", "detail drawings, assembly drawings, and installation drawings.", "detail drawings, orthographic projection drawings, and pictorial drawings."], "correctIndex": 1, "explanation": "The three classes of working drawings are: detail drawings, assembly drawings, and installation drawings.", "img": null}, {"id": "13-140", "deck": 13, "q": "What is the class of working drawing that is the description/depiction of a single part?", "options": ["Installation drawing.", "Assembly drawing.", "Detail drawing."], "correctIndex": 2, "explanation": "A detail drawing is a description of a single part, given in such a manner as to describe by lines, notes, and symbols the specifications as to size, shape, material, and method of manufacture that are to be used in making the part.", "img": null}, {"id": "13-141", "deck": 13, "q": "Sketches are usually made easier by the use of", "options": ["graph paper.", "plain white paper.", "artist's paper."], "correctIndex": 0, "explanation": "Sketches are easily made by using graph paper, which is available, ruled with light lines, in either four or five squares to the inch.", "img": null}, {"id": "13-142", "deck": 13, "q": "What material symbol is frequently used in drawings to represent all metals?", "options": ["Steel.", "Cast iron.", "Aluminum."], "correctIndex": 1, "explanation": "If the exact specifications of a material are shown on the drawing, the easily drawn symbol for cast iron is used for the sectioning, and the material specification is listed in the bill of materials or indicated in a note.", "img": null}, {"id": "13-143", "deck": 13, "q": "(Refer to Figure 33.) Which material section-line symbol indicates cast iron?", "options": ["1", "2", "3"], "correctIndex": 2, "explanation": "Section lines shown in 1 are for rubber, plastic, or electrical insulation. Section lines shown in 2 are for steel. Section lines shown in 3 are for cast iron.", "img": "414609_6.jpg"}, {"id": "13-144", "deck": 13, "q": "(Refer to Figure 34.) What is the dimension of the chamfer?", "options": ["1/16 X 37º.", "0.3125 + .005 -0.", "0.0625 X 45º."], "correctIndex": 2, "explanation": "The chamfer is the tapered end of the cylindrical body of this clevis. The drawing shows that the end is chamfered at an angle of 45º, and the chamfer extends back for 1/16 inch. One-sixteenth of an inch is 0.0625 inch.", "img": "414609_7.jpg"}, {"id": "13-145", "deck": 13, "q": "(Refer to Figure 34.) What is the maximum diameter of the hole for the clevis pin?", "options": ["0.3175.", "0.3130.", "0.31255."], "correctIndex": 0, "explanation": "The hole in this clevis through which the clevis pin fits has a diameter of 0.3125 (+0.005, -0.000) inch. The tolerance (+0.005, -0.000) allows us to make the hole anywhere between 0.3125 and 0.3175 inch in diameter.", "img": "414609_7.jpg"}, {"id": "13-146", "deck": 13, "q": "(Refer to Figure 34.) What would be the minimum diameter of 4130 round stock required for the construction of the clevis that would produce a machined surface?", "options": ["55/64 inch.", "1 inch.", "7/8 inch."], "correctIndex": 1, "explanation": "The maximum diameter of the finished clevis is 7/8 (0.875) inch. To be sure that every part of this maximum diameter is machined, we would need to use a larger bar of material to make it.\n55/64 inch = 0.859375 (this is too small)\n1 inch (this is the correct choice)\n7/8 inch = 0.875 (this is too small)", "img": "414609_7.jpg"}, {"id": "13-147", "deck": 13, "q": "(Refer to Figure 34.) Using the information, what size drill would be required to drill the clevis bolthole?", "options": ["5/16 inch.", "21/64 inch.", "1/2 inch."], "correctIndex": 0, "explanation": "The drawing shows that the hole for the clevis bolt should have a diameter of 0.3125 (+.005, -0.000). This hole could be drilled with a 5/16 drill. The decimal equivalent of 5/16 inch is 0.3125.", "img": "414609_7.jpg"}, {"id": "13-148", "deck": 13, "q": "The measurements showing the ideal or 'perfect' sizes of parts on drawings are called", "options": ["allowances.", "dimensions.", "tolerances."], "correctIndex": 1, "explanation": "Allowances are the difference between the nominal dimension of a part and its upper or lower limit. Dimensions are the measurements used to describe the size of an object. It is the ideal or 'perfect' size of the part. Tolerances are the differences between the extreme allowable dimensions of a part.", "img": null}, {"id": "13-149", "deck": 13, "q": "(Refer to Figure 35.) Identify the extension line.", "options": ["3", "1", "4"], "correctIndex": 0, "explanation": "1 is a visible outline. 2 is a hidden line. 3 is an extension line used to show the width of the paint stripe. 4 is a center line.", "img": "414609_8.jpg"}, {"id": "13-150", "deck": 13, "q": "(Refer to Figure 36.) The diameter of the holes in the finished object is", "options": ["3/4 inch.", "31/64 inch.", "1/2 inch."], "correctIndex": 2, "explanation": "The two holes in this part have a finished diameter of 1/2 inch. They are made by first drilling them to a diameter of 31/64 inch and then reaming them to their final diameter of 1/2 inch. This information is found in note 1.", "img": "414609_9.jpg"}, {"id": "13-151", "deck": 13, "q": "Zone numbers on aircraft blueprints are used to", "options": ["locate parts, sections, and views on large drawings.", "indicate different sections of the aircraft.", "locate parts in the aircraft."], "correctIndex": 0, "explanation": "Large drawings used for manufacturing aircraft are zoned to make it easy to locate parts, sections, and views on large drawings. Zone identifiers are placed every foot along the edge of the drawing. The identifiers along the bottom of the drawing are numbers and those up the side of the drawing are letters.", "img": null}, {"id": "13-152", "deck": 13, "q": "One purpose for schematic diagrams is to show the", "options": ["functional location of components within a system.", "physical location of components within a system.", "size and shape of components within a system."], "correctIndex": 0, "explanation": "Schematic diagrams are used to show the functional location of components within the system by showing all of the components laid out in the way that they relate to each other in the functioning of the system. Schematic diagrams do not show the physical location of the components within a system, nor do they show the size and shape of the components.", "img": null}, {"id": "13-153", "deck": 13, "q": "When reading a blueprint, a dimension is given as 4.387 inches +.005 -.002. Which statement is true?", "options": ["The maximum acceptable size is 4.390 inches.", "The minimum acceptable size is 4.385 inches.", "The minimum acceptable size is 4.382 inches."], "correctIndex": 1, "explanation": "The part described here has a dimension of 4.387 inches, with a tolerance of +0.005, -0.002. The part could have a dimension of anywhere between 4.385 inches and 4.392 inches.", "img": null}, {"id": "13-154", "deck": 13, "q": "What is the allowable manufacturing tolerance for a bushing where the outside dimensions shown on the blueprint are: 1.0625 + .0025 -.0003?", "options": [".0028.", "1.0650.", "1.0647."], "correctIndex": 0, "explanation": "The bushing described here has an outside dimension of 1.0625 inch with a tolerance of +0.0025 -0.0003. The bushing could have an outside diameter of anywhere between 1.0622 inch and 1.0650 inch. The tolerance for this part is 0.0028 inch.", "img": null}, {"id": "13-155", "deck": 13, "q": "A hydraulic system schematic drawing typically indicates the", "options": ["specific location of the individual components within the aircraft.", "direction of fluid flow through the system.", "amount of pressure in the pressure and return lines, and in system components."], "correctIndex": 1, "explanation": "A schematic drawing of a hydraulic system would not show the specific location of any of the parts in the aircraft, nor the amount of pressure in the pressure and return lines, and in system components. A schematic drawing shows the way all of the components are connected together to form the complete system. It also shows the direction the fluid flows through the system.", "img": null}, {"id": "13-156", "deck": 13, "q": "(Refer to Figure 37.) The vertical distance between the top of the plate and the bottom of the lowest 15/64-inch hole is", "options": ["2.250.", "2.242.", "2.367."], "correctIndex": 2, "explanation": "The distance from the top of the plate to the center of the top hole is 3/8 inch (0.375 inch). The distance between the center of the top hole and the center of the second hole is 7/8 inch (0.875 inch). The distance between the center of the second hole and the center of the third hole is 7/8 inch (0.875 inch). The distance between the center of the third hole and the center of the lowest small hole is 1/8 inch (0.125 inch). The distance from the center of the 15/64-inch hole to its bottom edge is 15/128 inch (0.117 inch). When all of these dimensions are added together, we find the distance from the top of the plate to the bottom of the lower small hole to be 2.367 inches.", "img": "414609_10.jpg"}, {"id": "13-157", "deck": 13, "q": "(1) A measurement should not be scaled from an aircraft print because the paper shrinks or stretches when the print is made.\n(2) When a detail drawing is made, it is carefully and accurately drawn to scale, and is dimensioned.\nRegarding the above statements,", "options": ["only No. 2 is true.", "both No. 1 and No. 2 are true.", "neither No. 1 nor No. 2 is true."], "correctIndex": 1, "explanation": "Statement (1) is true. Measurements should never be scaled from an aircraft drawing because the paper shrinks and stretches. The print is seldom the exact same size as the original drawing. Statement (2) is also true. When a detail drawing is made, it is carefully and accurately drawn to scale and is dimensioned.", "img": null}, {"id": "13-158", "deck": 13, "q": "The drawings often used in illustrated parts manuals are", "options": ["exploded view drawings.", "block drawings.", "detail drawings."], "correctIndex": 0, "explanation": "The drawings used in illustrated parts manuals are exploded-view drawings.", "img": null}, {"id": "13-159", "deck": 13, "q": "A drawing in which the subassemblies or parts are shown as brought together on the aircraft is called", "options": ["an assembly drawing.", "a detail drawing.", "an installation drawing."], "correctIndex": 2, "explanation": "An installation drawing is one in which all of the parts and subassemblies are brought together.", "img": null}, {"id": "13-160", "deck": 13, "q": "What type of diagram shows the wire size required for a particular installation?", "options": ["A block diagram.", "A schematic diagram.", "A wiring diagram."], "correctIndex": 2, "explanation": "An electrical wiring diagram shows the wire size required for a particular installation.", "img": null}, {"id": "13-161", "deck": 13, "q": "In what type of electrical diagram are images of components used instead of conventional electrical symbols?", "options": ["A pictorial diagram.", "A schematic diagram.", "A block diagram."], "correctIndex": 0, "explanation": "A pictorial diagram is similar to a photograph. It shows an object as it appears to the eye, but is not satisfactory for showing complex forms and shapes.", "img": null}, {"id": "13-162", "deck": 13, "q": "Schematic diagrams are best suited for which of the following?", "options": ["Showing the visual details of individual components in a system.", "Showing the overall location and appearance of components in a system.", "Troubleshooting system malfunctions."], "correctIndex": 2, "explanation": "A schematic diagram shows the relative location of all of the parts in a system, but does not give the location of the parts in the aircraft. Schematic drawings are of great help when troubeshooting a system.", "img": null}, {"id": "13-163", "deck": 13, "q": "In the reading of aircraft blueprints, the term 'tolerance,' used in association with aircraft parts or components,", "options": ["is the tightest permissible fit for proper construction and operation of mating parts.", "is the difference between extreme permissible dimensions that a part may have and still be acceptable.", "represents the limit of galvanic compatibility between different adjoining material types in aircraft parts."], "correctIndex": 1, "explanation": "Tolerance is the difference between the extreme permissible dimensions of a part.", "img": null}, {"id": "13-164", "deck": 13, "q": "(Refer to Figure 38.) An aircraft reciprocating engine has a 1,830 cubic-inch displacement and develops 1,250 brake-horsepower at 2,500 RPM. What is the brake mean effective pressure?", "options": ["217", "205", "225"], "correctIndex": 0, "explanation": "1. Find the 1,250-brake-horsepower vertical line at the top of the chart, and follow this line down until it intersects the diagonal line for the 1,830-cubic-inch-displacement engine.\n2. Draw a horizontal line from this intersection point to the right until it intersects the diagonal line for 2,500 RPM.\n3. From the intersection of the horizontal line and the RPM diagonal line, draw a line vertically downward to the BMEP scale.\n4. You will find that the vertical line touches the BMEP scale just about on the 217-psi-BMEP line.", "img": "414609_11.jpg"}, {"id": "13-165", "deck": 13, "q": "(Refer to Figure 38.) An aircraft reciprocating engine has a 2,800 cubic-inch displacement, develops 2,000 brake-horsepower, and indicates 270 brake mean effective pressure. What is the engine speed (RPM)?", "options": ["2,200.", "2,100.", "2,300."], "correctIndex": 1, "explanation": "1. Find the 2,000-brake-horsepower vertical line along the top of the chart.\n2. Follow this line down until it intersects the diagonal line for the 2,800-cubic-inch-displacement engine.\n3. Draw a horizontal line from this intersection to the right of the chart.\n4. Find the 270-BMEP vertical line at the bottom of the chart, and follow this line up until it intersects the horizontal line you just drew.\n5. Find the diagonal line for the RPM that crosses the intersection of the two lines you have just drawn.\n6. An R-2800 engine will need to turn at 2,100 RPM to develop 2,000 brake horsepower when it has a BMEP of 270 psi.", "img": "414609_11.jpg"}, {"id": "13-166", "deck": 13, "q": "(Refer to Figure 38.) An aircraft reciprocating engine has a 2,800 cubic-inch displacement and develops 2,000 brake-horsepower at 2,200 RPM. What is the brake mean effective pressure?", "options": ["257.5.", "242.5.", "275.0."], "correctIndex": 0, "explanation": "1. Find the 2,000-brake-horsepower vertical line at the top of the chart and follow this line down until it intersects the diagonal line for the 2,800-cubic-inch-displacement engine.\n2. Draw a horizontal line from this intersection point to the right until it intersects the diagonal line for 2,200 RPM.\n3. From the intersection of the horizontal line and the RPM diagonal line, draw a line vertically downward to the BMEP scale.\n4. You will find that the vertical line touches the BMEP scale just about on the 257-psi-BMEP line.", "img": "414609_11.jpg"}, {"id": "13-167", "deck": 13, "q": "(Refer to Figure 39.) Determine the cable size of a 40-foot length of single cable in free air, with a continuous rating, running from a bus to the equipment in a 28-volt system with a 15-ampere load and a 1-volt drop.", "options": ["No. 10.", "No. 11.", "No. 18."], "correctIndex": 0, "explanation": "1. Follow the 15-ampere diagonal line down until it intersects the horizontal line for 40 feet in the 28-volt column.\n2. This intersection occurs between the vertical lines for 12-gage and 10-gage wire.\n3. You would need a 10-gage wire (always use the larger of the two wires) to carry a 15-amp load for 40 feet and not have more than a 1-volt drop.", "img": "414609_12.jpg"}, {"id": "13-168", "deck": 13, "q": "(Refer to Figure 39.) Determine the maximum length of a No. 16 cable to be installed from a bus to the equipment in a 28-volt system with a 25-ampere intermittent load and a 1-volt drop.", "options": ["8 feet.", "10 feet.", "12 feet."], "correctIndex": 0, "explanation": "1. Draw a diagonal line for 25 amperes midway between and parallel to the 20-ampere and the 30-ampere diagonal lines.\n2. Follow this line down until it intersects the 16-gage vertical line.\n3. This intersection occurs just above curve 3 on the horizontal line for 8 feet of length in the 28-volt (1-volt drop) column.\n4. A number 16 cable can carry an intermittent load of 25 amperes for 8 feet without exceeding a voltage drop of 1 volt.", "img": "414609_12.jpg"}, {"id": "13-169", "deck": 13, "q": "(Refer to Figure 39.) Determine the minimum wire size of a single cable in a bundle carrying a continuous current of 20 amperes 10 feet from the bus to the equipment in a 28-volt system with an allowable 1-volt drop.", "options": ["No. 12.", "No. 14.", "No. 16."], "correctIndex": 0, "explanation": "1. Follow the 20-ampere diagonal line down until it intersects curve 1. This curve limits the wire sizes that can be used in a bundle.\n2. This intersection occurs between the vertical lines for 14-gage and 12-gage wires.\n3. A 12-gage wire is needed to carry a continuous current of 20 amps if the wire is routed in a bundle.\n4. This wire size is chosen on the basis of the heat developed, not on the voltage drop. (If voltage drop were the limiting factor, a 16-gage wire could be used.)", "img": "414609_12.jpg"}, {"id": "13-170", "deck": 13, "q": "(Refer to Figure 39.) Determine the maximum length of a No. 12 single cable that can be used between a 28-volt bus and a component utilizing 20 amperes continuous load in free air with a maximum acceptable 1-volt drop.", "options": ["22.5 feet.", "26.5 feet.", "12.5 feet."], "correctIndex": 1, "explanation": "1. Follow the diagonal line for 20 amperes down until it intersects the 12-gage vertical line.\n2. Draw a line horizontally to the left from this point of intersection. This line meets the 1-volt drop column at the 26.5-foot mark.\n3. This point of intersection is above curve 1 showing that the wire can carry this load continuously without producing too much heat.\n4. A 12-gage wire can carry 20 amperes continuously for 26.5 feet without overheating the wire and without producing a voltage drop of more than one volt.", "img": "414609_12.jpg"}, {"id": "13-171", "deck": 13, "q": "(Refer to Figure 40.) Determine the proper tension for a 1/8-inch cable (7 x 19) if the temperature is 80ºF.", "options": ["70 pounds.", "75 pounds.", "80 pounds."], "correctIndex": 0, "explanation": "1. Follow the vertical line for a temperature of 80ºF upward until it intersects the curve for 1/8-inch, 7 x 19 cable.\n2. From this point of intersection, draw a line horizontally to the right until it intersects the rigging load in pounds index. This intersection is at 70 pounds.", "img": "414609_13.jpg"}, {"id": "13-172", "deck": 13, "q": "(Refer to Figure 40.) Determine the proper tension for a 3/16-inch cable (7 x 19 extra flex) if the temperature is 87ºF.", "options": ["135 pounds.", "125 pounds.", "140 pounds."], "correctIndex": 1, "explanation": "1. Draw a line vertically upward from a temperature of 87ºF until it intersects the curve for 3/16-inch, 7 x 19 cable.\n2. From this point of intersection, draw a line horizontally to the right until it intersects the rigging load in pounds index. This intersection is at 125 pounds.", "img": "414609_13.jpg"}, {"id": "13-173", "deck": 13, "q": "(Refer to Figure 41.) Determine how much fuel would be required for a 30-minute reserve operating at 2,300 RPM.", "options": ["25.3 pounds.", "35.5 pounds.", "49.8 pounds."], "correctIndex": 0, "explanation": "1. Follow the 2,300-RPM vertical line upward until it intersects the propeller load horsepower curve.\n2. From the point of intersection, project a line horizontally to the left to read the brake horsepower the engine develops at 2,300 RPM. This is 110 brake horsepower.\n3. Follow the 2,300-RPM curve upward until it intersects the propeller load brake specific fuel consumption curve.\n4. From the point of intersection, project a line horizontally to the right to read the specific fuel consumption for 2,300 RPM. This is 0.46 pound of fuel burned per hour for each horsepower developed.\n5. The engine burns 50.6 pounds of fuel per hour when it is developing 110 brake horsepower.\n6. A 30-minute reserve would require one-half of this, or 25.3 pounds.", "img": "414609_14.jpg"}, {"id": "13-174", "deck": 13, "q": "(Refer to Figure 41.) Determine the fuel consumption with the engine operating at cruise, 2,350 RPM.", "options": ["49.2 pounds per hour.", "51.2 pounds per hour.", "55.3 pounds per hour."], "correctIndex": 2, "explanation": "1. Follow the 2,350-RPM vertical line upward until it intersects the propeller load horsepower curve.\n2. From the point of intersection, project a line horizontally to the left to read the brake horsepower that the engine develops at 2,350 RPM. This is 118 brake horsepower.\n3. Follow the 2,350 RPM curve upward until it intersects the propeller load brake specific fuel consumption curve.\n4. From the point of intersection, project a line horizontally to the right to read the specific fuel consumption for 2,350 RPM. This is 0.47 pound of fuel burned per hour for each horsepower developed.\n5. Multiply 118 by 0.47 to get 55.46, the fuel consumption in pounds per hour when it is developing 118 brake horsepower.", "img": "414609_14.jpg"}, {"id": "13-175", "deck": 13, "q": "Which of the following terms is/are used to indicate specific measured distances from the datum and/or other points identified by the manufacturer, to points in or on the aircraft?\n1. Zone numbers.\n2. Reference numbers.\n3. Station numbers.", "options": ["1 and 3.", "3.", "2."], "correctIndex": 1, "explanation": "Station numbers is a numbering system used on large assemblies for aircraft to locate stations such as fuselage frames. Fuselage Frame-Sta 185 indicates the frame is 185 inches from the datum of the aircraft. The measurement is usually taken from the nose or zero station, but in some instances it may be taken from the firewall or some other point chosen by the manufacturer.", "img": null}, {"id": "13-176", "deck": 13, "q": "In a sectional view drawing, what sections illustrate particular parts of an object?", "options": ["Removed.", "Revolved.", "Half."], "correctIndex": 0, "explanation": "A removed section illustrates particular parts of an object. It is similar to revolved sections, except it is placed at one side and, to bring out pertinent details, often drawn to a larger scale than the main view on which it is indicated.", "img": null}, {"id": "13-177", "deck": 13, "q": "(1) Sketches are usually made with the aid of drafting instruments.\n(2) Sketches are usually more complicated to make when using graph paper.\nRegarding the above statements,", "options": ["Only No. 1 is true.", "Only No. 2 is true.", "Neither No. 1 nor No. 2 is true."], "correctIndex": 2, "explanation": "Sketches are simple drawings made without the use of tools.  It is easier to do a sketch on graph paper where dimensions are easier to visualize without using tools such as a ruler.", "img": null}, {"id": "13-178", "deck": 13, "q": "What is used to indicate that a surface must be machine finished?", "options": ["Tolerances.", "Leader lines.", "Finished marks."], "correctIndex": 2, "explanation": "By using finished marks a drawing identifies those surfaces that must be machine finished.", "img": null}, {"id": "13-179", "deck": 13, "q": "What numbering system is used to locate fuselage frames?", "options": ["Zone numbers.", "Station numbers.", "Tolerances."], "correctIndex": 1, "explanation": "Locations for fuselage frames in aircraft drawings are identified by station numbers.", "img": null}, {"id": "13-180", "deck": 13, "q": "What type of drawing line consists of alternating long and short lines?", "options": ["Dimension.", "Center.", "Hidden."], "correctIndex": 1, "explanation": "Centerlines are made up of alternate long and short dashes. They indicate the center of an object or part of an object. Where centerlines cross, the short dashes intersect symmetrically. In the case of very small circles, the centerlines may be shown unbroken.", "img": null}, {"id": "14-181", "deck": 14, "q": "When computing weight and balance, an airplane is considered to be in balance when", "options": ["the average moment arm of the loaded airplane falls within its CG range.", "all moment arms of the plane fall within CG range.", "the movement of the passengers will not cause the moment arms to fall outside the CG range."], "correctIndex": 0, "explanation": "An airplane is considered to be in balance when the average moment arm of the loaded aircraft falls within its CG range.", "img": null}, {"id": "14-182", "deck": 14, "q": "What tasks are completed prior to weighing an aircraft to determine its empty weight?", "options": ["Remove all items except those on the aircraft equipment list; drain fuel and hydraulic fluid.", "Remove all items on the aircraft equipment list; drain fuel, compute oil and hydraulic fluid weight.", "Remove all items except those on the aircraft equipment list; drain fuel and fill hydraulic reservoir."], "correctIndex": 2, "explanation": "14 CFR Part 23, which applies to most general aviation aircraft, defines empty weight of an aircraft. Empty weight includes fixed ballast, unusable fuel, full operating fluids including oil, hydraulic fluid and other fluids required for normal operation of airplane systems except potable water, lavatory precharge water, and water intended for injection in the engines. When preparing an airplane for weighing, remove all items except those on the equipment list, drain the fuel, and fill the hydraulic reservoir.", "img": null}, {"id": "14-183", "deck": 14, "q": "The useful load of an aircraft consists of the", "options": ["crew, usable fuel, passengers, and cargo.", "crew, usable fuel, oil, and fixed equipment.", "crew, passengers, usable fuel, oil, cargo, and fixed equipment."], "correctIndex": 0, "explanation": "The useful load of an aircraft is the difference between its empty weight and the maximum allowable gross weight. It does not include any of the fixed or required equipment as these are part of the empty weight.", "img": null}, {"id": "14-184", "deck": 14, "q": "Which of the following can provide the empty weight of an aircraft if the aircraft's weight and balance records become lost, destroyed, or otherwise inaccurate?", "options": ["Reweighing the aircraft.", "The applicable Aircraft Specification or Type Certificate Data Sheet.", "The applicable flight manual or pilot's operating handbook."], "correctIndex": 0, "explanation": "If the aircraft weight and balance records are lost, destroyed, or otherwise inaccurate, the aircraft must be re-weighed. The Aircraft Specification, Type Certificate Data Sheet, Flight Manual, and Pilot's Operating Handbook do not list the empty weight of the specific aircraft.", "img": null}, {"id": "14-185", "deck": 14, "q": "In the theory of weight and balance, what is the name of the distance from the fulcrum to an object?", "options": ["Lever arm.", "Balance arm.", "Fulcrum arm."], "correctIndex": 0, "explanation": "In the theory of weight and balance, the distance of any object from the fulcrum is called the lever arm.", "img": null}, {"id": "14-186", "deck": 14, "q": "In the process of weighing an airplane toward obtaining the CG, the arms from the weighing points always extend", "options": ["parallel to the centerline of the airplane.", "straight forward from each of the landing gear.", "directly from each weighing point to the others."], "correctIndex": 0, "explanation": "An arm, used in determining the CG of an airplane, is the horizontal distance from the datum to the center of gravity of the item. Arms are always measured parallel to the centerline of the airplane.", "img": null}, {"id": "14-187", "deck": 14, "q": "Which would have an effect on aircraft CG results when conducting a weight and balance check?", "options": ["Leaving the parking brake on.", "Leaving the parking brake off.", "Leaving the downlocks installed."], "correctIndex": 0, "explanation": "All of the required equipment must be properly installed, and there should be no equipment installed that is not included in the equipment list.", "img": null}, {"id": "14-188", "deck": 14, "q": "When an aircraft is positioned for weighing on scales located under each landing gear wheel, which of the following may cause erroneous scale readings?", "options": ["Gear downlocks installed.", "Parking brakes set.", "Parking brakes not set."], "correctIndex": 1, "explanation": "When positioning an aircraft on platform type scales for weighing, the parking brakes must be released so there will be no side load applied to the scale platform. Any side load will cause an erroneous scale reading.", "img": null}, {"id": "14-189", "deck": 14, "q": "(1) Private aircraft are required by regulations to be weighed periodically.\n(2) Private aircraft are required to be weighed after making any alteration.\nRegarding the above statements,", "options": ["neither No. 1 nor No. 2 is true.", "only No. 1 is true.", "only No. 2 is true."], "correctIndex": 0, "explanation": "Statement (1) is not true. No Federal Aviation Regulation requires that private aircraft be weighed periodically. Statement (2) is not true. When a private aircraft is altered, the weight and balance records must be updated to show any change that has been made in the weight or in the empty-weight CG location. These changes are normally found mathematically rather than by actually weighing the aircraft.", "img": null}, {"id": "14-190", "deck": 14, "q": "What FAA-approved document gives the leveling means to be used when weighing an aircraft?", "options": ["Type Certificate Data Sheet.", "AC 43.13-1B.", "Manufacturer's maintenance manual."], "correctIndex": 0, "explanation": "The FAA-approved document that gives the leveling means to be used when weighing a specific aircraft is the Type Certificate Data Sheet for that aircraft.", "img": null}, {"id": "14-191", "deck": 14, "q": "Use of which of the following generally yields the highest degree of aircraft leveling accuracy?", "options": ["Plumb bob and chalk line.", "Spirit level(s).", "Electronic load cell(s)."], "correctIndex": 1, "explanation": "The leveling means for determining weight and balance is specified by the aircraft manufacturer and is listed in the Type Certificate Data Sheets. Proper level may be determined with spirit levels placed across leveling lugs or along the door sill.", "img": null}, {"id": "14-192", "deck": 14, "q": "To obtain useful weight data for purposes of determining the CG, it is necessary that an aircraft be weighed", "options": ["in a level flight attitude.", "with all items of useful load installed.", "with no more than minimum fuel (1/12-gallon per METO horsepower) in all fuel tanks."], "correctIndex": 0, "explanation": "When an aircraft is being weighed, it must be placed in a level-flight attitude. When the aircraft is in its level-flight attitude, the centers of gravity of all of the items are in their correct locations relative to the datum.", "img": null}, {"id": "14-193", "deck": 14, "q": "What type of measurement is used to designate the arm in weight and balance computation?", "options": ["Distance.", "Weight.", "Weight x distance."], "correctIndex": 0, "explanation": "The arm used in weight and balance computation is the distance, in inches, between the center of gravity of an object and the aircraft datum.", "img": null}, {"id": "14-194", "deck": 14, "q": "What determines whether the value of a moment is preceded by a plus (+) or a minus (-) sign in aircraft weight and balance?", "options": ["The location of the weight in reference to the datum.", "The result of a weight being added or removed and its location relative to the datum.", "The location of the datum in reference to the aircraft CG."], "correctIndex": 1, "explanation": "A moment is a force that causes rotation about a point, and in order to specify the direction of the rotation, signs (+) and (-) are assigned to the moment. In aircraft weight and balance, a positive moment is one that causes the aircraft nose to go up, and a negative moment is one that causes the nose to go down. Since a moment is the product of weight and the distance from the datum, and both of these are signed values, we have four choices for the sign of the moment:\n1. A positive weight (weight added) and a positive arm (arm behind the datum) give a positive moment.\n2. A positive weight and a negative arm (arm ahead of the datum) give a negative moment.\n3. A negative weight (weight removed) and a positive arm give a negative moment.\n4. A negative weight and a negative arm gives a positive moment.", "img": null}, {"id": "14-195", "deck": 14, "q": "The maximum weight of an aircraft is the", "options": ["empty weight plus crew, maximum fuel, cargo, and baggage.", "empty weight plus crew, passengers, and fixed equipment.", "empty weight plus useful load."], "correctIndex": 2, "explanation": "The useful load of an aircraft is found by subtracting the empty weight of the aircraft from the maximum weight. Therefore, the maximum weight is the sum of the empty weight and the useful load.", "img": null}, {"id": "14-196", "deck": 14, "q": "Which statement is true regarding helicopter weight and balance?", "options": ["Regardless of internal or external loading, lateral axis cg control is ordinarily not a factor in maintaining helicopter weight and balance.", "The moment of tail-mounted components is subject to constant change.", "Weight and balance procedures for airplanes generally also apply to helicopters."], "correctIndex": 2, "explanation": "When computing the weight and balance of an aircraft, it makes no difference whether the aircraft has a fixed wing or a rotary wing. The procedures are the same, but the actual effect of weight and balance is more critical for a helicopter than for a fixed-wing aircraft.", "img": null}, {"id": "14-197", "deck": 14, "q": "What should be clearly indicated on the aircraft weighing form?", "options": ["Minimum allowable gross weight.", "Weight of unusable fuel.", "Weighing points."], "correctIndex": 2, "explanation": "Since the weight and balance computations are based on the scale weights of an aircraft, the weighing form used with a specific aircraft should specify not only the leveling means, but also the location of the weighing points.", "img": null}, {"id": "14-198", "deck": 14, "q": "If the reference datum line is placed at the nose of an airplane rather than at the firewall or some other location aft of the nose,", "options": ["all measurement arms will be in negative numbers.", "all measurement arms will be in positive numbers.", "measurement arms can be either positive or negative numbers depending on the manufacturer's preference."], "correctIndex": 1, "explanation": "The reference datum used for weight and balance purposes can be located anywhere the aircraft manufacturer chooses. Current practice is to locate it on or near the nose or out ahead of the aircraft. The reason for this is that all of the arms will be positive (they will all be behind the datum). If all of the arms are positive, the moment of all added weight will be positive, and the moment of all removed weight will be negative. This will simplify weight and balance computations and will give less chance for error.", "img": null}, {"id": "14-199", "deck": 14, "q": "Maximum zero fuel weight is the", "options": ["dry weight plus the weight of full crew, passengers, and cargo.", "basic operating weight without crew, fuel, and cargo.", "maximum permissible weight of a loaded aircraft (passengers, crew, and cargo) without fuel."], "correctIndex": 2, "explanation": "The zero fuel weight of an aircraft is the maximum allowable weight of the loaded aircraft without fuel. The weight of the cargo, passengers, and crew are included in the zero fuel weight.", "img": null}, {"id": "14-200", "deck": 14, "q": "If it is necessary to weigh an aircraft with full fuel tanks, all fuel weight must be subtracted from the scale reading(s)", "options": ["except minimum fuel.", "including unusable fuel.", "except unusable fuel."], "correctIndex": 2, "explanation": "The empty weight of an aircraft includes the weight of the unusable fuel. The weight and location of the unusable fuel is found in Note 1 in the section of the Type Certificate Data Sheets, 'Data pertinent to All Models.'", "img": null}, {"id": "14-201", "deck": 14, "q": "The empty weight of an airplane is determined by", "options": ["adding the net weight of each weighing point and multiplying the measured distance to the datum.", "subtracting the tare weight from the scale reading and adding the weight of each weighing point.", "multiplying the measured distance from each weighing point to the datum times the sum of scale reading less the tare weight."], "correctIndex": 1, "explanation": "When an aircraft is to be weighed, it is placed on the scales and chocked to prevent its rolling. The weight of the chocks is called tare weight. The empty weight of the aircraft is found by subtracting the tare weight from the scale readings, to get the net weight. The net weight from each weighing point is added to get the total net weight which is the total empty weight of the aircraft.", "img": null}, {"id": "14-202", "deck": 14, "q": "When dealing with weight and balance of an aircraft, the term 'maximum weight' is interpreted to mean the maximum", "options": ["weight of the empty aircraft.", "weight of the useful load.", "authorized weight of the aircraft and its contents."], "correctIndex": 2, "explanation": "Maximum weight, when considering the weight and balance of an aircraft, is the maximum certificated weight of the aircraft as specified on the Type Certificate Data Sheet or in the Aircraft Specification.", "img": null}, {"id": "14-203", "deck": 14, "q": "Most modern aircraft are designed so that if all seats are occupied, full baggage weight is carried, and all fuel tanks are full, what will be the weight condition of the aircraft?", "options": ["It will be in excess of maximum takeoff weight.", "It will be at maximum basic operating weight (BOW).", "It will be at maximum taxi or ramp weight."], "correctIndex": 0, "explanation": "Most modern aircraft are designed so that if all seats are occupied, full baggage weight is carried, and all fuel tanks are full, the aircraft will be grossly overloaded. It will be in excess of maximum takeoff weight.", "img": null}, {"id": "14-204", "deck": 14, "q": "The major source of weight change for most aircraft as they age is caused by", "options": ["accumulation of grime and debris in hard-to-reach areas of the structure, and moisture absorption in cabin insulation.", "repairs and alterations.", "installation of hardware and safety wire, and added layers of primer and paint on the structure."], "correctIndex": 1, "explanation": "Changes of fixed equipment may have a major effect upon the weight of an aircraft. Many aircraft are overloaded by the installation of extra radios or instruments.", "img": null}, {"id": "14-205", "deck": 14, "q": "The useful load of an aircraft is the difference between", "options": ["the maximum takeoff weight and basic empty weight.", "maximum ramp or takeoff weight as applicable, and zero fuel weight.", "(1) the weight of an aircraft with all seats filled, full baggage/cargo, and full fuel, and (2) aircraft weight with all seats empty, no baggage/cargo, and minimum operating fuel."], "correctIndex": 0, "explanation": "The useful load of an aircraft is the difference between the maximum takeoff weight, and the basic empty weight of the aircraft.", "img": null}, {"id": "14-206", "deck": 14, "q": "When determining the empty weight of an aircraft, certificated under current airworthiness standards (14 CFR Part 23), the oil contained in the supply tank is considered", "options": ["a part of the empty weight.", "a part of the useful load.", "the same as the fluid contained in the water injection reservoir."], "correctIndex": 0, "explanation": "The empty weight of an aircraft certificated under 14 CFR Part 23 includes a full supply tank of engine oil.", "img": null}, {"id": "14-207", "deck": 14, "q": "Improper loading of a helicopter which results in exceeding either the fore or aft CG limits is hazardous due to the", "options": ["reduction or loss of effective cyclic pitch control.", "Coriolis effect being translated to the fuselage.", "reduction or loss of effective collective pitch control."], "correctIndex": 0, "explanation": "If a helicopter is loaded in such a way that its CG is either too far forward or too far aft, flight will be hazardous. The cyclic pitch control will likely not be effective enough to control the helicopter against its out-of-balance condition.", "img": null}, {"id": "14-208", "deck": 14, "q": "The maximum weight as used in weight and balance control of a given aircraft can normally be found", "options": ["by adding the weight of full fuel, pilot, passengers, and maximum allowable baggage to the empty weight.", "in the Aircraft Specification or Type Certificate Data Sheet.", "by adding the empty weight and payload."], "correctIndex": 1, "explanation": "Type Certificate Data Sheets or Aircraft Specifications include the maximum certificated gross weight of an aircraft.", "img": null}, {"id": "14-209", "deck": 14, "q": "An aircraft with an empty weight of 2,100 pounds and an empty weight CG +32.5 was altered as follows:\n1. two 18-pound passenger seats located at +73 were removed;\n2. structural modifications were made at +77 increasing weight by 17 pounds;\n3. a seat and safety belt weighing 25 pounds were installed at +74.5; and\n4. radio equipment weighing 35 pounds was installed at +95.\nWhat is the new empty weight CG?", "options": ["+34.01.", "+33.68.", "+34.65."], "correctIndex": 1, "explanation": "ITEM WEIGHT ARM MOMENT\nAircraft 2,100 32.5 68,250\nSeats (remove) 36(-) 73 2,628(-)\nModification 17 77 1,309\nSeat 25 74.5 1,862.5\nRadio 35 95 3,325\nTOTAL 2,141 33.68 72,118.5\nThe new empty weight is 2,141 pounds, and the CG is located at fuselage station 33.68.", "img": null}, {"id": "14-210", "deck": 14, "q": "The CG range in single-rotor helicopters is", "options": ["much greater than for airplanes.", "approximately the same as the CG range for airplanes.", "more restricted than for airplanes."], "correctIndex": 2, "explanation": "Most helicopters have a much more restricted CG range than do airplanes. In some cases, this range is less than three inches.", "img": null}, {"id": "14-211", "deck": 14, "q": "The amount of fuel used for computing empty weight and corresponding CG is", "options": ["empty fuel tanks.", "unusable fuel.", "the amount of fuel necessary for 1/2 hour of operation."], "correctIndex": 1, "explanation": "The amount of fuel to be in the aircraft when it is weighed for purposes of finding its empty weight is only the unusable fuel. If the aircraft is weighed with full fuel tanks, the weight of the fuel must be subtracted from the weight found by the scales. The weight of the unusable fuel and its CG can be found in the Type Certificate Data Sheet for the aircraft.", "img": null}, {"id": "14-212", "deck": 14, "q": "An aircraft as loaded weighs 4,954 pounds at a CG of +30.5 inches. The CG range is +32.0 inches to +42.1 inches. Find the minimum weight of the ballast necessary to bring the CG within the CG range. The ballast arm is +162 inches.", "options": ["61.98 pounds.", "30.58 pounds.", "57.16 pounds."], "correctIndex": 2, "explanation": "The CG of this aircraft is out of allowable range by 1.5 inches. Its CG is at fuselage station 30.5 and the forward CG limit is at station 32.0. To find the amount of ballast needed to be attached at fuselage station 162, multiply the empty weight of the aircraft by the distance the CG is to be moved and divide this by the distance between the ballast location and the desired CG location.\nBallast weight = (Empty weight x Distance out) ÷ Distance ballast to new CG\n= (4954 x 1.5) ÷ (162 - 32)\n= 57.16 pounds\nAttaching a 57.16-pound ballast at fuselage station 162 will move the empty-weight CG to fuselage station 32.0.", "img": null}, {"id": "14-213", "deck": 14, "q": "As weighed, the total empty weight of an aircraft is 5,862 pounds with a moment of 885,957. However, when the aircraft was weighed, 20 pounds of potable water were on board at +84, and 23 pounds of hydraulic fluid were in a tank located at +101. What is the empty weight CG of the aircraft?", "options": ["150.700.", "151.700.", "151.365."], "correctIndex": 2, "explanation": "When weighing an aircraft to find its empty weight, a full reservoir of hydraulic fluid is included, but the potable water is not part of the required equipment.\nITEM WEIGHT ARM MOMENT\nAircraft 5,862 151.13 885,957\nPotable water 20(-) 84 1,680(-)\nTOTAL 5,842 151.365 884,277\nWhen the potable water is computed out of the empty weight, we find the new empty weight to be 5,842 pounds and the new empty-weight CG is located at fuselage station 151.365.", "img": null}, {"id": "14-214", "deck": 14, "q": "Two boxes which weigh 10 pounds and 5 pounds are placed in an airplane so that their distance aft from the CG are 4 feet and 2 feet respectively. How far forward of the CG should a third box, weighing 20 pounds, be placed so that the CG will not be changed?", "options": ["3 feet.", "2.5 feet.", "8 feet."], "correctIndex": 1, "explanation": "In order to not change the CG of the aircraft, it is necessary that the moment of the 20-pound weight be the same but have the opposite sign as the combined moments of the 10-pound box and the 5-pound box. The moment of the 10-pound box is 40 pound/feet. The moment of the 5-pound box is 10 pound/feet. The total positive moment is 50 pound/feet, and this must be balanced by a 50-pound/foot negative moment. By dividing the required moment by the weight, we find that the 20-pound box will have to be placed 2.5 feet ahead of the CG.", "img": null}, {"id": "14-215", "deck": 14, "q": "An aircraft with an empty weight of 1,800 pounds and an empty weight CG of +31.5 was altered as follows:\n1. two 15-pound passenger seats located at +72 were removed;\n2. structural modifications increasing the weight 14 pounds were made at +76;\n3. a seat and safety belt weighing 20 pounds were installed at +73.5; and\n4. radio equipment weighing 30 pounds was installed at +30.\nWhat is the new empty weight CG?", "options": ["+30.61.", "+31.61.", "+32.69."], "correctIndex": 1, "explanation": "ITEM WEIGHT ARM MOMENT\nAircraft 1,800 31.5 56,700\nSeats (remove) 30(-) 72 2,160(-)\nModification 14 76 1,064\nSeat 20 73.5 1,470\nRadio 30 30 900\nTOTAL 1,834 31.61 57,974\nThe alterations shown here will change the empty weight to 1,834 pounds and the empty-weight CG will move to fuselage station 31.61.", "img": null}, {"id": "14-216", "deck": 14, "q": "An aircraft had an empty weight of 2,886 pounds with a moment of 101,673.78 before several alterations were made. The alterations included:\n1. removing two passenger seats (15 pounds each) at +71;\n2. installing a cabinet (97 pounds) at +71;\n3. installing a seat and safety belt (20 pounds) at +71; and\n4. installing radio equipment (30 pounds) at +94.\nThe alterations caused the new empty weight CG to move", "options": ["1.62 inches aft of the original empty weight CG.", "2.03 inches forward of the original empty weight CG.", "2.03 inches aft of the original empty weight CG."], "correctIndex": 0, "explanation": "ITEM WEIGHT ARM MOMENT\nAircraft 2,886 35.23 101,673.78\nSeats (remove) 30(-) 71 2,130(-)\nCabinet 97 71 6,887\nSeat 20 71 1,420\nRadio 30 94 2,820\nTOTAL 3,003 36.85 110,670.78\nThe alterations shown here will change the empty weight to 3,003 pounds and the empty-weight CG will move to fuselage station 36.85.\nBefore the alteration, the EWCG was at +35.23.\nThe new EWCG of +36.85 is 1.62 inches aft of the original EWCG.", "img": null}, {"id": "14-217", "deck": 14, "q": "If a 40-pound generator applies +1400 inch-pounds to a reference axis, the generator is located", "options": ["-35 from the axis.", "+35 from the axis.", "+25 from the axis."], "correctIndex": 1, "explanation": "The distance from the axis is found by dividing the moment by the weight.\n1,400 ÷ 40 = 35\nSince the moment is positive, the arm will also be positive. The generator is located +35 inches from the axis.", "img": null}, {"id": "14-218", "deck": 14, "q": "In a balance computation of an aircraft from which an item located aft of the datum was removed, use", "options": ["(-)weight X (+)arm (-)moment.", "(-)weight X (-)arm (+)moment.", "(+)weight X (-)arm (-)moment."], "correctIndex": 0, "explanation": "A moment is a force that causes rotation about a point, and in order to specify the direction of the rotation, signs (+) and (-) are assigned to the moment. In aircraft weight and balance, a positive moment is a moment that causes the aircraft nose to go up, and a negative moment is one that causes the nose to go down. Since a moment is the product of weight and the distance from the datum and both of these are signed values, we have four choices for the sign of the moment:\n1. A positive weight (weight added) and a positive arm (arm behind the datum) give a positive moment.\n2. A positive weight and a negative arm (arm ahead of the datum) give a negative moment.\n3. A negative weight (weight removed) and a positive arm give a negative moment.\n4. A negative weight and a negative arm give a positive moment.", "img": null}, {"id": "14-219", "deck": 14, "q": "All other things being equal, if an item of useful load located aft of an aircraft's CG is removed, the aircraft's CG change will be", "options": ["aft in proportion to the weight of the item and its location in the aircraft.", "forward in proportion to the weight of the item and its location in the aircraft.", "forward in proportion to the weight of the item, regardless of its location in the aircraft."], "correctIndex": 1, "explanation": "An item located aft of an aircraft's CG has a positive arm, and when it is removed, it has a negative weight. A positive arm and a negative weight produce a negative moment. (+ arm x - weight = - moment). A negative moment moves the CG forward by an amount that is proportional to the weight of the item and its location in the aircraft.", "img": null}, {"id": "14-220", "deck": 14, "q": "Datum is forward of the main gear center point 30.24 inches\nActual distance between tail gear and main gear center points 360.26 inches \nNet weight at right main gear 9,980 pounds\nNet weight at left main gear 9,770 pounds\nNet weight at tail gear 1,970 pounds\nThese items were in the aircraft when weighed:\n1. Lavatory water tank full (34 pounds at +352).\n2. Hydraulic fluid (22 pounds at -8).\n3. Removable ballast (146 pounds at +380).\nWhat is the empty weight CG of the aircraft described above?", "options": ["62.92 inches.", "60.31 inches.", "58.54 inches."], "correctIndex": 1, "explanation": "We must first find the empty-weight CG of the aircraft as it is weighed.\nITEM WEIGHT ARM MOMENT\nRight main 9,980 30.24 301,795.2\nLeft main 9,770 30.24 295,444.8\nTail wheel 1,970 390.5 769,285.\nTOTAL 21,720 62.91 1,366,525.\nRemove, by computation, the weight of the water and the removable ballast. Leave the hydraulic fluid in, as it is part of the empty weight.\nITEM WEIGHT ARM MOMENT\nAircraft 21,720. 62.91 1,366,525\nWater 34.(-) 352. 11,968(-)\nBallast 146.(-) 380. 55,480(-)\nTOTAL 21,540. 60.31 1,299,077\nThe new empty weight, as corrected for the water and the ballast, is 21,540 pounds and the new empty-weight CG is at fuselage station 60.31.", "img": null}, {"id": "14-221", "deck": 14, "q": "When making a rearward weight and balance check to determine that the CG will not exceed the rearward limit during extreme conditions, the items of useful load which should be computed at their minimum weights are those located forward of the", "options": ["forward CG limit.", "datum.", "rearward CG limit."], "correctIndex": 2, "explanation": "When making a rearward weight and balance check to determine that the loaded CG cannot fall behind the rearward CG limit, you should use the maximum weight of all items of the useful load whose CG is behind the rear limit and the minimum weight for all items that are ahead of the rearward CG limit.", "img": null}, {"id": "14-222", "deck": 14, "q": "When, or under what condition(s) are adverse loading checks conducted?", "options": ["At or below the maximum gross weight of the aircraft.", "Anytime a repair or alteration causes EWCG to fall outside the CG range.", "At specified flight hour or calendar time intervals."], "correctIndex": 1, "explanation": "When a repair or alteration of an aircraft has been made that causes the empty weight-center of gravity to fall outside the EWCG range, an adverse-loaded CG check should be conducted to determine whether or not it is possible to load the aircraft in such a way that its operational CG will fall outside of its allowable limits.", "img": null}, {"id": "14-223", "deck": 14, "q": "When accomplishing loading computations for a small aircraft, necessary information obtained from the weight and balance records would include", "options": ["unusable fuel weight and distance from datum.", "weight and location of permanent ballast.", "current empty weight and empty weight CG."], "correctIndex": 2, "explanation": "When accomplishing loading computations for a small aircraft, you must know the current empty weight and the empty-weight CG of the aircraft. This information is essential to determine the loaded weight and loaded CG.", "img": null}, {"id": "14-224", "deck": 14, "q": "When an empty aircraft is weighed, the combined net weight at the main gears is 3,540 pounds with an arm of 195.5 inches. At the nose gear, the net weight is 2,322 pounds with an arm of 83.5 inches. The datum line is forward of the nose of the aircraft. What is the empty CG of the aircraft?", "options": ["151.1.", "155.2.", "146.5."], "correctIndex": 0, "explanation": "ITEM WEIGHT ARM MOMENT\nMain wheels 3,540 195.5 692,070\nNose wheel 2,322 83.5 193,887\nTOTAL 5,862 151.14 885,957\nThe empty weight of this aircraft is 5,862 pounds, and its empty-weight CG is located at fuselage station 151.14.", "img": null}, {"id": "14-225", "deck": 14, "q": "An aircraft with an empty weight of 1,500 pounds and an empty weight CG of +28.4 was altered as follows:\n1. two 12-pound seats located at +68.5 were removed;\n2. structural modifications weighing +28 pounds were made at +73;\n3. a seat and safety belt weighing 30 pounds were installed at +70.5; and\n4. radio equipment weighing 25 pounds was installed at +85.\nWhat is the new empty weight CG?", "options": ["+23.51.", "+31.35.", "+30.30."], "correctIndex": 2, "explanation": "ITEM WEIGHT ARM MOMENT\nAircraft 1,500 28.4 42,600\nSeats (remove) 24(-) 68.5 1,644(-)\nModification 28 73 2,044\nSeat 30 70.5 2,115\nRadio 25 85 2,125\nTOTAL 1,559 30.30 47,240\nThe empty weight of this aircraft is 1,559 pounds, and its empty-weight CG is located at fuselage station 30.30.", "img": null}, {"id": "14-226", "deck": 14, "q": "The following alteration was performed on an aircraft: A model B engine weighing 175 pounds was replaced by a model D engine weighing 185 pounds at a -62.00-inch station. The aircraft weight and balance records show the previous empty weight to be 998 pounds and an empty weight CG of 13.48 inches. What is the new empty weight CG?", "options": ["13.96 inches.", "14.25 inches.", "12.73 inches."], "correctIndex": 2, "explanation": "ITEM WEIGHT ARM MOMENT\nAircraft 998 13.48 13,453.04\nEngine change 10 62.00(-) 620.00(-)\nTOTAL 1,008 12.73 12,833.04\nThe new empty weight is 1,008 pounds, and the new empty-weight CG is at fuselage station 12.73.", "img": null}, {"id": "14-227", "deck": 14, "q": "If the empty weight CG of an airplane lies within the empty weight CG limits,", "options": ["it is necessary to calculate CG extremes.", "it is not necessary to calculate CG extremes.", "minimum fuel should be used in both forward and rearward CG checks."], "correctIndex": 1, "explanation": "If the empty-weight CG of an airplane lies within the empty-weight CG limits, it is not necessary to calculate the CG extremes. The airplane cannot be legally loaded in such a way that either its forward or aft CG limits can be exceeded.", "img": null}, {"id": "14-228", "deck": 14, "q": "When computing the maximum forward loaded CG of an aircraft, minimum weights, arms, and moments should be used for items of useful load that are located aft of the", "options": ["rearward CG limit.", "forward CG limit.", "datum."], "correctIndex": 1, "explanation": "When computing a maximum forward-loaded CG of an aircraft, you should use maximum weight for all items of the useful load located ahead of the forward CG limit, and the minimum weight for all items of the useful load located behind the forward CG limit.", "img": null}, {"id": "14-229", "deck": 14, "q": "Find the empty weight CG location for the following tricycle-gear aircraft. Each main wheel weighs 753 pounds, nosewheel weighs 22 pounds, distance between nosewheel and main wheels is 87.5 inches, nosewheel location is +9.875 inches from datum, with 1 gallon of hydraulic fluid at -21.0 inches included in the weight scale.", "options": ["+97.375 inches.", "+95.61 inches.", "+96.11 inches."], "correctIndex": 2, "explanation": "ITEM WEIGHT ARM MOMENT\nMain wheels 1,506 97.375 146,646.75\nNosewheel 22 9.875 217.25\nTOTAL 1,528 96.115 146,864.\nThe empty weight of this aircraft is 1,528 pounds, and its empty-weight CG is located at fuselage station 96.115.", "img": null}, {"id": "14-230", "deck": 14, "q": "An aircraft's LEMAC and TEMAC are defined in terms of distance", "options": ["from the datum.", "from each other.", "ahead of and behind the wing center of lift, respectively."], "correctIndex": 0, "explanation": "LEMAC is the leading edge of the mean aerodynamic chord, TEMAC is the trailing edge of the mean aerodynamic chord. These are locations measured from the datum and expressed in station numbers.", "img": null}, {"id": "14-231", "deck": 14, "q": "If an aircraft CG is found to be at 24 percent of MAC, that 24 percent is an expression of the", "options": ["distance from the TEMAC.", "distance from the LEMAC.", "average distance from the LEMAC to the wing center of lift."], "correctIndex": 1, "explanation": "When the CG of an aircraft is expressed as a percentage of MAC, its location is determined by finding that percent of MAC (the distance between the LEMAC and the TEMAC). The CG is located at this distance measured from the LEMAC.", "img": null}, {"id": "14-232", "deck": 14, "q": "What is meant by the term \"residual fuel\"?", "options": ["A known amount of fuel left in the tanks, lines, and engine.", "The fuel remaining in the tanks, lines, and engine after draining.", "The fuel remaining in the tank, lines, and engine before draining."], "correctIndex": 1, "explanation": "When weighing an aircraft to determine its empty weight, only the weight of residual (unusable) fuel should be included. Residual fuel is the fluid that will not normally drain out because it is trapped in the fuel lines and tanks.", "img": null}, {"id": "14-233", "deck": 14, "q": "Where do you look to determine the operating CG range when calculating a new aircraft weight and balance document?", "options": ["It is found on the airframe data plate.", "It is found in the type certificate data sheet.", "It is found in the pilot's aircraft information manual."], "correctIndex": 1, "explanation": "Some of the important weight and balance information found in a Type Certificate Data Sheet is as follows: center of gravity range, maximum weight, leveling means, number of seats and location, baggage capacity, fuel capacity, datum location, engine horsepower, oil capacity, amount of fuel in empty weight, and amount of oil in empty weight.", "img": null}, {"id": "15-234", "deck": 15, "q": "Which coupling nut should be selected for use with 1/2-inch aluminum oil lines which are to be assembled using flared tube ends and standard AN nuts, sleeves, and fittings?", "options": ["AN-818-5.", "AN-818-16.", "AN-818-8."], "correctIndex": 2, "explanation": "An AN-818-5 nut will fit a 5/16-inch tube. (The last dash number is the tube diameter in 1/16-inch increments.) An AN-818-16 nut will fit a 1-inch tube. An AN-818-8 nut will fit a 1/2-inch tube.", "img": null}, {"id": "15-235", "deck": 15, "q": "Metal tubing fluid lines are sized by wall thickness and", "options": ["outside diameter in 1/16 inch increments.", "inside diameter in 1/16 inch increments.", "outside diameter in 1/32 inch increments."], "correctIndex": 0, "explanation": "Metal tubing used in aircraft fluid power installations is sized by its outside diameter, which is measured fractionally in sixteenths of an inch.", "img": null}, {"id": "15-236", "deck": 15, "q": "From the following sequences of steps, indicate the proper order you would use to make a single flare on a piece of tubing:\n1. Place the tube in the proper size hole in the flaring block.\n2. Project the end of the tube slightly from the top of the flaring tool, about the thickness of a dime.\n3. Slip the fitting nut and sleeve on the tube.\n4. Strike the plunger several light blows with a lightweight hammer or mallet and turn the plunger one-half turn after each blow.\n5. Tighten the clamp bar securely to prevent slippage.\n6. Center the plunger or flaring pin over the tube.", "options": ["1, 3, 5, 2, 4, 6.", "3, 1, 6, 2, 5, 4.", "3, 1, 2, 6, 5, 4."], "correctIndex": 1, "explanation": "The correct sequence for making a single flare on a piece of tubing is:\n(3) Slip the fitting nut and sleeve on the tube.\n(1) Place the tube in the proper size hole in the flaring block.\n(6) Center the plunger or flaring pin over the tube.\n(2) Project the end of the tube slightly from the tip of the flaring tool, about the thickness of a dime.\n(5) Tighten the clamp bar securely to prevent slippage.\n(4) Strike the plunger several light blows with a lightweight hammer or mallet. Turn the plunger one-half turn after each blow.", "img": null}, {"id": "15-237", "deck": 15, "q": "Hydraulic tubing, which is damaged in a localized area to such an extent that repair is necessary, may be repaired", "options": ["by cutting out the damaged area and utilizing a swaged tube fitting to join the tube ends.", "only by replacing the tubing section run (connection to connection) using the same size and material as the original.", "by cutting out the damaged section and soldering in a replacement section of tubing."], "correctIndex": 0, "explanation": "If a piece of high-pressure hydraulic tubing is damaged in a localized area, the damage can be cut out and a new piece of tubing cut to replace the damaged section. Swage-type splice fittings are slipped over each end of the tubing, and the fittings are swaged to the tube ends.", "img": null}, {"id": "15-238", "deck": 15, "q": "What is an advantage of a double flare on aluminum tubing?", "options": ["Ease of construction.", "More resistant to damage when the joint is tightened.", "Can be applied to any size and wall-thickness of tubing."], "correctIndex": 1, "explanation": "Tubing made of 5052-O and 6061-T aluminum alloy in sizes from 1/8- to 3/8-inch OD should be flared with a double flare. Double flares are smoother than single flares and are more concentric. Also, the extra metal makes the flare more resistant to the shearing effect when the fittings are torqued.", "img": null}, {"id": "15-239", "deck": 15, "q": "A certain amount of slack must be left in a flexible hose during installation because, when under pressure, it", "options": ["expands in length and diameter.", "expands in length and contracts in diameter.", "contracts in length and expands in diameter."], "correctIndex": 2, "explanation": "When flexible hose is installed in an aircraft, it must be given a certain amount of slack because when pressure is applied to the hose, it contracts in length and expands in diameter.", "img": null}, {"id": "15-240", "deck": 15, "q": "The term 'cold flow' is generally associated with", "options": ["the effects of low temperature gasses or liquids flowing in hose or tubing.", "impressions left in natural or synthetic rubber hose material.", "flexibility characteristics of various hose materials at low ambient temperatures."], "correctIndex": 1, "explanation": "The term 'cold flow' describes the deep, permanent impression left in a natural or synthetic rubber hose by the pressure of hose clamps or supports.", "img": null}, {"id": "15-241", "deck": 15, "q": "What is the color of an AN steel flared-tube fitting?", "options": ["Black.", "Blue.", "Red."], "correctIndex": 0, "explanation": "Steel AN flared tube fittings are colored black. Aluminum alloy AN fittings are colored blue.", "img": null}, {"id": "15-242", "deck": 15, "q": "Which of the following statements is/are correct in reference to flare fittings?\n1. AN fittings have an identifying shoulder between the end of the threads and the flare cone.\n2. AC and AN fittings are considered identical except for material composition and identifying colors.\n3. AN fittings are generally interchangeable with AC fittings of compatible material composition.", "options": ["1.", "1 and 3.", "1, 2, and 3."], "correctIndex": 0, "explanation": "AN flare fittings have a shoulder between the end of the threads and the flare cone. In AC fittings the threads go all the way to the cone. AN fittings are dyed blue or black and AC fittings are gray or yellow. The threads on an AN fitting are courser than those on  an AC fitting. AN and AC fittings are not interchangeable.", "img": null}, {"id": "15-243", "deck": 15, "q": "Flexible lines must be installed with", "options": ["a slack of 5 to 8 percent of the length.", "a slack of at least 10 to 12 percent of the length.", "enough slack to allow maximum flexing during operation."], "correctIndex": 0, "explanation": "When flexible lines are installed in a fluid power system, they should be between 5 percent and 8 percent longer than the space between the fittings. This extra length (this slack) makes allowance for expansion in the system due to heat and for the fact that a hose contracts in its length when it is pressurized.", "img": null}, {"id": "15-244", "deck": 15, "q": "The maximum distance between end fittings to which a straight hose assembly is to be connected is 50 inches. The minimum hose length to make such a connection should be", "options": ["54-1/2 inches.", "51-1/2 inches.", "52-1/2 inches."], "correctIndex": 2, "explanation": "When a flexible line is installed in a fluid power system, it should be between 5 percent and 8 percent longer than the space between the fittings. If the distance between the fittings is 50 inches, the hose should be at least 5 percent longer than this, or 52-1/2 inches long.", "img": null}, {"id": "15-245", "deck": 15, "q": "Excessive stress on fluid or pneumatic metal tubing caused by expansion and contraction due to temperature changes can best be avoided by", "options": ["using short, straight sections of tubing between fixed parts of the aircraft.", "using tubing of the same material as the majority of the adjoining structure.", "providing bends in the tubing."], "correctIndex": 2, "explanation": "Never select a path for a rigid fluid line that does not require bends in the tubing. Bends are necessary to permit the tubing to expand and contract under temperature changes and to absorb vibration.", "img": null}, {"id": "15-246", "deck": 15, "q": "The material specifications for a certain aircraft require that a replacement oil line be fabricated from 3/4-inch 0.072 5052-0 aluminum alloy tubing. What is the inside dimension of this tubing?", "options": ["0.606 inch.", "0.688 inch.", "0.750 inch."], "correctIndex": 0, "explanation": "Find the inside diameter of a tube by subtracting two times the wall thickness from its outside diameter.\n0.750 - 2(0.072) = 0.606 inch\nThe inside diameter is 0.606 inch.", "img": null}, {"id": "15-247", "deck": 15, "q": "In most aircraft hydraulic systems, two-piece tube connectors consisting of a sleeve and a nut are used when a tubing flare is required. The use of this type connector eliminates", "options": ["the flaring operation prior to assembly.", "the possibility of reducing the flare thickness by wiping or ironing during the tightening process.", "wrench damage to the tubing during the tightening process."], "correctIndex": 1, "explanation": "There are two types of flare fittings that can be used in aircraft hydraulic systems. One type is the single-piece AN817 nut, and the other is the two-piece MS20819 sleeve and an AN818 nut. The AN818 nut and sleeve are preferred over the single-piece fitting because it eliminates the possibility of reducing the thickness of the flare by the wiping or ironing action when the nut is tightened. With the two-piece fitting, there is no relative motion between the fitting and the flare when the nut is being tightened.", "img": null}, {"id": "15-248", "deck": 15, "q": "Which statement(s) about Military Standard (MS) flareless fittings is/are correct?\n1. During installation, MS flareless fittings are normally tightened by turning the nut a specified amount, rather than being torqued. \n2. New MS flareless tubing/fittings should be assembled clean and dry without lubrication.\n3. During installation, MS flareless fittings are normally tightened by applying a specified torque to the nut", "options": ["1.", "1 and 2.", "3."], "correctIndex": 0, "explanation": "MS flareless fittings are attached to the end of a metal tube by presetting the fitting on the tube.\nPresetting consists of putting enough pressure on the fitting to deform the ferrule and cause it to cut into the outside of the tube. Presetting is done by lubricating the threads of the presetting tool and the nut with hydraulic fluid,  assembling the nut and ferrule on the tube, putting it in the presetting tool, and tightening the nut by hand until resistance is felt, then turning it with a wrench from 1 to 1-1/4 turns.\nWhen installing the fitting in an aircraft hydraulic system, tighten the nut by hand until resistance is felt, then turn it 1/6 to1/3 of a turn (one hex to two hexes) with a wrench", "img": null}, {"id": "15-249", "deck": 15, "q": "When flaring aluminum tubing for use with AN fittings, the flare angle must be", "options": ["37º.", "39º.", "45º."], "correctIndex": 0, "explanation": "The flare angle used with AN fittings is 37º.", "img": null}, {"id": "15-250", "deck": 15, "q": "Scratches or nicks on the straight portion of aluminum alloy tubing may be repaired if they are no deeper than", "options": ["20 percent of the wall thickness.", "1/32 inch or 20 percent of wall thickness, whichever is less.", "10 percent of the wall thickness."], "correctIndex": 2, "explanation": "Scratches or nicks are allowed in a piece of aluminum alloy tubing provided it is no deeper than 10 percent of the wall thickness of the tube, and it is not in the heel of a bend. Scratches and nicks should be burnished out of the tube, to prevent stress concentrations.", "img": null}, {"id": "15-251", "deck": 15, "q": "Flexible hose used in aircraft systems is classified in size according to the", "options": ["outside diameter.", "wall thickness.", "inside diameter."], "correctIndex": 2, "explanation": "The size of flexible hose is determined by its inside diameter. Sizes are in 1/16-inch increments and relate to corresponding sizes of rigid tubing with which it can be used.", "img": null}, {"id": "15-252", "deck": 15, "q": "A scratch or nick in aluminum tubing can be repaired provided it does not", "options": ["appear in the heel of a bend.", "appear on the inside of a bend.", "exceed 10 percent of the tube OD on a straight section."], "correctIndex": 0, "explanation": "Scratches or nicks not deeper than 10 percent of the wall thickness in aluminum alloy tubing, that are not in the heel of a bend, may be repaired by burnishing (forcing the displaced metal back into the nick or scratch) with a polished steel burnishing hand tool.", "img": null}, {"id": "15-253", "deck": 15, "q": "Which of the following hose materials are compatible with phosphate-ester base hydraulic fluids?\n1. Butyl.\n2. Teflon.\n3. Buna-N.\n4. Neoprene.", "options": ["1 and 2.", "2 and 4.", "1 and 3."], "correctIndex": 0, "explanation": "Butyl is not suitable for use with petroleum products, but is an excellent inner liner for phosphate-ester base hydraulic fluids. Teflon hose is unaffected by any fuel, petroleum, or synthetic-base oils, alcohol, coolants, or solvents commonly used in aircraft. Buna-N should not be used with phosphate-ester base hydraulic fluids. Neoprene is not suitable for use with phosphate-ester base hydraulic fluids.", "img": null}, {"id": "15-254", "deck": 15, "q": "Which tubings have the characteristics (high strength, abrasion resistance) necessary for use in a high-pressure (3,000 PSI) hydraulic system for operation of landing gear and flaps?", "options": ["2024-T or 5052-0 aluminum alloy.", "Corrosion-resistant steel annealed or 1/4H.", "1100-1/2H or 3003-1/2H aluminum alloy."], "correctIndex": 1, "explanation": "Rigid tubing made of corrosion-resistant steel, either annealed or 1/4 hard, is used in high-pressure hydraulic or pneumatic systems where high strength and abrasion resistance are important.", "img": null}, {"id": "15-255", "deck": 15, "q": "When installing bonded clamps to support metal tubing,", "options": ["paint removal from tube is not recommended as it will inhibit corrosion.", "paint clamp and tube after clamp installation to prevent corrosion.", "remove paint or anodizing from tube at clamp location."], "correctIndex": 2, "explanation": "When a piece of metal tubing is installed in a bonded clamp, any paint or anodizing oxide film must be removed from the portion of the tube where the clamp is to fit. Both paint and the oxide film are electrical insulators.", "img": null}, {"id": "15-256", "deck": 15, "q": "In a metal tubing installation,", "options": ["rigid straight line runs are preferable.", "tension is undesirable because pressurization will cause it to expand and shift.", "a tube may be pulled in line if the nut will start on the threaded coupling."], "correctIndex": 1, "explanation": "When making an installation of rigid metal tubing, each run of the tubing must have at least one bend in it to allow for the shifting of the line as it is pressurized. There must be no tension on the line (the flare in both ends of the tube should rest squarely on the flare cones of the fittings and not have to be pulled into place with the nut).", "img": null}, {"id": "15-257", "deck": 15, "q": "The best tool to use when cutting aluminum tubing, or any tubing of moderately soft metal is a", "options": ["hand operated wheel-type tubing cutter.", "fine-tooth hacksaw.", "circular-saw equipped with an abrasive cutting wheel."], "correctIndex": 0, "explanation": "A hand operated wheel-type tubing cutter is the best tool to use when cutting aluminum tubing, or any tubing of moderately soft metal.", "img": null}, {"id": "15-258", "deck": 15, "q": "The primary purpose of providing suitable bends in fluid and pneumatic metal tubing runs is to", "options": ["clear obstacles and make turns in aircraft structures.", "provide for access within aircraft structures.", "prevent excessive stress on the tubing."], "correctIndex": 2, "explanation": "When making an installation of rigid metal tubing, each run of the tubing must have at least one bend in it to allow for the shifting of the line as it is pressurized. This prevents excessive stress on the tubing.", "img": null}, {"id": "15-259", "deck": 15, "q": "Which of the following statements is true regarding minimum allowable bend radii for 1.5 inches OD or less aluminum alloy and steel tubing of the same size?", "options": ["The minimum radius for steel is greater than for aluminum.", "The minimum radius for steel is less than for aluminum.", "The minimum radius is the same for both steel and aluminum."], "correctIndex": 0, "explanation": "The minimum allowable bend radius for a 1.5 inch OD aluminum tubing is 5 inches. The minimum allowable bend radius for the same diameter steel tubing is 5.25 inches. Steel tubing in sizes smaller than 1.5 inch OD require a greater minimum bend radius than aluminum alloy tubing of the same size.", "img": null}, {"id": "15-260", "deck": 15, "q": "A gas or fluid line marked with the letters PHDAN is", "options": ["a dual-purpose pneumatic and/or hydraulic line for normal and emergency system use.", "used to carry a hazardous substance.", "a pneumatic or hydraulic system drain or discharge line."], "correctIndex": 1, "explanation": "The marking PHDAN on a fluid line indicates that the fluid carried in the line is physically hazardous and dangerous to personnel.", "img": null}, {"id": "15-261", "deck": 15, "q": "Which statement is true regarding the variety of symbols utilized on the identifying color-code bands that are currently used on aircraft plumbing lines?", "options": ["Symbols are composed of various single colors according to line content.", "Symbols are always black against a white background regardless of line content.", "Symbols are composed of one to three contrasting colors according to line content."], "correctIndex": 2, "explanation": "The fluid carried in fluid lines in an aircraft is identified by a series of color-coded bands around the line. These bands have from one to three contrasting colors. There is also a white band with black geometric symbols for the benefit of color-blind personnel.", "img": null}, {"id": "15-262", "deck": 15, "q": "If a flared tube coupling nut is overtightened, where is the tube most likely to be weakened/damaged?", "options": ["Along the entire length of the sleeve and tube interface.", "At the edge of the sleeve and straight portion of the tube.", "At the sleeve and flare junction."], "correctIndex": 2, "explanation": "Overtightening a flared tube coupling nut will likely weaken or damage the tube and it is most likely to fail at the sleeve and flare junction.", "img": null}, {"id": "15-263", "deck": 15, "q": "Which statement concerning Bernoulli's principle is true?", "options": ["The pressure of a fluid increases at points where the velocity of the fluid increases.", "The pressure of a fluid decreases at points where the velocity of the fluid increases.", "It applies only to gases and vaporized liquids."], "correctIndex": 1, "explanation": "Bernoulli's principle is one of the most useful principles we have to explain the behavior of fluid (either liquid or gas) in motion. Bernoulli's principle tells us that if we neither add energy nor take any energy from fluid in motion, an increase in the velocity of the fluid (its kinetic energy) will result in a corresponding decrease in its pressure (its potential energy).", "img": null}, {"id": "15-264", "deck": 15, "q": "(1) Bonded clamps are used for support when installing metal tubing.\n(2) Unbonded clamps are used for support when installing wiring.\nRegarding the above statements,", "options": ["only No. 1 is true.", "both No. 1 and No. 2 are true.", "neither No. 1 nor No. 2 is true."], "correctIndex": 1, "explanation": "Statement (1) is true. Bonded clamps (clamps in which the tube is contacted with a piece of bare metal) are used when installing metal tubing in an aircraft. Bonded clamps keep the tube at the same electrical potential as the aircraft structure. Statement (2) is also true. Unbonded (cushion) clamps are used when securing wire bundles to the aircraft structure. The soft cushion in the clamp prevents abrasion wearing away the insulation on the wire.", "img": null}, {"id": "15-265", "deck": 15, "q": "Which statement is true regarding flattening of tubing in bends?", "options": ["Flattening by a maximum of 20 percent of the original diameter is permissible.", "Flattening by not more than 25 percent of the original diameter is permissible.", "The small diameter portion in the bend cannot exceed more than 75 percent of the diameter of straight tubing."], "correctIndex": 1, "explanation": "Tubing in the bend is often deformed, and the bend is not satisfactory if its small diameter is less than 75% of the outside diameter of the straight tubing. This allows a flattening in the bend of not more than 25% of the original OD of the tube.", "img": null}, {"id": "15-266", "deck": 15, "q": "A 3/8 inch aircraft high pressure flexible hose as compared to 3/8 inch metal tubing used in the same system will", "options": ["have higher flow capabilities.", "have equivalent flow characteristics.", "usually have interchangeable applications."], "correctIndex": 1, "explanation": "Flexible hose may be used in any part of an aircraft fluid system where it has been proven by the aircraft manufacturer to be suitable. The hose must be able to carry the pressure, withstand the vibration, and pass the required fluid flow. The size of a flexible hose is approximately its inside diameter in 1/16-inch increments. This refers to the outside diameter of a rigid tube that has the equivalent flow characteristics.", "img": null}, {"id": "15-267", "deck": 15, "q": "When a Teflon hose has been in service for a time, what condition may have occurred and/or what precaution should be taken when it is temporarily removed from the aircraft?", "options": ["The hose interior must be kept wet with the fluid carried to prevent embrittlement/deterioration.", "The hose may become stiff and brittle if not flexed or moved regularly.", "The hose may have developed a set, or have been manufactured with a pre-set shape, and must be supported to maintain its shape."], "correctIndex": 2, "explanation": "Teflon hoses develops a permanent set after having been in use for an extended period of time or may have been manufactured with a permanent set for the particular function, thus is should be supported to maintain its shape and prevent inadvertent straightening.", "img": null}, {"id": "15-268", "deck": 15, "q": "Rolling-type Flaring Tools are used to flare X, X, and X tubing.", "options": ["Stainless steel, hard copper, mild steel.", "Titanium, soft copper, corrosion resistant steel.", "Soft copper, aluminum, brass."], "correctIndex": 2, "explanation": "Use rolling-type flaring tools only to flare soft copper, aluminum, and brass tubing. Do not use with corrosion resistant steel or titanium.", "img": null}, {"id": "15-269", "deck": 15, "q": "When installing a castle nut, and the nut castellation does not align with the cotter pin hole in the bolt within the torque range, the acceptable practice is to", "options": ["back the nut off and align it to the nearest hole.", "continue tightening the nut to the next hole.", "change the nut or washer and try again."], "correctIndex": 2, "explanation": "When tightening castellated nuts on bolts, the cotter pin holes may not line up with the slots in the nuts for the range of recommended values. Except in cases of highly-stressed engine parts, the nut may not be over-torqued. Remove hardware and realign the holes.", "img": null}, {"id": "16-270", "deck": 16, "q": "Magnetic particle inspection is used primarily to detect", "options": ["distortion.", "deep subsurface flaws.", "flaws on or near the surface."], "correctIndex": 2, "explanation": "Magnetic particle inspection is used to detect flaws in ferromagnetic material on or near the surface. These flaws form north and south magnetic poles when the part is magnetized. Iron oxide suspended in a fluid pumped over the part is attracted to and held by the magnetism and it outlines the flaw.", "img": null}, {"id": "16-271", "deck": 16, "q": "Liquid penetrant inspection methods may be used on which of the following?\n1. porous plastics.\n2. ferrous metals.\n3. nonferrous metals.\n4. smooth primer-sealed wood.\n5. nonporous plastics.", "options": ["2, 3, 4.", "1, 2, 3.", "2, 3, 5."], "correctIndex": 2, "explanation": "Liquid penetrant inspection methods may be used to detect faults that extend to the surface on both ferrous and nonferrous metals and nonporous plastics.", "img": null}, {"id": "16-272", "deck": 16, "q": "Which of these nondestructive testing methods is suitable for the inspection of most metals, plastics, and ceramics for surface and subsurface defects?", "options": ["Eddy current inspection.", "Magnetic particle inspection.", "Ultrasonic inspection."], "correctIndex": 2, "explanation": "Ultrasonic inspection uses high-frequency sound waves to detect faults in a material. It can be used on a wide variety of materials such as ferrous and nonferrous metals, plastics and ceramics. It can detect subsurface as well as surface defects.", "img": null}, {"id": "16-273", "deck": 16, "q": "Which of the following defects are not acceptable for metal lines?\n1. Cracked flare\n2. Seams\n3. Dents in the heel of a bend less than 20% of the diameter\n4. Scratches/nicks on the inside of a bend less than 10% of wall thickness\n5. Dents in straight section that are 20% of tube diameter", "options": ["1, 2, 3, 4, and 5.", "1, 2, and 3.", "1, 2, 3, and 5."], "correctIndex": 2, "explanation": "1. A cracked flare is cause for rejection of a metal fluid line.\n2. Metal fluid lines must be made of seamless tubing.\n3. A dent in the heel of a bend of more than 10% of the tube diameter is not acceptable.\n4. Scratches/nicks less than 10% of the wall thickness of the tube are repairable if they are not in the heel of the bend.\n5. A dent of more than 20% of the tube diameter is not acceptable", "img": null}, {"id": "16-274", "deck": 16, "q": "What nondestructive testing method requires little or no part preparation, is used to detect surface or near-surface defects in most metals, and may also be used to separate metals or alloys and their heat-treat conditions?", "options": ["Eddy current inspection.", "Ultrasonic inspection.", "Magnetic particle inspection."], "correctIndex": 0, "explanation": "Eddy current inspection requires relatively little preparation of the part being inspected. It induces a magnetic field into the part which causes eddy currents to flow. Variations in the magnitude of the eddy currents affect this magnetic field, and when it is analyzed electronically, it gives information regarding such structural characteristics as flaws, discontinuities, thickness, and alloy or heat-treat condition of the material. Eddy current inspection is used to locate defects both on the surface and below the surface.", "img": null}, {"id": "16-275", "deck": 16, "q": "What method of magnetic particle inspection is used most often to inspect aircraft parts for invisible cracks and other defects?", "options": ["Residual.", "Inductance.", "Continuous."], "correctIndex": 2, "explanation": "The continuous method of magnetic particle inspection is used for most aircraft parts because it provides the strongest magnetic field to attract the oxide from the fluid. In the continuous method of magnetic particle inspection, the part is either placed between the heads of the magnetizing machine or held inside the solenoid (coil). Magnetizing current flows while the fluid is pumped over the part. In the residual method of magnetic particle inspection, used for some smaller parts, the parts are magnetized and the magnetizing current is shut off. Only residual magnetism is left in the part to attract the oxide.", "img": null}, {"id": "16-276", "deck": 16, "q": "How many of these factors are considered essential knowledge for x-ray exposure?\n1. Processing of the film.\n2. Material thickness and density.\n3. Exposure distance and angle.\n4. Film characteristics.", "options": ["One.", "Three.", "Four."], "correctIndex": 1, "explanation": "The factors of radiographic exposure are so interdependent that it is necessary to consider all factors for any particular radiographic exposure. These factors include, but are not limited to, the following:\n1. Material thickness and density\n2. Shape and size of the object\n3. Type of defect to be detected\n4. Characteristics of X-ray machine used\n5. The exposure distance\n6. The exposure angle\n7. Film characteristics\n8.Type of intensifying screen, if used", "img": null}, {"id": "16-277", "deck": 16, "q": "The testing medium that is generally used in magnetic particle inspection utilizes a ferromagnetic material that has", "options": ["high permeability and low retentivity.", "low permeability and high retentivity.", "high permeability and high retentivity."], "correctIndex": 0, "explanation": "The testing medium used to indicate the presence of a fault in magnetic particle inspection is a finely ground iron oxide that has a high permeability and low retentivity, and is nontoxic. It is usually suspended in a light oil such as kerosine.", "img": null}, {"id": "16-278", "deck": 16, "q": "Which statement relating to the residual magnetizing inspection method is true?", "options": ["Subsurface discontinuities are made readily apparent.", "It is used in practically all circular and longitudinal magnetizing procedures.", "It may be used with steels which have been heat treated for stressed applications."], "correctIndex": 2, "explanation": "In the residual method of magnetic particle inspection, the part is magnetized and removed from the magnetic field before the oxide-carrying fluid is pumped over it. Steel that has a high retentivity (retains its magnetism after the magnetizing force has been removed) can be inspected by the residual method. Steel that has been heat-treated for stressed applications has a high retentivity and it can be inspected by the residual method.", "img": null}, {"id": "16-279", "deck": 16, "q": "A mechanic has completed a bonded honeycomb repair using the potted compound repair technique. What nondestructive testing method is used to determine the soundness of the repair after the repair has cured?", "options": ["Eddy current test.", "Metallic ring test.", "Ultrasonic test."], "correctIndex": 1, "explanation": "After a bonded honeycomb repair has been made using the potted-compound repair technique, the soundness of the repair can be tested by using the metallic ring test. The repaired surface is tested by tapping it with the edge of a coin. If the repair is sound, the tapping will produce a metallic ringing sound. If there is any void in the material, the tapping will produce a dull, thudding sound.", "img": null}, {"id": "16-280", "deck": 16, "q": "What two types of indicating mediums are available for magnetic particle inspection?", "options": ["Iron and ferric oxides.", "Wet and dry process materials.", "High retentivity and low permeability material."], "correctIndex": 1, "explanation": "The magnetic medium used for magnetic particle inspection can be applied either as a dry oxide powder dusted over the surface or (as is more commonly done) suspended in a light oil such as kerosine and pumped over the surface. The iron oxide used as the indicating medium is often treated with a fluorescent dye that causes it to glow with a green light when an ultraviolet light (black light) is shone on it.", "img": null}, {"id": "16-281", "deck": 16, "q": "Which of the following materials may be inspected using the magnetic particle inspection method?\n1. Magnesium alloys.\n2. Aluminum alloys.\n3. Iron alloys.\n4. Copper alloys.\n5. Zinc alloys.", "options": ["1, 2, 3.", "1, 2, 4, 5.", "3"], "correctIndex": 2, "explanation": "In order for a part to be inspected by the magnetic particle method, it must be magnetizable. The only magnetizable metals listed in the alternatives are iron alloys.", "img": null}, {"id": "16-282", "deck": 16, "q": "One way a part may be demagnetized after magnetic particle inspection is by", "options": ["subjecting the part to high voltage, low amperage ac.", "slowly moving the part out of an ac magnetic field of sufficient strength.", "slowly moving the part into an ac magnetic field of sufficient strength."], "correctIndex": 1, "explanation": "A steel part is magnetized by holding it in a strong, steady magnetic field that aligns all of the magnetic domains in the material. It is demagnetized by placing it in an AC magnetic field that continually reverses its polarity. This causes the domains to continually reverse their direction. As the domains are reversing, the part is slowly moved from the field so the domains remain in a disoriented state when the demagnetizing force is removed.", "img": null}, {"id": "16-283", "deck": 16, "q": "Which type crack can be detected by magnetic particle inspection using either circular or longitudinal magnetization?", "options": ["45º.", "Longitudinal.", "Transverse."], "correctIndex": 0, "explanation": "Longitudinal magnetization produces a magnetic field that extends lengthwise in the material. It is used to detect faults that extend across the part, perpendicular to the lines of magnetic flux. Circular magnetization produces a magnetic field that extends across the material. It can detect faults that are oriented along the length of the part. Either type of magnetization can detect a fault that runs at 45º to the length of the part.", "img": null}, {"id": "16-284", "deck": 16, "q": "Which of the following methods may be suitable to use to detect cracks open to the surface in aluminum forgings and castings?\n1. Dye penetrant inspection.\n2. Magnetic particle inspection.\n3. Metallic ring (coin tap) inspection.\n4. Eddy current inspection.\n5. Ultrasonic inspection.\n6. Visual inspection.", "options": ["1, 4, 5, 6.", "1, 2, 4, 5, 6.", "1, 2, 3, 4, 5, 6."], "correctIndex": 0, "explanation": "Dye penetrant, eddy current, ultrasonic, and visual inspections may be used on aluminum forgings and castings. Magnetic particle inspection can only be used on ferrous metals, and the metallic ring inspection is used to check for delaminations in bonded composite structural materials.", "img": null}, {"id": "16-285", "deck": 16, "q": "To detect a minute crack using dye penetrant inspection usually requires", "options": ["that the developer be applied to a flat surface.", "a longer-than-normal penetrating time.", "the surface to be highly polished."], "correctIndex": 1, "explanation": "The amount of penetrant that can enter a small crack is determined by both the length of time the penetrant is allowed to remain on the surface and the temperature of the part. When looking for very small cracks, the part can be heated (but not enough to cause the penetrant to evaporate from the surface), and the penetrant can be allowed to stay on the surface for a longer than normal time before it is washed off.", "img": null}, {"id": "16-286", "deck": 16, "q": "Which of the following is a main determinant of the dwell time to use when conducting a dye or fluorescent penetrant inspection?", "options": ["The size and shape of the discontinuities being looked for.", "The size and shape of the part being inspected.", "The type and/or density of the part material."], "correctIndex": 0, "explanation": "The dwell time (the time the penetrant is allowed to remain on the surface) is determined by the size and shape of the discontinuity being looked for.", "img": null}, {"id": "16-287", "deck": 16, "q": "When checking an item with the magnetic particle inspection method, circular and longitudinal magnetization should be used to", "options": ["reveal all possible defects.", "evenly magnetize the entire part.", "ensure uniform current flow."], "correctIndex": 0, "explanation": "Since longitudinal magnetization detects faults that lie across a part, and circular magnetization detects faults that lie parallel to its length, a complete inspection that will show up all possible defects requires that the part be magnetized twice, longitudinally and circularly, and given two separate inspections.", "img": null}, {"id": "16-288", "deck": 16, "q": "In magnetic particle inspection, a flaw that is perpendicular to the magnetic field flux lines generally causes", "options": ["a large disruption in the magnetic field.", "a minimal disruption in the magnetic field.", "no disruption in the magnetic field."], "correctIndex": 0, "explanation": "In order to locate a defect in a part by the magnetic particle inspection method, it is essential that the magnetic lines of force pass approximately perpendicular to the defect. This causes the maximum disruption of the magnetic field and forms magnetic poles which attract the indicating medium across the defect.", "img": null}, {"id": "16-289", "deck": 16, "q": "If dye penetrant inspection indications are not sharp and clear, the most probable cause is that the part", "options": ["was not correctly degaussed before the developer was applied.", "has no appreciable damage.", "was not thoroughly washed before the developer was applied."], "correctIndex": 2, "explanation": "After the penetrant has been on the surface of a part for the correct dwell time, the surface must be thoroughly washed to remove all traces of the penetrant. When the surface is clean and dry, the developer is sprayed or dusted on. Any penetrant left on the surface or in the pores of the material will stain the developer and faults will not show up as sharp and clear marks.", "img": null}, {"id": "16-290", "deck": 16, "q": "(1) An aircraft part may be demagnetized by subjecting it to a magnetizing force from alternating current that is gradually reduced in strength.\n(2) An aircraft part may be demagnetized by subjecting it to a magnetizing force from direct current that is alternately reversed in direction and gradually reduced in strength.|Regarding the above statements,", "options": ["both No. 1 and No. 2 are true.", "only No. 1 is true.", "only No. 2 is true."], "correctIndex": 0, "explanation": "Statement (1) is true. A part is demagnetized by placing it in an AC magnetic field whose strength is gradually reduced while it continually reverses its polarity. This leaves the domains in a disoriented state when the demagnetizing force is removed. Statement (2) is also true. A DC magnetic field whose direction is continually reversed and the strength is gradually reduced may be used to demagnetize an aircraft part that has been inspected by the magnetic particle inspection method.", "img": null}, {"id": "16-291", "deck": 16, "q": "The pattern for an inclusion is a magnetic particle buildup forming", "options": ["a fernlike pattern.", "a single line.", "parallel lines."], "correctIndex": 2, "explanation": "Inclusions are impurities trapped inside a piece of metal when it was cast.|When the part is inspected by magnetic particle inspection, the inclusion does not show up as a clearly defined fault but the indication is fuzzy. Rather than sharply defined poles, there are several sets of poles that cause the oxide to form in a series of parallel lines.", "img": null}, {"id": "16-292", "deck": 16, "q": "A part which is being prepared for dye penetrant inspection should be cleaned with", "options": ["a volatile petroleum-base solvent.", "the penetrant developer.", "water-base solvents only."], "correctIndex": 0, "explanation": "It is important when performing a dye penetrant inspection that the surface of the part be as clean as possible. Volatile petroleum-based solvents such as Stoddard solvent and naphtha are widely used for cleaning parts to be inspected.", "img": null}, {"id": "16-293", "deck": 16, "q": "Under magnetic particle inspection, a part will be identified as having a fatigue crack under which condition?", "options": ["The discontinuity pattern is straight.", "The discontinuity is found in a nonstressed area of the part.", "The discontinuity is found in a highly stressed area of the part."], "correctIndex": 2, "explanation": "Fatigue cracks usually show up in areas that have been subjected to high concentrations of stresses. They are likely to form where the cross-sectional area of the part changes sharply.", "img": null}, {"id": "16-294", "deck": 16, "q": "In performing a dye penetrant inspection, the developer", "options": ["seeps into a surface crack to indicate the presence of a defect.", "acts as a blotter to produce a visible indication.", "thoroughly cleans the surface prior to inspection."], "correctIndex": 1, "explanation": "To perform a dye penetrant inspection, the part to be inspected is thoroughly cleaned and soaked in a liquid penetrant which seeps into any cracks or defects that extend to the surface. After the part is soaked for the required dwell time, the penetrant is washed from the surface, and the surface is covered with a developer which, acting as a blotter, pulls the penetrant from the fault. The penetrant pulled out by the developer shows up as a visible indication.", "img": null}, {"id": "16-295", "deck": 16, "q": "What defects will be detected by magnetizing a part using continuous longitudinal magnetization with a cable?", "options": ["Defects perpendicular to the long axis of the part.", "Defects parallel to the long axis of the part.", "Defects parallel to the concentric circles of magnetic force within the part."], "correctIndex": 0, "explanation": "A part magnetized longitudinally by current flowing through a cable wrapped around it will show up defects that are perpendicular (at right angles) to the long axis of the part.", "img": null}, {"id": "16-296", "deck": 16, "q": "Circular magnetization of a part can be used to detect which defects?", "options": ["Defects parallel to the long axis of the part.", "Defects perpendicular to the long axis of the part.", "Defects perpendicular to the concentric circles of magnetic force within the part."], "correctIndex": 0, "explanation": "A part magnetized circularly by the magnetizing current flowing lengthwise through it, will show up defects parallel to the long axis of the part.", "img": null}, {"id": "16-297", "deck": 16, "q": "(1) In nondestructive testing, a discontinuity may be defined as an interruption in the normal physical structure or configuration of a part.\n(2) A discontinuity may or may not affect the usefulness of a part.|Regarding the above statements,", "options": ["only No. 1 is true.", "only No. 2 is true.", "both No. 1 and No. 2 are true."], "correctIndex": 2, "explanation": "Statement (1) is true. In nondestructive testing, a discontinuity may be defined as an interruption in the normal physical structure or configuration of a part. Statement (2) is also true. A discontinuity may or may not affect the usefulness of a part.", "img": null}, {"id": "16-298", "deck": 16, "q": "What type of corrosion may attack the grain boundaries of aluminum alloys when the heat treatment process has been improperly accomplished?", "options": ["Concentration cell.", "Intergranular.", "Fretting."], "correctIndex": 1, "explanation": "An aluminum alloy part is heat-treated by being heated in an oven and then removed and immediately quenched in cold water. If there is a delay between the time the part is removed from the oven and the time it is quenched, the grains in the metal will grow. Because of this, there is a good probability that intergranular corrosion will develop along the boundaries of the grains within the metal.", "img": null}, {"id": "16-299", "deck": 16, "q": "Which of the following describe the effects of annealing steel and aluminum alloys?\n1. decrease in internal stress.\n2. softening of the metal.\n3. improved corrosion resistance.", "options": ["1, 2.", "1, 3.", "2, 3."], "correctIndex": 0, "explanation": "Steel and aluminum alloys may be annealed to decrease internal stresses and soften the metal. Annealing does not improve corrosion resistance.", "img": null}, {"id": "16-300", "deck": 16, "q": "Which heat-treating process of metal produces a hard, wear-resistant surface over a strong, tough core?", "options": ["Case hardening.", "Annealing.", "Tempering."], "correctIndex": 0, "explanation": "Case hardening is a heat treatment process for steel in which the surface is hardened to make it wear resistant, but the inside of the metal remains strong and tough. Annealing is a heat treatment process for either ferrous or nonferrous metal that makes the metal softer. Tempering is a method of heat treatment in which some of the hardness is removed from a hardened metal. Removing some of the hardness makes the metal less brittle.", "img": null}, {"id": "16-301", "deck": 16, "q": "Which heat-treating operation would be performed when the surface of the metal is changed chemically by introducing a high carbide or nitride content?", "options": ["Tempering.", "Normalizing.", "Case hardening."], "correctIndex": 2, "explanation": "In case hardening, the surface of the metal is changed chemically by introducing a high carbide or nitride content. The core is unaffected chemically. When heat-treated, the surface responds to hardening while the core remains tough.", "img": null}, {"id": "16-302", "deck": 16, "q": "Normalizing is a process of heat treating", "options": ["aluminum alloys only.", "iron-base metals only.", "both aluminum alloys and iron-base metals."], "correctIndex": 1, "explanation": "Normalizing is a heat treating process in which an iron-base metal is heated to a temperature above its critical temperature and allowed to cool in still air. Normalizing reduces the stresses in the metal that were put there by the fabrication process.", "img": null}, {"id": "16-303", "deck": 16, "q": "Which of the following occurs when a mechanical force is repeatedly applied to most metals at room temperature, such as rolling, hammering, or bending?\n1. The metals become artifically aged.\n2. The metals become stress corrosion cracked.\n3. The metals become cold worked, strain or work hardened.", "options": ["2.", "1 and 3.", "3."], "correctIndex": 2, "explanation": "When a mechanincal force such as rolling, hammering, or bending is repeatedly applied to most metals at room temperature, the metals become cold worked, strain, or work hardened. They become so hard and brittle that they break.", "img": null}, {"id": "16-304", "deck": 16, "q": "The reheating of a heat treated metal, such as with a welding torch", "options": ["has little or no effect on a metal's heat treated characteristics.", "has a cumulative enhancement effect on the original heat treatment.", "can significantly alter a metal's properties in the reheated area."], "correctIndex": 2, "explanation": "When a heat-treated metal is reheated with a welding torch there is no close control of the temperature and the metal's properties in the reheated area may be significantly altered.", "img": null}, {"id": "16-305", "deck": 16, "q": "Why is steel tempered after being hardened?", "options": ["To increase its hardness and ductility.", "To increase its strength and decrease its internal stresses.", "To relieve its internal stresses and reduce its brittleness."], "correctIndex": 2, "explanation": "Steel is tempered after it is hardened to remove some of the internal stresses and make it less brittle. Tempering is done by heating it to a temperature quite a way below its critical temperature and allowing it to cool in still air.", "img": null}, {"id": "16-306", "deck": 16, "q": "What aluminum alloy designations indicate that the metal has received no hardening or tempering treatment?", "options": ["3003-F.", "5052-H36.", "6061-O."], "correctIndex": 0, "explanation": "In the temper designations used with aluminum alloy, these letters have the following meanings:\nF means 'as fabricated.' There has been no control over its temper.\nH36 means the metal is nonheat-treatable, but it has been strain-hardened and stabilized to its 3/4 hard state.\nO means the metal has been annealed.", "img": null}, {"id": "16-307", "deck": 16, "q": "Which material cannot be heat treated repeatedly without harmful effects?", "options": ["Unclad aluminum alloy in sheet form.", "6061-T9 stainless steel.", "Clad aluminum alloy."], "correctIndex": 2, "explanation": "Clad aluminum alloy sheets have a core of high-strength aluminum alloy onto whose surface have been rolled a thin layer of pure aluminum. When clad sheets are heated in the process of heat treatment, some of the pure aluminum diffuses into the core alloy and weakens the sheet. The manufacturer of the aluminum specifies the number of times clad sheets can be heat-treated. Typically, they allow the sheet to be heat-treated only one to three times.", "img": null}, {"id": "16-308", "deck": 16, "q": "What is descriptive of the annealing process of steel during and after it has been annealed?", "options": ["Rapid cooling; high strength.", "Slow cooling; low strength.", "Slow cooling; increased resistance to wear."], "correctIndex": 1, "explanation": "Annealing of steel is accomplished by heating the metal to just above the upper critical point, soaking at that temperature and cooling very slowly in the furnace. Annealing of steel produces a fine-grained, soft, ductile metal without internal stresses or strains. In the annealed state steel has its lowest strength.", "img": null}, {"id": "16-309", "deck": 16, "q": "Unless otherwise specified, torque values for tightening aircraft nuts and bolts relate to", "options": ["clean, dry threads.", "clean, lightly oiled threads.", "both dry and lightly oiled threads."], "correctIndex": 0, "explanation": "The amount of torque used to screw a nut onto a bolt is critical in determining the integrity of a bolted joint. For torque to be uniform and to allow the torque specified by the manufacturer to be duplicated in the field, the following rule applies: Unless it is specified otherwise, the values given in a torque chart relate to clean, dry threads.", "img": null}, {"id": "16-310", "deck": 16, "q": "What is generally used in the construction of aircraft exhaust collectors, stacks, and manifolds?", "options": ["Stainless steel.", "Chrome-molybdenum alloy steel.", "Titanium nickel alloy."], "correctIndex": 0, "explanation": "The material most generally used for firewalls, exhaust collectors, stacks, and manifolds on aircraft is stainless steel at least 0.015 inch thick. Mild steel, at least 0.018 inch thick and protected from corrosion, terneplate at least 0.018 inch thick, and Monel at least 0.018 inch thick may also be used.", "img": null}, {"id": "16-311", "deck": 16, "q": "Unless otherwise specified or required, aircraft bolts should be installed so that the bolthead is", "options": ["upward, or in rearward direction.", "upward, or in a forward direction.", "downward, or in a forward direction."], "correctIndex": 1, "explanation": "An accepted rule of thumb for installing bolts in an aircraft structure is to have the bolt head up, forward, or outboard. When the bolt is installed in this way, it is least likely to fall out if the nut should ever back off.", "img": null}, {"id": "16-312", "deck": 16, "q": "Alclad is a metal consisting of", "options": ["aluminum alloy surface layers and a pure aluminum core.", "pure aluminum surface layers on an aluminum alloy core.", "a homogeneous mixture of pure aluminum and aluminum alloy."], "correctIndex": 1, "explanation": "Alclad is the registered trade name for an aluminum alloy sheet that has pure aluminum rolled onto its surfaces. The pure aluminum protects the alloy core from corrosion.", "img": null}, {"id": "16-313", "deck": 16, "q": "A fiber-type, self-locking nut must never be used on an aircraft if the bolt is", "options": ["under shear loading.", "under tension loading.", "subject to rotation."], "correctIndex": 2, "explanation": "Fiber-type, self-locking nuts depend upon the fiber insert in the end of the nut gripping the bolt threads tight enough to prevent the nut backing off. Since there is no mechanical lock between the nut and the bolt, the FAA recommends that a fiber-type self-locking nut not be used in any installation in which the fastener is subject to rotation.", "img": null}, {"id": "16-314", "deck": 16, "q": "The Society of Automotive Engineers (SAE) and the American Iron and Steel Institute use a numerical index system to identify the composition of various steels. In the number '4130' designating chromium molybdenum steel, the first digit indicates the", "options": ["percentage of the basic element in the alloy.", "percentage of carbon in the alloy in hundredths of a percent.", "basic alloying element."], "correctIndex": 2, "explanation": "In the SAE four-digit numbering system for identifying the composition of steel, the first two digits identify the basic alloy, and the second two digits show the percentage of carbon in hundredths of a percent.", "img": null}, {"id": "16-315", "deck": 16, "q": "(Refer to Figure 42.) Which of the bolthead code markings shown identifies an AN corrosion resistant steel bolt?", "options": ["1", "2", "3"], "correctIndex": 2, "explanation": "The cross on the head of a bolt identifies it as a standard AN bolt made of nickel alloy steel. The cross inside a triangle identifies the bolt as an NAS close-tolerance bolt. The single dash on the head of a bolt identifies it as a standard bolt made of corrosion-resistant steel.", "img": "426981_8.jpg"}, {"id": "16-316", "deck": 16, "q": "Aircraft bolts with a cross or asterisk marked on the bolthead are", "options": ["made of aluminum alloy.", "close tolerance bolts.", "standard steel bolts."], "correctIndex": 2, "explanation": "A cross or asterisk on the head of a bolt identifies it as a standard AN bolt made of nickel alloy steel.", "img": null}, {"id": "16-317", "deck": 16, "q": "Which statement regarding aircraft bolts is correct?", "options": ["When tightening castellated nuts on drilled bolts, if the cotter pin holes do not line up, it is permissible to overtighten the nut to permit alignment of the next slot with the cotter pin hole.", "In general, bolt grip lengths should equal the material thickness.", "Alloy steel bolts smaller than 1/4-inch diameter should not be used in primary structure."], "correctIndex": 1, "explanation": "Bolts for installation in an aircraft structure should be selected so that their grip length (the length of the unthreaded shank) is equal to the thickness of the material being joined.", "img": null}, {"id": "16-318", "deck": 16, "q": "Generally speaking, bolt grip lengths should be", "options": ["equal to the thickness of the material which is fastened together, plus approximately one diameter.", "equal to the thickness of the material which is fastened together.", "one and one half times the thickness of the material which is fastened together."], "correctIndex": 1, "explanation": "Bolts for installation in an aircraft structure should be selected so that their grip length (the length of the unthreaded shank) is equal to the thickness of the material being joined.", "img": null}, {"id": "16-319", "deck": 16, "q": "When the specific torque value for nuts is not given, where can the recommended torque value be found?", "options": ["AC 43.13-1B.", "Technical Standard Order.", "AC 43.13-2A."], "correctIndex": 0, "explanation": "A list of recommended torque values for nut-bolt combinations (without lubrication) are found in AC 43.13-1B on page 7-9.", "img": null}, {"id": "16-320", "deck": 16, "q": "(Refer to Figure 43.) Identify the clevis bolt illustrated.", "options": ["1", "3", "2"], "correctIndex": 1, "explanation": "The bolt shown in View 1 is a drilled-head, hex-head bolt. The bolt shown in View 2 is an eyebolt. The bolt shown in View 3 is a clevis bolt.", "img": "426981_9.jpg"}, {"id": "16-321", "deck": 16, "q": "A particular component is attached to the aircraft structure by the use of an aircraft bolt and a castle tension nut combination. If the cotter pin hole does not align within the recommended torque range, the acceptable practice is to", "options": ["exceed the recommended torque range by no more than 10 percent.", "tighten below the torque range.", "change washers and try again."], "correctIndex": 2, "explanation": "When tightening castle nuts on bolts, the cotter pin holes may not line up with the slots in the nuts at maximum recommended torque, plus friction drag. If the hole and nut castellation do not align, change washers and try again. Exceeding the maximum recommended torque is not recommended.", "img": null}, {"id": "16-322", "deck": 16, "q": "A bolt with a single raised dash on the head is classified as an", "options": ["AN corrosion-resistant steel bolt.", "NAS standard aircraft bolt.", "NAS close tolerance bolt."], "correctIndex": 0, "explanation": "An AN corrosion-resistant steel bolt is identified by a single raised dash on its head.", "img": null}, {"id": "16-323", "deck": 16, "q": "How is a clevis bolt used with a fork-end cable terminal secured?", "options": ["With a shear nut tightened to a snug fit, but with no strain imposed on the fork and safetied with a cotter pin.", "With a castle nut tightened until slight binding occurs between the fork and the fitting to which it is being attached.", "With a shear nut and cotter pin or a thin self-locking nut tightened enough to prevent rotation of the bolt in the fork."], "correctIndex": 0, "explanation": "When a clevis bolt is used to secure a fork-end cable terminal, a shear castle nut should be used on the clevis bolt. The nut should be tightened until it is snug, but there must be no strain on the fork. The nut is secured to the clevis bolt with a cotter pin.", "img": null}, {"id": "16-324", "deck": 16, "q": "Where is an AN clevis bolt used in an airplane?", "options": ["For tension and shear load conditions.", "Where external tension loads are applied.", "Only for shear load applications."], "correctIndex": 2, "explanation": "A clevis bolt should be used only where the load to which the bolt is applied is a shear load. A clevis bolt is not designed to take any type of tensile load. The threaded portion of a clevis bolt is short and there is a groove between the threads and the shank. The head of a clevis bolt has a screwdriver slot rather than flats for the use of a wrench.", "img": null}, {"id": "16-325", "deck": 16, "q": "A bolt with an X inside a triangle on the head is classified as an", "options": ["NAS standard aircraft bolt.", "NAS close tolerance bolt.", "AN corrosion-resistant steel bolt."], "correctIndex": 1, "explanation": "An NAS or an AN standard aircraft bolt has a raised cross or asterisk on its head. An NAS close-tolerance bolt has a cross or an X inside a triangle on its head. An AN corrosion-resistant steel bolt has a single raised dash on its head.", "img": null}, {"id": "16-326", "deck": 16, "q": "The core material of Alclad 2024-T4 is", "options": ["heat-treated aluminum alloy, and the surface material is commercially pure aluminum.", "commercially pure aluminum, and the surface material is heat-treated aluminum alloy.", "strain-hardened aluminum alloy, and the surface material is commercially pure aluminum."], "correctIndex": 0, "explanation": "Alclad 2024-T4 is a type of sheet metal that has a core of 2024-T4 solution-heat-treated aluminum alloy. Commercially pure aluminum is rolled onto the surfaces of the sheet for corrosion protection. The name Alclad is a registered trade name.", "img": null}, {"id": "16-327", "deck": 16, "q": "The aluminum code number 1100 identifies what type of aluminum?", "options": ["Aluminum alloy containing 11 percent copper.", "Aluminum alloy containing zinc.", "99 percent commercially pure aluminum."], "correctIndex": 2, "explanation": "Aluminum identified by the code number 1100 is 99 percent commercially pure aluminum.", "img": null}, {"id": "16-328", "deck": 16, "q": "Aircraft bolts are usually manufactured with a", "options": ["class 1 fit for the threads.", "class 2 fit for the threads.", "class 3 fit for the threads."], "correctIndex": 2, "explanation": "A class-1 fit is a loose fit. This is used for coarse-thread stove bolts and square nuts. A class-2 fit is a free fit. It is used on some machine screws. A class-3 fit is a medium fit. It is used on almost all standard aircraft bolts.", "img": null}, {"id": "16-329", "deck": 16, "q": "In the four-digit aluminum index system number 2024, the first digit indicates", "options": ["the major alloying element.", "the number of major alloying elements used in the metal.", "the percent of alloying metal added."], "correctIndex": 0, "explanation": "In the four-digit numbering system for identifying aluminum alloys, the first digit shows the major alloy used with the aluminum. The 1000 series is commercially pure aluminum. The 2000 series has copper as the main alloy. The 3000 series has manganese as the main alloy. The 4000 series has silicon as the main alloy. The 5000 series has magnesium as the main alloy. The 6000 series has magnesium and silicon in it. The 7000 series has zinc as the main alloy.", "img": null}, {"id": "16-330", "deck": 16, "q": "How is the locking feature of the fiber-type locknut obtained?", "options": ["By the use of an unthreaded fiber locking insert.", "By a fiber insert held firmly in place at the base of the load carrying section.", "By making the threads in the fiber insert slightly smaller than those in the load carrying section."], "correctIndex": 0, "explanation": "A fiber-type lock nut is held firmly on the threads of a bolt by pressure caused by an unthreaded fiber insert locked into a recess in the end of the nut. When the bolt is screwed through the nut, it forces its way through the unthreaded fiber. The fiber grips the threads and applies a downward force between the threads in the nut and those on the bolt. This force prevents the nut vibrating loose.", "img": null}, {"id": "16-331", "deck": 16, "q": "Why should an aircraft maintenance technician be familiar with weld nomenclature?", "options": ["So that accurate visual (pictorial) comparisons can be made.", "In order to gain familiarity with the welding technique, filler material, and temperature range used.", "In order to compare welds with written (non-pictorial) description standards."], "correctIndex": 1, "explanation": "It is extremely important to make a weld repair equal to the original weld. Identifying the kind of metal to be welded, identifying the kind of welding process used in building the part originally, and determining the best way to make welded repairs are of utmost importance.", "img": null}, {"id": "16-332", "deck": 16, "q": "(Refer to Figure 44.) Identify the weld caused by an excessive amount of acetylene.", "options": ["4", "1", "3"], "correctIndex": 2, "explanation": "The weld in view 1 was made too rapidly. The long and pointed appearance of the ripples was caused by an excessive amount of heat or by an oxidizing flame. If this weld were cross-sectioned, it would probably show gas pockets, porosity, and slag inclusions. \nThe weld in view 2 has improper penetration and cold laps caused by insufficient heat. It appears rough and irregular and its edges are not feathered into the base metal.\nThe weld in view 3 has been made with a flame that had an excess of acetylene. There are bumps along the center of the bead and craters at the edge of the weld. Cross checks are apparent where the body of the weld is sound. If this weld were cross-sectioned, it would show pockets and porosity.\nThe weld in view 4 has considerable variations in depth of penetration. It often has the appearance of a cold weld.", "img": "426981_10.jpg"}, {"id": "16-333", "deck": 16, "q": "(Refer to Figure 44.) Select the illustration which depicts a cold weld.", "options": ["3", "2", "4"], "correctIndex": 1, "explanation": "The weld in view 2 is a cold weld. It has improper penetration and cold laps caused by insufficient heat. It appears rough and irregular and its edges are not feathered into the base metal.", "img": "426981_10.jpg"}, {"id": "16-334", "deck": 16, "q": "Why is it considered good practice to normalize a part after welding?", "options": ["To relieve internal stresses developed within the base metal.", "To increase the hardness of the weld.", "To remove the surface scale formed during welding."], "correctIndex": 0, "explanation": "When a part is welded, it has expanded and been fused to another part. When it cools, stresses inside it try to deform it. After a part has been welded, it should be normalized by heating it to a temperature above its critical temperature and allowed to cool in still air. This heating relieves the stresses in the metal, and the part is not so likely to crack in service.", "img": null}, {"id": "16-335", "deck": 16, "q": "Holes and a few projecting globules are found in a weld. What action should be taken?", "options": ["Reweld the defective portions.", "Remove all the old weld, and reweld the joint.", "Grind the rough surface smooth, inspect, and reweld all gaps/holes."], "correctIndex": 1, "explanation": "Blow holes and projecting globules are indications of a poor weld. All of the old weld bead should be removed and the material rewelded.", "img": null}, {"id": "16-336", "deck": 16, "q": "Which condition indicates a part has cooled too quickly after being welded?", "options": ["Cracking adjacent to the weld.", "Discoloration of the base metal.", "Gas pockets, porosity, and slag inclusions."], "correctIndex": 0, "explanation": "Heat causes metal to expand. Cooling causes it to contract. If a metal is cooled too quickly after it is welded, it will contract unevenly and stresses will remain in the metal. These stresses produce cracks adjacent to the weld.", "img": null}, {"id": "16-337", "deck": 16, "q": "Select a characteristic of a good gas weld.", "options": ["The depth of penetration shall be sufficient to ensure fusion of the filler rod.", "The height of the weld bead should be 1/8 inch above the base metal.", "The weld should taper off smoothly into the base metal."], "correctIndex": 2, "explanation": "The bead of a gas weld that has good penetration and good fusion is uniform and straight. It has a slightly crowned surface that tapers off smoothly into the base metal.", "img": null}, {"id": "16-338", "deck": 16, "q": "One characteristic of a good weld is that no oxide should be formed on the base metal at a distance from the weld of more than", "options": ["1/2 inch.", "1 inch.", "1/4 inch."], "correctIndex": 0, "explanation": "When making a good weld, the heat should be concentrated in the area being welded. The oxides that form on the base metal give an indication of the amount of heat put into the metal. Oxides formed for a distance of much more than 1/2 inch from the weld show that too much heat was put into the metal. The metal may have been weakened.", "img": null}, {"id": "16-339", "deck": 16, "q": "In examining and evaluating a welded joint, a mechanic should be familiar with", "options": ["likely ambient exposure conditions and intended use of the part, along with type of weld and original part material composition.", "the welding technique, filler material, and temperature range used.", "the parts, proportions, and formation of a weld."], "correctIndex": 0, "explanation": "It is important when evaluating a welded joint that you are familiar with the likely ambient conditions to which the part will be exposed, the intended use of the part, the type of weld, and the material of which the part is made.", "img": null}, {"id": "16-340", "deck": 16, "q": "(Refer to Figure 45.) What type weld is shown at A?", "options": ["Fillet.", "Butt.", "Lap."], "correctIndex": 1, "explanation": "Weld A is a single butt weld.\nWeld B is a double butt weld.\nWelds C are both butt welds.\nWeld D is a rosette weld.\nWeld E is a fillet weld.\nWeld F is an edge weld.\nWelds G are lap welds.", "img": "426981_11.jpg"}, {"id": "16-341", "deck": 16, "q": "(Refer to Figure 45.) What type weld is shown at B?", "options": ["Butt.", "Double butt.", "Fillet."], "correctIndex": 1, "explanation": "Weld B is a double butt weld. Both sides of the material have been ground in a V and a bead is formed on both sides of the sheet.", "img": "426981_11.jpg"}, {"id": "16-342", "deck": 16, "q": "(Refer to Figure 45.) What type weld is shown at G?", "options": ["Lap.", "Butt.", "Joint."], "correctIndex": 0, "explanation": "The two welds shown at G are lap welds. When both edges are welded as is done here, the joint is called a double lap joint.", "img": "426981_11.jpg"}, {"id": "16-343", "deck": 16, "q": "On a fillet weld, the penetration requirement includes what percentage(s) of the base metal thickness?", "options": ["100 percent.", "25 to 50 percent.", "60 to 80 percent."], "correctIndex": 1, "explanation": "A properly made fillet weld has a penetration of 25 to 50 percent of the thickness of the base metal.", "img": null}, {"id": "16-344", "deck": 16, "q": "Which tool can be used to measure the alignment of a rotor shaft or the plane of rotation of a disk?", "options": ["Dial indicator.", "Shaft gauge.", "Protractor."], "correctIndex": 0, "explanation": "A dial indicator is used to measure the alignment of a rotor shaft. The dial indicator is clamped to the structure, the contact finger is placed against the surface of the shaft, and the indicator is zeroed. The shaft is rotated and the dial indicator measures the amount the shaft is out of alignment. The plane of rotation of a disk may also be measured with a dial indicator.", "img": null}, {"id": "16-345", "deck": 16, "q": "(Refer to Figure 46.) The measurement reading on the illustrated micrometer is", "options": ["0.2851.", "0.2911.", "0.2901."], "correctIndex": 0, "explanation": "The thimble has been screwed out more than 0.275 inch (the third mark beyond the 2 is visible). The thimble has rotated just a bit more than ten hundredths of the way around, as is shown by the line on the sleeve. It is just beyond the 10 on the thimble. This means that 0.010 is added to the 0.275 on the sleeve. The vernier line on the barrel for 1 is lined up with one of the marks on the thimble, and this means that we add 0.0001 inch to the two other numbers we have. The total reading of this vernier micrometer is 0.275 + 0.010 + 0.0001 = 0.2851 inch.", "img": "426981_12.jpg"}, {"id": "16-346", "deck": 16, "q": "Identify the correct statement.", "options": ["An outside micrometer is limited to measuring diameters.", "Tools used on certificated aircraft must be an approved type.", "Dividers do not provide a reading when used as a measuring device."], "correctIndex": 2, "explanation": "Dividers do not provide a reading when they are used as a measuring device. They are used by placing their points at the locations between which the measurement is to be taken. Then the distance between the points is measured with a steel machinist's scale.", "img": null}, {"id": "16-347", "deck": 16, "q": "(Refer to Figure 47.) What is the measurement reading on the vernier caliper scale?", "options": ["1.411 inches.", "1.436 inches.", "1.700 inches."], "correctIndex": 1, "explanation": "The zero on the vernier scale is beyond the 1. This shows the measurement is more than 1 inch. It is beyond the 4. This shows it is more than 1.4 inch. It is beyond the first 0.025 mark on the bar. This shows that it is more than 1.425 inch. The 11 line on the vernier scale lines up with one of the marks on the bar. This 0.011 is added to the reading we have. The total reading is 1.425 + 0.011 = 1.436 inches.", "img": "426981_13.jpg"}, {"id": "16-348", "deck": 16, "q": "Which tool is used to measure the clearance between a surface plate and a relatively narrow surface being checked for flatness?", "options": ["Depth gauge.", "Thickness gauge.", "Dial indicator."], "correctIndex": 1, "explanation": "A part is checked for flatness by putting it on a surface plate and sliding a thickness gauge (a feeler gauge) between the part and the surface plate. The thickness of the feeler gauge that will slip between the part and the surface plate is the amount the part lacks being flat.", "img": null}, {"id": "16-349", "deck": 16, "q": "Which number represents the vernier scale graduation of a micrometer?", "options": [".00001.", ".001.", ".0001."], "correctIndex": 2, "explanation": "The vernier scale (the series of parallel lines on the sleeve) on a vernier micrometer caliper is used to give an indication of one ten thousandth of an inch (0.0001 inch) of spindle movement.", "img": null}, {"id": "16-350", "deck": 16, "q": "Which tool is used to find the center of a shaft or other cylindrical work?", "options": ["Combination set.", "Dial indicator.", "Micrometer caliper."], "correctIndex": 0, "explanation": "The center of a shaft or other circle can be found with the center head of a combination set. A combination set consists of a steel scale that has three heads that can be moved to any position on the scale and locked in place. The three heads are a stock head that measures 90º and 45º angles, a protractor head that can measure any angle between the head and the blade, and the center head that uses one side of the blade as the bisector of a 90-degree angle. The center head is placed against the circumference of the circle and a diameter is drawn along the edge of the blade. The head is moved about a quarter of the way around the circle and another diameter is drawn. The two diameters cross in the center of the circle.", "img": null}, {"id": "16-351", "deck": 16, "q": "(Refer to Figure 48.) What does the micrometer read?", "options": [".2974.", ".3004.", ".3108."], "correctIndex": 1, "explanation": "The thimble has been screwed out slightly more than 0.300 inch (the line by the 3 is just barely visible). The thimble has rotated just a bit beyond the zero line on the sleeve. The vernier line on the barrel for 4 is lined up with one of the marks on the thimble, and this means that we add 0.0004 inch to the other numbers we have. The total reading of this vernier micrometer is 0.300 + 0.0004 = 0.3004 inch.", "img": "426981_14.jpg"}, {"id": "16-352", "deck": 16, "q": "If it is necessary to accurately measure the diameter of a hole approximately 1/4 inch in diameter, the mechanic should use a", "options": ["telescoping gauge and determine the size of the hole by taking a micrometer reading of the adjustable end of the telescoping gauge.", "0- to 1-inch inside micrometer and read the measurement directly from the micrometer.", "small-hole gauge and determine the size of the hole by taking a micrometer reading of the ball end of the gauge."], "correctIndex": 2, "explanation": "The diameter of a small hole is measured by placing a ball-type, small-hole gauge in the hole and expanding it until its outside diameter is exactly the same size as the inside diameter of the hole. Remove the small-hole gauge from the hole and measure its outside diameter with a micrometer caliper.", "img": null}, {"id": "16-353", "deck": 16, "q": "(Refer to Figure 49.) The measurement reading on the micrometer is", "options": [".2758.", ".2702.", ".2792."], "correctIndex": 2, "explanation": "The thimble has moved out beyond two tenths of an inch (0.200 inch). It has moved out to a point that is beyond the third twenty-five thousandths of an inch mark. (0.075 inch.) The 4 mark on the thimble has just passed the scale on the sleeve (0.075 + 0.004 inch = 0.079). The 2 line on the vernier scale lines up with a number on the thimble. This adds 0.0002 inch. The total measurement is 0.2792 inch.", "img": "426981_15.jpg"}, {"id": "16-354", "deck": 16, "q": "What tool is generally used to set a divider to an exact dimension?", "options": ["Machinist scale.", "Surface gauge.", "Dial indicator."], "correctIndex": 0, "explanation": "Dividers are not considered to be a precision measuring tool. They are set with a machinist's scale. One of the points of the dividers is placed at the one-inch mark on the scale. The other point is moved out until it touches the mark for the distance you want between the points.", "img": null}, {"id": "16-355", "deck": 16, "q": "What tool is generally used to calibrate a micrometer or check its accuracy?", "options": ["Gauge block.", "Dial indicator.", "Machinist scale."], "correctIndex": 0, "explanation": "Micrometer calipers are precision measuring instruments. They are checked for accuracy by using gauge blocks. A 0- to 1-inch micrometer is checked with the thimble screwed down against the anvil. No gauge block is used. A 1- to 2-inch micrometer uses a 1-inch gauge block. A 2- to 3-inch micrometer uses a 2-inch gauge block.", "img": null}, {"id": "16-356", "deck": 16, "q": "What precision measuring tool is used for measuring crankpin and main bearing journals for out-of-round wear?", "options": ["Dial gauge.", "Micrometer caliper.", "Depth gauge."], "correctIndex": 1, "explanation": "A vernier micrometer caliper is used to measure a crankpin and a main bearing journal for an out-of-round condition. Two measurements are made at right angles to each other. The difference between the two readings is the amount the shaft is out-of-round.", "img": null}, {"id": "16-357", "deck": 16, "q": "The side clearances of piston rings are measured with a", "options": ["micrometer caliper gauge.", "thickness gauge.", "dial gauge."], "correctIndex": 1, "explanation": "A thickness gauge (a feeler gauge) is used to measure the side clearance of a piston ring in its ring groove. The ring is installed in the groove and its outside edge is held flush with the side of the piston. A feeler gauge is placed between the side of the piston ring and the edge of the ring groove to measure the amount of clearance between the ring and the groove.", "img": null}, {"id": "16-358", "deck": 16, "q": "How can the dimensional inspection of a bearing in a rocker arm be accomplished?", "options": ["Depth gauge and micrometer.", "Thickness gauge and push-fit arbor.", "Telescopic gauge and micrometer."], "correctIndex": 2, "explanation": "A dimensional inspection of a bearing in a rocker arm can be made by expanding a telescopic gauge inside the bushing (bearing) until its length is exactly the same as the inside diameter of the bushing. Remove the gauge and measure it with a vernier micrometer caliper. Measure the rocker arm shaft with the same vernier micrometer caliper.\nThe difference between the diameter of the shaft and that of the hole is the fit of the shaft in its bushing.", "img": null}, {"id": "16-359", "deck": 16, "q": "The twist of a connecting rod is checked by installing push-fit arbors in both ends, supported by parallel steel bars on a surface plate. Measurements are taken between the arbor and the parallel bar with a", "options": ["dial gauge.", "height gauge.", "thickness gauge."], "correctIndex": 2, "explanation": "Connecting rod twist is measured by fitting a feeler gauge (a thickness gauge) between the ends of arbors and the parallel bars.", "img": null}, {"id": "16-360", "deck": 16, "q": "The clearance between the piston rings and the ring lands is measured with a", "options": ["micrometer caliper.", "thickness gauge.", "depth gauge."], "correctIndex": 1, "explanation": "A thickness gauge (a feeler gauge) is used to measure the side clearance of a piston ring in its ring groove. The ring is installed in the groove. Its outside edge is held flush with the side of the piston. A feeler gauge is placed between the side of the piston ring and the ring land (the edge of the ring groove) to measure the amount of clearance between the ring and the groove.", "img": null}, {"id": "16-361", "deck": 16, "q": "What may be used to check the stem on a poppet-type valve for stretch?", "options": ["Dial indicator.", "Micrometer.", "Telescoping gauge."], "correctIndex": 1, "explanation": "The stem of a poppet valve is checked for stretch by using a vernier micrometer caliper to measure the stem diameter in the center of the stem and at the spring end. If the center diameter is less than the diameter at the spring end, the valve stem has been stretched.", "img": null}, {"id": "16-362", "deck": 16, "q": "Which tool can be used to determine piston pin out-of-round wear?", "options": ["Telescopic gauge.", "Micrometer caliper.", "Dial indicator."], "correctIndex": 1, "explanation": "Piston pin out-of-round can be measured with a vernier micrometer caliper. Measure each end of the pin in two directions at right angles to each other. The difference in the two readings is the amount the pin is out-of-round.", "img": null}, {"id": "16-363", "deck": 16, "q": "What metal has special short-time heat properties and is used in the construction of aircraft firewalls?", "options": ["Stainless steel.", "Chrome molybdenum alloy steel.", "Titanium alloy."], "correctIndex": 2, "explanation": "Titanium has some merit for short-time exposure up to 3,000 degrees F where strength is not important. Aircraft firewalls demand this requirement.", "img": null}, {"id": "16-364", "deck": 16, "q": "Self-locking nuts may be used on aircraft provided that", "options": ["the bolt and nut are safety wired.", "the bolt and nut is not under tension.", "the bolt or nut are not subject to rotation."], "correctIndex": 2, "explanation": "Self-locking nuts are used on aircraft to provide tight connections which will not shake loose under severe vibration. Do not use self-locking nuts at joints that subject either the nut or bolt to rotation.", "img": null}, {"id": "17-365", "deck": 17, "q": "When stopping a nosewheel-type airplane after taxiing (or towing), the nosewheel should be left:", "options": ["Unlocked and pointed straight ahead.", "Turned at a small angle towards uphill if the parking area is not perfectly flat.", "Pointed straight ahead."], "correctIndex": 2, "explanation": "When stopping an airplane that is equipped with a nosewheel, the nosewheel should be left straight ahead to relieve any strain on the nose gear and to make it easier to start moving straight ahead.", "img": null}, {"id": "17-366", "deck": 17, "q": "Both gasoline and kerosene have certain advantages for use as turbine fuel. Which statement is true in reference to the advantages of each?", "options": ["Kerosene has a higher heat energy/value per unit weight than gasoline.", "Gasoline has a higher heat energy/value per unit volume than kerosene.", "Kerosene has a higher heat energy/value per unit volume than gasoline."], "correctIndex": 2, "explanation": "Gasoline has a higher heat energy per pound than kerosine (nominally 20,000 Btu per pound for gasoline versus about 18,500 Btu per pound for kerosine). Kerosine, however, weighs more than gasoline (about 6.7 pounds per gallon for kerosine compared with about 6.0 pounds per gallon for gasoline). Because there are more pounds of kerosine per gallon, there are more Btu's in a gallon of kerosine than in a gallon of gasoline. Note: ASA prefers to adopt the scientific/technical spelling of 'kerosine.'", "img": null}, {"id": "17-367", "deck": 17, "q": "Jet fuel number identifiers are:", "options": ["Performance numbers to designate the volatility of the fuel.", "Performance numbers and are relative to the fuel's performance in the aircraft engine.", "Type numbers and have no relation to the fuel's performance in the aircraft engine."], "correctIndex": 2, "explanation": "Jet engine fuel identification numbers (JP-4, JP-5, Jet A, Jet A1, and Jet B) are identification numbers only and do not relate in any way to the performance of the fuel in the engine.", "img": null}, {"id": "17-368", "deck": 17, "q": "Which of the following is the most satisfactory extinguishing agent for use on a carburetor or intake fire?", "options": ["Dry chemical.", "A fine, water mist.", "Carbon dioxide."], "correctIndex": 2, "explanation": "Carbon dioxide (CO(2)) is the most satisfactory fire-extinguishing agent to use for putting out an induction system fire in an aircraft engine. CO(2) does not damage the engine, and it does not leave any residue to clean up.", "img": null}, {"id": "17-369", "deck": 17, "q": "Which statement below reflects a typical requirement when towing some aircraft?", "options": ["Discharge all hydraulic pressure to prevent accidental operation of the nosewheel steering mechanism.", "Tailwheel aircraft must be towed backwards.", "If the aircraft has a steerable nosewheel, the torque-link lock should be set to full swivel."], "correctIndex": 2, "explanation": "When towing a tricycle-gear airplane, the nose wheel torque-link lock should either be disconnected or set to full swivel, whichever the aircraft manufacturer recommends. If this is not done, there is a good possibility that the tow bar can turn the nose wheel enough to break the steering stops.", "img": null}, {"id": "17-370", "deck": 17, "q": "(1) Jet fuel is of higher viscosity than aviation gasoline and therefore holds contaminants better.\n(2) Viscosity has no relation to contamination of fuel.\nRegarding the above statements:", "options": ["Only No. 1 is true.", "Both No. 1 and No. 2 are true.", "Neither No. 1 nor No. 2 is true."], "correctIndex": 0, "explanation": "Statement (1) is true. Jet fuel has a higher viscosity than gasoline and it holds contaminants more readily (better) than gasoline. Statement (2) is not true. Viscosity does have a great deal to do with the fact that jet fuel holds more contaminants than gasoline. The higher the viscosity, the fewer contaminants will settle out of the fuel.", "img": null}, {"id": "17-371", "deck": 17, "q": "Characteristics of aviation gasoline are:", "options": ["High heat value, High volatility.", "High heat value, Low volatility.", "Low heat value, Low volatility."], "correctIndex": 0, "explanation": "Aviation gasoline is suitable as a fuel for reciprocating engines because it has a high heat value (nominally 20,000 Btu per pound) and a high volatility. It readily changes from a liquid into a vapor so that it can be burned.", "img": null}, {"id": "17-372", "deck": 17, "q": "When first starting to move an aircraft while taxiing, it is important to:", "options": ["Test the brakes.", "Closely monitor the instruments.", "Notify the control tower."], "correctIndex": 0, "explanation": "When first starting to taxi an airplane, test the brakes for proper operation. If braking action is unsatisfactory, the engine should be shut down immediately.", "img": null}, {"id": "17-373", "deck": 17, "q": "If a hot start occurs during starting of a turbine powerplant, what is the likely cause?", "options": ["The starting unit overheated.", "The ambient air temperature was too high (over 100 degrees F).", "The fuel/air mixture was excessively rich."], "correctIndex": 2, "explanation": "A hot start of a turbojet engine is one in which the engine starts normally but the exhaust-gas temperature exceeds its allowable limits. Hot starts are usually caused by too rich a fuel-air mixture. (There was too much fuel for the amount of air being moved through the engine by the compressor.)", "img": null}, {"id": "17-374", "deck": 17, "q": "The main differences between grades 100 and 100LL fuel are:", "options": ["Volatility and lead content.", "Volatility, lead content, and color.", "Lead content and color."], "correctIndex": 2, "explanation": "The main difference between grades 100 and 100LL aviation gasoline is the content of tetraethyl lead and the color. Their antiknock characteristics are the same. Grade 100 is allowed to have a maximum of 3.0 milliliter of TEL per gallon, and it is dyed green. Grade 100LL is allowed to have a maximum of 2.0 milliliter of TEL per gallon, and it is dyed blue.", "img": null}, {"id": "17-375", "deck": 17, "q": "How are aviation fuels, which possess greater antiknock qualities than 100 octane, classified?", "options": ["According to the milliliters of lead.", "By reference to normal heptane.", "By performance numbers."], "correctIndex": 2, "explanation": "Aviation fuel whose antidetonation characteristics are better than those of the reference fuel (100-octane) are rated in performance numbers", "img": null}, {"id": "17-376", "deck": 17, "q": "When approaching the rear of an idling turbojet or turbofan engine, the hazard area extends aft of the engine approximately:", "options": ["200 Feet.", "100 Feet.", "50 Feet."], "correctIndex": 1, "explanation": "The hazard area extends aft of an idling turbojet or turbofan engine for approximately 100 feet.", "img": null}, {"id": "17-377", "deck": 17, "q": "A fuel that vaporizes too readily may cause:", "options": ["Hard starting.", "Detonation.", "Vapor lock."], "correctIndex": 2, "explanation": "If a fuel vaporizes too readily, it has a high vapor pressure. It requires a high pressure to keep the vapors in the fuel. Vapors that form in a fuel line can prevent liquid fuel flowing through the line and can stop the engine because of fuel exhaustion. This is a vapor lock.", "img": null}, {"id": "17-378", "deck": 17, "q": "The color of 100LL fuel is", "options": ["Blue.", "Colorless or straw.", "Red."], "correctIndex": 0, "explanation": "Low-lead 100-octane aviation gasoline is dyed blue. Turbine fuel is normally colorless or straw colored. Grade 80 aviation gasoline is dyed red.", "img": null}, {"id": "17-379", "deck": 17, "q": "How is a flooded engine, equipped with a float-type carburetor, cleared of excessive fuel?", "options": ["Crank the engine with the starter or by hand, with the mixture control in cutoff, ignition switch off, and the throttle fully open, until the fuel charge has been cleared.", "Turn off the fuel and the ignition. Discontinue the starting attempt until the excess fuel has cleared.", "Crank the engine with the starter or by hand, with the mixture control in cutoff, ignition switch on, and the throttle fully open, until the excess fuel has cleared or until the engine starts."], "correctIndex": 0, "explanation": "A flooded reciprocating engine can be cleared of excessive fuel by placing the mixture control in the CUTOFF position to shut off all flow of fuel to the cylinders. Turn the ignition off, open the throttle and crank the engine with the starter or by hand until the fuel charge in the cylinders has been cleared.", "img": null}, {"id": "17-380", "deck": 17, "q": "Characteristics of detonation are:", "options": ["Cylinder pressure remains the same, excessive cylinder head temperature, and a decrease in engine power.", "Rapid rise in cylinder pressure, excessive cylinder head temperature, and a decrease in engine power.", "Rapid rise in cylinder pressure, cylinder head temperature normal, and a decrease in engine power."], "correctIndex": 1, "explanation": "Detonation is an uncontrolled burning, or explosion, of the fuel-air mixture within the cylinder of a reciprocating engine. The fuel-air mixture ignites and burns normally. But as it burns, it compresses and heats the mixture ahead of the flame front. When the heated and compressed mixture reaches its critical pressure and temperature, it releases its energy almost instantaneously (it explodes). It is the explosions inside the cylinder that cause the cylinder-head temperature to go up, the cylinder pressure to go up, and the engine power to decrease.", "img": null}, {"id": "17-381", "deck": 17, "q": "The most important condition to be monitored during start after fuel flow begins in a turbine engine is the:", "options": ["EGT, TIT, or ITT.", "RPM.", "Oil pressure."], "correctIndex": 0, "explanation": "When starting a turbine engine, the most critical instrument to watch after the fuel flow begins is the EGT, TIT, or ITT to be sure that the engine lights off properly and the temperature does not rise above its allowable limits.", "img": null}, {"id": "17-382", "deck": 17, "q": "Tetraethyl lead is added to aviation gasoline to:", "options": ["Retard the formation of corrosives.", "Improve the gasoline's performance in the engine.", "Dissolve the moisture in the gasoline."], "correctIndex": 1, "explanation": "Tetraethyl lead is added to aviation gasoline to increase its critical pressure and temperature. The higher critical pressure and temperature allow the engine to operate with higher cylinder pressures without the fuel-air mixture detonating.", "img": null}, {"id": "17-383", "deck": 17, "q": "A hung start in a jet engine is often caused by:", "options": ["Malfunctions in the ignition system.", "The starter cutting off too soon.", "An excessively rich fuel/air mixture."], "correctIndex": 1, "explanation": "A hung, or false, start is often the result of insufficient power to the starter or the starter cutting off before the engine reaches its self-accelerating speed.", "img": null}, {"id": "17-384", "deck": 17, "q": "If fan engine fire develops during the starting procedures the first step you should take in extinguishing the fire is:", "options": ["Discontinue the start attempt and allow the fireguard to extinguish the fire using the available equipment.", "Continue cranking to start the engine and blow out the fire.", "Continue cranking and allow the fireguard to extinguish the fire using the available -equipment."], "correctIndex": 1, "explanation": "If fan engine fire develops during the starting procedure, continue cracking to start the engine and blow out the fire. If the engine does not start and the fire continues to burn, discontinue the start attempt. The fireguard should extinguish the fire using the available equipment.", "img": null}, {"id": "17-385", "deck": 17, "q": "What must accompany fuel vaporization?", "options": ["An absorption of heat.", "A decrease in vapor pressure.", "A reduction in volume."], "correctIndex": 0, "explanation": "When fuel changes from a liquid into a vapor, it absorbs heat from the surrounding air. This absorption of heat drops the temperature of the air enough that moisture can condense out and freeze. This is the main cause of carburetor ice.", "img": null}, {"id": "17-386", "deck": 17, "q": "Which of the following conditions has the most potential for causing engine damage when starting or attempting to start a turbine engine?", "options": ["Hung start.", "Cold start.", "Hot start."], "correctIndex": 2, "explanation": "A hot start is one in which the exhaust gas temperature (EGT) or turbine inlet temperature (TIT) rises above its allowable limit. An engine can be seriously damaged by a hot start.", "img": null}, {"id": "17-387", "deck": 17, "q": "Why is ethylene dibromide added to aviation gasoline?", "options": ["To remove zinc silicate deposits from the spark plugs.", "To scavenge lead oxide from the cylinder combustion chambers.", "To increase the antiknock rating of the fuel."], "correctIndex": 1, "explanation": "Tetraethyl lead is added to aviation gasoline to improve its antidetonation characteristics (to raise its critical pressure and temperature), but deposits left inside the cylinders from the tetraethyl lead foul spark plugs and cause corrosion. In order to get rid of the residue from the tetraethyl lead, ethylene dibromide is mixed with the gasoline. When the gasoline burns, the ethylene dibromide combines with the lead and forms volatile lead bromides that go out the exhaust and do not form solid contaminants inside the cylinder.", "img": null}, {"id": "17-388", "deck": 17, "q": "Which statement(s) is/are true regarding tiedown of small aircraft?\n1. Manila (hemp) rope has a tendency to stretch when it gets wet.\n2. Nylon or dacron rope is preferred to manila rope.\n3. The aircraft should be headed downwind in order to eliminate or minimize wing lift.\n4. Leave the nosewheel or tailwheel unlocked.", "options": ["1, 2, 3, and 4.", "1 and 2.", "2."], "correctIndex": 2, "explanation": "Manilla (hemp) rope has the tendency to shrink, not stretch, when it gets wet. Nylon and dacron rope are both superior to manilla because they are stronger, and neither of them shrink when they are wet. The airplanes should be pointed as nearly into the wind as practicable and the tail wheel or nosewheel should be locked in their straight-ahead position to prevent the wind from slewing the aircraft around.", "img": null}, {"id": "17-389", "deck": 17, "q": "Generally, when an induction fire occurs during starting of a reciprocating engine, the first course of action should be to", "options": ["Discharge carbon dioxide from a fire extinguisher into the air intake of the engine.", "Continue cranking and start the engine if possible.", "Close the throttle."], "correctIndex": 1, "explanation": "If an induction system fire occurs when starting a reciprocating engine, the best procedure is to continue cranking and start the engine if possible. When the engine starts, the air flowing into the engine will extinguish the fire.", "img": null}, {"id": "17-390", "deck": 17, "q": "When towing a large aircraft:", "options": ["A person should be in the cockpit to watch for obstructions.", "Persons should be stationed at the nose, each wingtip, and the empennage at all times.", "A person should be in the cockpit to operate the brakes."], "correctIndex": 2, "explanation": "When a large aircraft is being towed, there should be a person in the cockpit to operate the brakes in the event of an emergency.", "img": null}, {"id": "17-391", "deck": 17, "q": "Weathervaning tendency is greatest when taxiing:", "options": ["Both nosewheel and tailwheel-type airplanes in a quartering tailwind.", "A tailwheel-type airplane in a direct crosswind.", "A nosewheel-type airplane in a quartering headwind."], "correctIndex": 1, "explanation": "Weathervaning tendency is more prevalent in the tailwheel-type because the airplane's surface area behind the main landing gear is greater than in nosewheel-type airplanes. The tendency of a tailwheel-type airplane to weather vane is greatest while taxiing directly crosswind. It is difficult to prevent the airplane from turning into any wind of considerable velocity since the airplane's rudder capability may be inadequate to counteract the crosswind.", "img": null}, {"id": "17-392", "deck": 17, "q": "(Refer to Figure 50.) Identify the signal to engage rotor on a rotorcraft.", "options": ["1.", "3.", "2."], "correctIndex": 1, "explanation": "Signal 1 means to start the engine. Signal 2 means to stop the rotor. Signal 3 means to engage the rotor.", "img": "426986_2.jpg"}, {"id": "17-393", "deck": 17, "q": "(Refer to Figure 51.) Which marshalling signal should be given if a taxiing aircraft is in imminent danger of striking an object?", "options": ["1 or 3.", "2.", "3."], "correctIndex": 2, "explanation": "Signal 1 means to stop. Signal 2 means to come ahead. Signal 3 calls for an emergency stop. If the aircraft is in imminent danger of striking an object, the signal shown in 3 should be used.", "img": "426986_3.jpg"}, {"id": "17-394", "deck": 17, "q": "When taxiing (or towing) an aircraft, an alternating red and green light from the control tower means:", "options": ["Move clear of the runway/taxiway immediately.", "OK to proceed but use extreme caution.", "Return to starting point."], "correctIndex": 1, "explanation": "The meanings of the light signals that are used by control towers to control the operation of aircraft on the ground are: Steady red -- Stop Flashing red -- Taxi clear of the runway or taxiway Steady green -- OK to taxi Alternating red and green -- OK to taxi, but exercise extreme caution Flashing white -- Return to starting point.", "img": null}, {"id": "17-395", "deck": 17, "q": "A fuel that does not vaporize readily enough can cause:", "options": ["Vapor lock.", "Detonation.", "Hard starting."], "correctIndex": 2, "explanation": "An ideal fuel for an aircraft reciprocating engine must vaporize (change from a liquid into a vapor) easily, yet it must not vaporize so easily that it will form vapor locks in the fuel system. Liquid fuel will not burn, so for it to burn, it must be changed into a fuel vapor. If the fuel does not vaporize readily enough, it will cause the engine to be hard to start.", "img": null}, {"id": "17-396", "deck": 17, "q": "When taxiing (or towing) an aircraft, a flashing white light from the control tower means:", "options": ["Move clear of the runway/taxiway immediately.", "OK to proceed but use extreme caution.", "Return to starting point."], "correctIndex": 2, "explanation": "The meanings of the light signals that are used by control towers to control the operation of aircraft on the ground are: Steady red -- Stop Flashing red -- Taxi clear of the runway or taxiway Steady green -- OK to taxi Alternating red and green -- OK to taxi, but exercise extreme caution Flashing white -- Return to starting point.", "img": null}, {"id": "17-397", "deck": 17, "q": "When taxiing an airplane with a quartering tailwind, the elevators and:", "options": ["Upwind aileron should be held in the up position.", "Upwind aileron should be held in the down position.", "Both ailerons should be kept in the neutral position."], "correctIndex": 1, "explanation": "When taxiing with a quartering tailwind, the elevator should be held in the DOWN position, and the upwind aileron, DOWN. Since the wind is striking the airplane from behind, these control positions reduce the tendency of the wind to get under the tail and the wing and to nose the airplane over.", "img": null}, {"id": "17-398", "deck": 17, "q": "What effect, if any, will aviation gasoline mixed with jet fuel have on a turbine engine?", "options": ["No appreciable effect.", "The tetraethyl lead in the gasoline forms deposits on the turbine blades.", "The tetraethyl lead in the gasoline forms deposits on the compressor blades."], "correctIndex": 1, "explanation": "Many aviation gas turbine engine manufacturers allow the use of some aviation gasoline as a fuel when turbine fuel is not available. The manufacturer limits the amount of time aviation gasoline can be used for two reasons: (1) The tetraethyl lead in the aviation gasoline causes deposits to form on the turbine blades. (2) Aviation gasoline does not have the lubricating properties of kerosine. Using too much gasoline can cause excessive wear on the fuel control.", "img": null}, {"id": "17-399", "deck": 17, "q": "When taxiing (or towing) an aircraft, a flashing red light from the control tower means:", "options": ["Stop and wait for a green light.", "Move clear of the runway/taxiway immediately.", "Return to starting point."], "correctIndex": 1, "explanation": "The meanings of the light signals that are used by control towers to control the operation of aircraft on the ground are: Steady red -- Stop Flashing red -- Taxi clear of the runway or taxiway Steady green -- OK to taxi Alternating red and green -- OK to taxi, but exercise extreme caution Flashing white -- Return to starting point.", "img": null}, {"id": "17-400", "deck": 17, "q": "When approaching the front of an idling jet engine, the hazard area extends forward of the engine approximately:", "options": ["10 Feet.", "15 Feet.", "25 Feet."], "correctIndex": 2, "explanation": "It is extremely dangerous to approach an operating turbojet engine from either ahead or behind. The hazard area extends out ahead of an idling turbojet engine for about 25 feet.", "img": null}, {"id": "17-401", "deck": 17, "q": "During starting of a turbine powerplant using a compressed air starter, a hung start occurred. Select the proper procedure:", "options": ["Advance power lever to increase RPM.", "Re-engage the starter.", "Shut the engine down."], "correctIndex": 2, "explanation": "A hung start of a turbojet engine is a start in which the engine lights off as it should, but does not accelerate to a speed that allows it to operate without help from the starter. Anytime a hung start occurs, the engine should be shut down and the cause of the problem found and corrected.", "img": null}, {"id": "17-402", "deck": 17, "q": "When starting and ground operating an aircraft's engine, the aircraft should be positioned to head into the wind primarily:", "options": ["To aid in achieving and maintaining the proper air flow into the engine induction system.", "For engine cooling purposes.", "To help cancel out engine torque effect."], "correctIndex": 1, "explanation": "Position the aircraft to head into the prevailing wind to ensure adequate air flow over the engine for cooling purposes.", "img": null}, {"id": "17-403", "deck": 17, "q": "The priming of a fuel injected horizontally opposed engine is accomplished by placing the fuel control lever in the:", "options": ["IDLE-CUTOFF position.", "AUTO-RICH position.", "FULL-RICH position."], "correctIndex": 2, "explanation": "When starting a horizontally opposed aircraft engine equipped with a fuel-injection system, prime the engine by placing the mixture control in the FULL-RICH position and turning on the fuel boost pump until there is an indication of fuel flow on the flow meter. After some fuel has flowed through the injector nozzles, the mixture control is returned to the IDLE-CUTOFF position and the engine is started. As soon as the engine starts, the mixture control is again placed in the FULL-RICH position.", "img": null}, {"id": "17-404", "deck": 17, "q": "If a radial engine has been shut down for more than 30 minutes, the propeller should be rotated through at least two revolutions to:", "options": ["Check for hydraulic lock.", "Check for leaks.", "Prime the engine."], "correctIndex": 0, "explanation": "A radial engine that has been shut down for some time should be turned through by hand for at least two revolutions to check for a hydraulic lock. A hydraulic lock is a condition in a reciprocating engine in which oil has leaked past the piston rings into a cylinder below the center of the engine. If the engine fires when there is oil in any of its cylinders, it will sustain major structural damage.", "img": null}, {"id": "17-405", "deck": 17, "q": "A person should approach or leave a helicopter in the pilot's field of vision whenever the engine is running in order to avoid", "options": ["The tail rotor.", "The main rotor.", "Blowing dust or debris caused by rotor downwash."], "correctIndex": 0, "explanation": "When approaching or leaving a helicopter whose engine is running, you should remain within the pilot's field of vision to avoid an encounter with the tail rotor.", "img": null}, {"id": "18-406", "deck": 18, "q": "A primary reason why ordinary or otherwise nonapproved cleaning compounds should not be used when washing aircraft is because their use can result in", "options": ["hydrogen embrittlement in metal structures.", "hydrogen embrittlement in nonmetallic materials.", "a general inability to remove compound residues."], "correctIndex": 0, "explanation": "Some nonapproved commercial cleaning compounds can cause a chemical reaction with some of the metals used in aircraft structure. This reaction releases hydrogen gas that can be absorbed into the metal and cause hydrogen embrittlement which weakens the metal and can cause cracking and failure.", "img": null}, {"id": "18-407", "deck": 18, "q": "How may magnesium engine parts be cleaned?", "options": ["Soak in a 20 percent caustic soda solution.", "Spray with MEK (methyl ethyl ketone).", "Wash with a commercial solvent, decarbonize, and scrape or grit blast."], "correctIndex": 2, "explanation": "Magnesium engine parts are cleaned by washing them with a commercial solvent such as naphtha or Stoddard solvent, then soaking them in a decarbonizer that has been proven safe for magnesium.\nAny hard deposits that are not removed by this treatment can be removed with a scraper or with a grit blast.", "img": null}, {"id": "18-408", "deck": 18, "q": "When an anodized surface coating is damaged in service, it can be partially restored by", "options": ["applying a thin coat of zinc chromate primer.", "chemical surface treatment.", "use of a suitable mild cleaner."], "correctIndex": 1, "explanation": "An anodized coating is an electrolytically deposited film of oxide that covers the surface of the metal and keeps air and moisture away from it. If this coating is damaged, the metal can corrode. Damaged anodized coating can be repaired by treating the damaged area with a chemical conversion coating material such as Alodine. This chemical treatment forms a hard oxide film on the surface much like the anodized surface.", "img": null}, {"id": "18-409", "deck": 18, "q": "For which of the following reasons would a water break test be conducted?", "options": ["To make certain that a newly alodized aluminum surface is sufficiently coated.", "To make certain that a bare metal surface is thoroughly clean.", "To make certain that an anodizing coating has been sufficiently removed before an electrical bonding connection can be made."], "correctIndex": 1, "explanation": "Alodine can be applied to a surface after all traces of corrosion have been removed. The surface should be chemically cleaned until it supports an unbroken water film. Any breaks in the film of rinse water show that there some wax, grease, or oil on  the surface, and further cleaning must be done.", "img": null}, {"id": "18-410", "deck": 18, "q": "Select the solvent recommended for wipedown of cleaned surfaces just before painting.", "options": ["Aliphatic naptha.", "Dry-cleaning solvent.", "Aromatic naptha."], "correctIndex": 0, "explanation": "Aliphatic naptha is a petroleum product between gasoline and kerosine in its characteristics. It is well suited for use as a cleaning agent for removing fingerprints, dust, and oily deposits that have settled on a surface to prepare the surface for painting. Dry-cleaning solvent, such as Stoddard solvent, leaves a slight residue on the surface that can interfere with the adhesion of the paint.|Aromatic naptha is a coal tar derivative that is toxic and attacks acrylics and rubber products. It is not suitable for wiping down a surface before painting.", "img": null}, {"id": "18-411", "deck": 18, "q": "Nickel-cadmium battery cases and drain surfaces which have been affected by electrolyte should be neutralized with a solution of", "options": ["boric acid.", "sodium bicarbonate.", "potassium hydroxide."], "correctIndex": 0, "explanation": "An area that has been affected by the electrolyte from a nickel-cadmium battery should be washed and neutralized with ammonia or a boric acid solution, allowed to dry thoroughly, then painted with an alkali-resisting varnish.", "img": null}, {"id": "18-412", "deck": 18, "q": "Which of the following are acceptable to use when utilizing chemical cleaning agents on aircraft?\n1. Synthetic fiber wiping cloths when using a flammable agent.\n2. Cotton fiber wiping cloths when using a flammable agent.\n3. Atomizing spray equipment.", "options": ["2 and 3.", "1.", "2."], "correctIndex": 0, "explanation": "When cleaning and/or depainting an aircraft surface with a flammable agent, use only a cotton wiping cloth or a natural bristle brush. Synthetic fibers tend to create unsafe charges of static electricity that could ignite the flammable agent. Emulsion-type cleaning agents may be applied to the surface with atomizing spray equipment. After the agent has penetrated the dirt or exhaust residue, it is scrubbed with a natural bristle brush and washed from the surface.", "img": null}, {"id": "18-413", "deck": 18, "q": "Select the solvent used to clean acrylics and rubber.", "options": ["Aliphatic naphtha.", "Methyl ethyl ketone.", "Aromatic naphtha."], "correctIndex": 0, "explanation": "Aliphatic naphtha is the only one of the three materials listed here that will not damage rubber or acrylic plastic. Be sure that aromatic naphtha (a coal tar derivative) is not used.", "img": null}, {"id": "18-414", "deck": 18, "q": "Fayed surfaces cause concern in chemical cleaning because of the danger of", "options": ["forming passive oxides.", "entrapping corrosive materials.", "corrosion by imbedded iron oxide."], "correctIndex": 1, "explanation": "Fayed surfaces are the parts of a structure that are covered in a lap joint. It is important when a structure is chemically cleaned that the fayed surfaces be protected so that corrosive materials do not seep between the sheets in the lap joints. This would cause corrosion to form in an area where it is hard to detect.", "img": null}, {"id": "18-415", "deck": 18, "q": "Caustic cleaning products used on aluminum structures have the effect of producing", "options": ["passive oxidation.", "improved corrosion resistance.", "corrosion."], "correctIndex": 2, "explanation": "Aluminum alloys such as those used in an aircraft structure are reactive metals. This means that they are likely to react with chemicals to form salts (corrosion). Many caustic cleaning products react with aluminum alloy and cause them to corrode.", "img": null}, {"id": "18-416", "deck": 18, "q": "Fretting corrosion is most likely to occur", "options": ["when two surfaces fit tightly together but can move relative to one another.", "only when two dissimilar metals are in contact.", "when two surfaces fit loosely together and can move relative to one another."], "correctIndex": 0, "explanation": "Fretting corrosion is a form of corrosion that forms between closely fitting assembled parts that have a slight amount of relative motion. When sheets of aluminum alloy are riveted together, there should be no relative motion between the sheets or between the sheets and the rivets. But if there is a slight bit of movement, the protective oxide coating will be rubbed off of the metal and a new oxide coating will form. The material that has been rubbed off acts as an abrasive and accelerates the wear.", "img": null}, {"id": "18-417", "deck": 18, "q": "The rust or corrosion that occurs with most metals is the result of", "options": ["a tendency for them to return to their natural state.", "blocking the flow of electrons in homogenous metals, or between dissimilar metals.", "electron flow in or between metals from cathodic to anodic areas."], "correctIndex": 0, "explanation": "Corrosion is a natural phenomenon which attacks metal by chemical or electrochemical action and converts it into a metallic compound, such as an oxide, hydroxide, or sulfate. Corrosion occurs because of the tendency for metals to return to their natural state. Noble metals like gold and platinum do not corrode since they are chemically uncombined in their natural state.", "img": null}, {"id": "18-418", "deck": 18, "q": "Which of the following are the desired effects of using Alodine on aluminum alloy?\n1. A slightly rough surface.\n2. Relieved surface stresses.\n3. A smooth painting surface.\n4. Increased corrosion resistance.", "options": ["3 and 4.", "1, 2, and 4.", "1 and 4."], "correctIndex": 2, "explanation": "Alodine is a conversion coating used to prepare aluminum alloys for painting. It etches the surface providing a microscopically rough surface and forms an oxide film on the surface to increase the corrosion resistance.", "img": null}, {"id": "18-419", "deck": 18, "q": "Which of the listed conditions is NOT one of the requirements for corrosion to occur?", "options": ["The presence of an electrolyte.", "Electrical contact between an anodic area and a cathodic area.", "The presence of a passive oxide film."], "correctIndex": 2, "explanation": "There are four conditions that must exist before corrosion can occur:\n1. The presence of a metal that will corrode, the anode.\n2. Presence of a dissimilar conductive material, the cathode, which has less tendency to corrode.\n3. Presence of a conductive liquid, the electrolyte.\n4. Electrical contact between the anode and cathode.\nA passive oxide film is used as a corrosion preventive.", "img": null}, {"id": "18-420", "deck": 18, "q": "The lifting or flaking of the metal at the surface due to delamination of grain boundaries caused by the pressure of corrosion residual product buildup is called", "options": ["brinelling.", "granulation.", "exfoliation."], "correctIndex": 2, "explanation": "Exfoliation corrosion is a severe form of intergranular corrosion that normally forms in extruded metal. When metal is extruded, its grain structure is basically arranged in a series of layers. If an extrusion is improperly heat-treated, the grains are enlarged to the extent that intergranular corrosion can form along the grain boundaries within the metal. Severe intergranular corrosion in an extruded material causes it to delaminate (the layers of the metal to push apart). The surface of the metal lifts or flakes off.", "img": null}, {"id": "18-421", "deck": 18, "q": "A nonelectrolytic chemical treatment for aluminum alloys to increase corrosion resistance and paint-bonding qualities is called", "options": ["anodizing.", "alodizing.", "dichromating."], "correctIndex": 1, "explanation": "Alodizing is the depositing of an oxide film on the surface of aluminum alloy by the application of the patented chemical, Alodine. The generic term for this type of nonelectrolytic corrosion protection is conversion coating. Anodizing is a method of electrolytically depositing a hard film of aluminum hydroxide on the surface of the metal.", "img": null}, {"id": "18-422", "deck": 18, "q": "Which of the following are acceptable to use in cleaning anodized surfaces?\n1. Steel wool.\n2. Brass wire brush.\n3. Aluminum wool.\n4. Stainless steel wire brush.\n5. Fiber bristle brush.", "options": ["1, 3, & 5.", "2 & 4.", "3 & 5."], "correctIndex": 2, "explanation": "Anodized surfaces should never be cleaned with anything that could scratch through the anodizing and expose the untreated alloy, or that could contaminate the surface. For this reason only aluminum wool or fiber bristle brushes are suitable for cleaning these surfaces.", "img": null}, {"id": "18-423", "deck": 18, "q": "Intergranular corrosion in aluminum alloy parts", "options": ["may be detected by surface pitting, and white, powdery deposit formed on the surface of the metal.", "commonly appears as threadlike filaments of corrosion products under a dense film of paint.", "cannot always be detected by surface indications."], "correctIndex": 2, "explanation": "Intergranular corrosion forms along the grain boundaries within an aluminum alloy. Since this type of corrosion does not necessarily extend all the way to the surface of the metal in its early stages, it is quite possible for intergranular corrosion to reach an advanced state before it shows up on the surface.", "img": null}, {"id": "18-424", "deck": 18, "q": "Which of the following may not be detectable even by careful visual inspection of the surface of aluminum alloy parts or structures?", "options": ["Filiform corrosion.", "Intergranular corrosion.", "Uniform etch corrosion."], "correctIndex": 1, "explanation": "Intergranular corrosion is an attack along the grain boundaries of an alloy and commonly results from a lack of uniformity in the alloy structure. Intergranular corrosion is difficult to detect in its early stage, and ultrasonic and eddy current inspection methods must be used.", "img": null}, {"id": "18-425", "deck": 18, "q": "What may be used to remove corrosion from highly stressed steel surfaces?", "options": ["Steel wire brushes.", "Fine-grit aluminum oxide.", "Medium-grit carborundum paper."], "correctIndex": 1, "explanation": "Any corrosion on the surface of a highly stressed steel part is potentially dangerous, and all of the corrosion products must be removed. The removal can be done with mild abrasive papers such as rouge or fine grit aluminum oxide, or fine buffing compounds on cloth buffing wheels.", "img": null}, {"id": "18-426", "deck": 18, "q": "A primary cause of intergranular corrosion is", "options": ["improper heat treatment.", "dissimilar metal contact.", "improper application of primer."], "correctIndex": 0, "explanation": "One of the primary causes for intergranular corrosion is improper heat treatment. If there is a delay in the time between the removal of a metal part from the heat treatment oven and the time the part is quenched, the grains of the metal have an opportunity to grow large enough that an electrical potential exists across the grain boundaries. This potential within the metal causes the formation of intergranular corrosion.", "img": null}, {"id": "18-427", "deck": 18, "q": "Corrosion should be removed from magnesium parts with a", "options": ["stiff, nonmetallic brush.", "silicon carbide brush.", "carborundum abrasive."], "correctIndex": 0, "explanation": "Mechanical removal of corrosion from magnesium parts should be limited to the use of stiff hog-bristle brushes and similar nonmetallic cleaning tools.", "img": null}, {"id": "18-428", "deck": 18, "q": "Why is it important not to rotate the crankshaft after the corrosion preventive mixture has been put into the cylinders on engines prepared for storage?", "options": ["Fuel may be drawn into one or more cylinders and dilute or wash off the corrosion preventive mixture.", "The seal of corrosion preventive mixture will be broken.", "Engine damage can occur from hydraulic lock."], "correctIndex": 1, "explanation": "When a reciprocating engine is prepared for storage, the inside of the cylinders are sprayed with a mixture of engine oil and a preservative oil. The oil mixture forms a seal on the cylinder wall and across the top of the piston. This mixture keeps air and moisture away from the metal surface. If the propeller is turned, the pistons will move and break the seal so that air and moisture can reach the cylinder walls and cause them to rust.", "img": null}, {"id": "18-429", "deck": 18, "q": "Which of the following is an acceptable first step procedure to help prevent scratching when cleaning a transparent plastic surface?", "options": ["Gently wipe the surface with a clean, dry, soft cloth.", "Flush the surface with clean water.", "Gently wipe the surface with a clean, soft cloth moistened with de-mineralized or distilled water."], "correctIndex": 1, "explanation": "When cleaning the transparent plastic windshield of an aircraft, you should first flush it with a stream of clean fresh water to remove all sand and grit from the surface. After the surface is free of anything that can scratch the soft plastic, it can be washed with soap and water and then rinsed.", "img": null}, {"id": "18-430", "deck": 18, "q": "What should be done to prevent rapid deterioration when oil or grease come in contact with a tire?", "options": ["Wipe the tire thoroughly with a dry cloth, and then rinse with clean water.", "Wipe the tire with a dry cloth followed by a washdown and rinse with soap and water.", "Wipe the tire with a cloth dampened with aromatic naphtha and then wipe dry with a clean cloth."], "correctIndex": 1, "explanation": "When an aircraft tire comes in contact with oil or grease, remove all of the excess material by wiping it with a dry cloth. Then wash the tire with a solution of mild soap and warm water. Rinse the tire with fresh water and dry it with compressed air.", "img": null}, {"id": "18-431", "deck": 18, "q": "Galvanic corrosion is likely to be most rapid and severe when", "options": ["the surface area of the cathodic metal is smaller than surface area of the anodic metal.", "the surface areas of the anodic and cathodic metals are approximately the same.", "the surface area of the anodic metal is smaller than the surface area of the cathodic metal."], "correctIndex": 2, "explanation": "Galvanic corrosion occurs when two dissimilar metals make electrical contact in the presence of an electrolyte. The rate at which corrosion occurs depends on the difference in the activities of the two metals. The greater the difference, the faster the corrosion occurs. The rate of galvanic corrosion also depends on the size of the parts in contact. If the surface area of the corroding material, the anode, is smaller than the surface area of the less active metal, the cathode, corrosion will be rapid and severe.", "img": null}, {"id": "18-432", "deck": 18, "q": "Corrosion caused by galvanic action is the result of", "options": ["excessive anodization.", "contact between two unlike metals.", "excessive etching."], "correctIndex": 1, "explanation": "Galvanic corrosion is caused by an electrolytic action that takes place when two metals that have a different place in the galvanic scale are in contact with each other and are covered with an electrolyte. The more anodic of the metals reacts with the electrolyte and some of it changes into salts (it corrodes).", "img": null}, {"id": "18-433", "deck": 18, "q": "Which of these materials is the most anodic?", "options": ["Cadmium.", "7075-T6 aluminum alloy.", "Magnesium."], "correctIndex": 2, "explanation": "Some of the common metals in the order of their electrochemical activity are:\n(Most anodic)\nMagnesium\nZinc\nCadmium\n7075 Aluminum alloy\n2024 Aluminum alloy\nMild steel\nCopper\nStainless Steel\nChromium\nGold\n(Most cathodic)", "img": null}, {"id": "18-434", "deck": 18, "q": "The interior surface of sealed structural steel tubing would be best protected against corrosion by which of the following?", "options": ["Charging the tubing with dry nitrogen prior to sealing.", "Evacuating moisture from the tubing before sealing.", "A coating of linseed oil."], "correctIndex": 2, "explanation": "The inside of structural steel tubing on an aircraft is protected from rust and corrosion by drilling small holes in the end of each section of the tube and pumping linseed oil through the hole. After the inside is thoroughly coated, the excess oil is drained out and the hole is sealed with a drive screw or by welding it shut.", "img": null}, {"id": "18-435", "deck": 18, "q": "Which of these materials is the most cathodic?", "options": ["Zinc.", "2024 aluminum alloy.", "Stainless steel."], "correctIndex": 2, "explanation": "Some of the common metals in the order of their electrochemical activity are:\n(Most anodic)\nMagnesium\nZinc\nCadmium\n7075 Aluminum alloy\n2024 Aluminum alloy\nMild steel\nCopper\nStainless Steel\nChromium\nGold\n(Most cathodic)", "img": null}, {"id": "18-436", "deck": 18, "q": "Of the following, when and/or where is galvanic corrosion is most likely to occur?", "options": ["When an electrolyte (water) covers the surface of an aluminum skin, seeps into the cracks between lap joints, and oxygen is excluded from the area.", "At the interface of a steel fastener and aluminum alloy inspection plate in the presence of an electrolyte.", "In an area of unprotected metal exposed to an atmosphere containing battery fumes, exhaust gases, or industrial contaminants."], "correctIndex": 1, "explanation": "Galvanic corrosion occurs any time two dissimilar metals make electrical contact in the presence of an electrolyte.", "img": null}, {"id": "18-437", "deck": 18, "q": "One way of obtaining increased resistance to stress corrosion cracking is by", "options": ["relieving compressive stresses (via heat treatment) on the metal surface.", "creating compressive stresses (via shot peening) on the metal surface.", "producing nonuniform deformation while cold working during the manufacturing process."], "correctIndex": 1, "explanation": "Stress-corrosion cracking is an intergranular cracking of the metal which is caused by a combination of stress and corrosion. Shot peening a metal surface increases its resistance to stress corrosion cracking by creating compressive stresses on the surface. Any applied tensile stress must first overcome the surface compression before the tensile stress is felt.", "img": null}, {"id": "18-438", "deck": 18, "q": "(1) In the corrosion process, it is the cathodic area or dissimilar cathodic material that corrodes.\n(2) In the Galvanic or Electro-Chemical Series for metals, the most anodic metals are those that will give up electrons most easily.\nRegarding the above statements,", "options": ["only No. 1 is true.", "only No. 2 is true.", "both No. 1 and No. 2 are true."], "correctIndex": 1, "explanation": "Statement (1) is false. It is the anodic, not the cathodic, material that is destroyed in the corrosion process. Statement (2) is true. Corrosion occurs in an anodic material when it gives up electrons to a cathodic material. The more easily a material gives up electrons, the more anodic, or corrosive, it is.", "img": null}, {"id": "18-439", "deck": 18, "q": "Spilled mercury on aluminum", "options": ["greatly increases susceptibility to hydrogen embrittlement.", "may cause impaired corrosion resistance if left in prolonged contact.", "causes rapid and severe corrosion that is very difficult to control."], "correctIndex": 2, "explanation": "Mercury spilled in an aircraft requires immediate action for its isolation and recovery to prevent it from causing corrosion damage and embrittlement of the aluminum structural components. Mercury is highly toxic and spreads very easily from one surface to another.", "img": null}, {"id": "19-440", "deck": 19, "q": "What power of 10 is equal to 1,000,000,000?", "options": ["10 to the sixth power.", "10 to the tenth power.", "10 to the ninth power."], "correctIndex": 2, "explanation": "An easy way to tell the power of 10 to which a number has been raised is to count the number of places the decimal would have to be moved to leave a number between 1 and 10. In this problem, the decimal would have to be moved nine places to the left. 1,000,000,000 is 1 x 10^9", "img": null}, {"id": "19-441", "deck": 19, "q": "Find the square root of 1,746.", "options": ["41.7852.", "41.7752.", "40.7742."], "correctIndex": 0, "explanation": "The square root of a number is the number that, when multiplied by itself, gives the number. By using an electronic calculator, we find that the square root of 1,746 is 41.785165.", "img": null}, {"id": "19-442", "deck": 19, "q": "(Refer to Figure 52.) Solve the equation.", "options": ["115", "4.472.", "5"], "correctIndex": 1, "explanation": "To solve this equation, follow these steps: clear all of the parentheses, perform the multiplication, then the addition. Finally take the square root of the number you have just obtained. Any number raised to the zero power is 1.\n(-4)^0 = 1\nThe fourth root of 1,296 is the same as 1,296 raised to the 1/4 power.\n1,296^0.25 = 6\nThe square of the square root of 3 = 3", "img": "429786_23.jpg"}, {"id": "19-443", "deck": 19, "q": "Find the square root of 3,722.1835.", "options": ["61.00971.", "61.00.", "61.0097."], "correctIndex": 2, "explanation": "The square root of a number is the number that, when multiplied by itself, gives the number. By using an electronic calculator, we find that the square root of 3,722.1835 is 61.00970005.", "img": null}, {"id": "19-444", "deck": 19, "q": "Which of the following is the square root of (-1776)/(-2) - 632?", "options": ["128.", "256.", "16."], "correctIndex": 2, "explanation": "Solve this problem in three steps:||1. Divide -1776 by -2: -1776/-2 = 888.\n2. Subtract 632 from 888: 888 - 632 = 256.\n3. Find the square root of 256: 16.", "img": null}, {"id": "19-445", "deck": 19, "q": "(Refer to Figure 69.) Solve the equation.", "options": ["12.", "60.", "76."], "correctIndex": 0, "explanation": "The square root of 100 is 10.\nThe square root of 36 is 6.\nThe square root of 16 is 4.\n10 + 6 - 4 = 12", "img": "429786_16.jpg"}, {"id": "19-446", "deck": 19, "q": "Find the cube of 64.", "options": ["4", "192", "262,144."], "correctIndex": 2, "explanation": "The cube of a number is found by multiplying the number by itself three times.\n64^3 = 64 x 64 x 64 = 262,144", "img": null}, {"id": "19-447", "deck": 19, "q": "Find the value of 10 raised to the negative sixth power.", "options": ["0.000001.", "0.000010.", "0.0001."], "correctIndex": 0, "explanation": "Ten raised to the negative sixth power (10^-6) is equal to 0.000 001. This negative number is the reciprocal of the positive sixth power of ten. It is found by dividing the number 1 by the sixth power of 10 (1,000,000).", "img": null}, {"id": "19-448", "deck": 19, "q": "What is the square root of 4 raised to the fifth power?", "options": ["32", "64", "20"], "correctIndex": 0, "explanation": "The square root of four is two. Two raised to the fifth power is 32.", "img": null}, {"id": "19-449", "deck": 19, "q": "The number 3.47 x 10 to the negative fourth power is equal to", "options": [".00347.", "34,700.", ".000347."], "correctIndex": 2, "explanation": "The value of 3.47 x 10^-4 is found by multiplying 3.47 by 1 divided by 10,000 (1 x 10^4).\n3.47 x 10^-4 = 0.000347", "img": null}, {"id": "19-450", "deck": 19, "q": "Which alternative answer is equal to 16,300?", "options": ["1.63 x 10 to the fourth power.", "1.63 x 10 to the negative third power.", "163 x 10 to the negative second power."], "correctIndex": 0, "explanation": "1.63 x 10^4 = 16,300\n1.63 x 10^-3 = 0.00163\n163 x 10^-2 = 1.63", "img": null}, {"id": "19-451", "deck": 19, "q": "Find the square root of 124.9924.", "options": ["111.8 x 10 to the third power.", ".1118 x 10 to the negative second power.", "1,118 x 10 to the negative second power."], "correctIndex": 2, "explanation": "The square root of 124.9924 is 11.18.\n111.8 x 10^3 = 111,800\n.1118 x 10^-2 = 0.001118\n1,118 x 10^-2 = 11.18", "img": null}, {"id": "19-452", "deck": 19, "q": "What is the square root of 16 raised to the fourth power?", "options": ["1,024.", "4,096.", "256."], "correctIndex": 2, "explanation": "The square root of 16 is 4. 4 raised to the 4th power is 256.", "img": null}, {"id": "19-453", "deck": 19, "q": "(Refer to Figure 53.) Solve the equation.", "options": [".0297.", ".1680.", ".0419."], "correctIndex": 2, "explanation": "The square root of 31 is 5.5677. The square root of 43 is 6.5574. The square of 17 is 289. \n(5.5677 + 6.5574) ÷ 289 = 0.0419", "img": "429786_17.jpg"}, {"id": "19-454", "deck": 19, "q": "The result of 7 raised to the third power plus the square root of 39 is equal to", "options": ["349.24.", ".34924.", "343.24."], "correctIndex": 0, "explanation": "7 raised to the 3rd power is 343. The square root of 39 is 6.245. The sum of these two numbers is 349.245.", "img": null}, {"id": "19-455", "deck": 19, "q": "Find the square root of 1,824.", "options": ["42.708 x 10 to the negative second power.", ".42708.", ".42708 x 10 to the second power."], "correctIndex": 2, "explanation": "The square root of 1,824 is 42.708. 42.708 x 10^-2 = 0.42708\n.42708 x 10^2 = 42.708", "img": null}, {"id": "19-456", "deck": 19, "q": "(Refer to Figure 65.) Which of the figures is using scientific notation?", "options": ["1.", "2.", "both 1 and 2."], "correctIndex": 0, "explanation": "Equation 1 uses scientific notation, equation 2 does not. Scientific notation requires 10 to be raised to a power. Four raised to the 10th power does not qualify as scientific notation. See the Update PDF for the figure associated with this question.", "img": "429786_18.jpg"}, {"id": "19-457", "deck": 19, "q": "(Refer to Figure 70.) Which alternative answer is equal to 5.59?", "options": ["1.", "2.", "3."], "correctIndex": 0, "explanation": "See the Update PDF for the figure associated with this question. You must follow the Order of Operations rule:\n\n1.(v31) + (v43) ÷ 172\n(5.56) + (6.56/289)\n5.56 + .02 = 5.58\n\n2.(v31 + v43) ÷ 172\n(5.56 + 6.56) / 289\n12.12 / .04 = 12.16\n\n3.(v31) + (v43) - 172\n5.56 + 6.56 - 289 = -276.88", "img": "429786_19.jpg"}, {"id": "19-458", "deck": 19, "q": "The total piston displacement of a specific engine is", "options": ["dependent on the compression ratio.", "the volume displaced by all the pistons during one revolution of the crankshaft.", "the total volume of all the cylinders."], "correctIndex": 1, "explanation": "The piston displacement of an engine is the total volume swept by the pistons in one revolution of the crankshaft. The piston displacement is found by multiplying the area of the piston head by the length of the stroke (this gives the displacement of one cylinder). Multiply the displacement of one cylinder by the number of cylinders in the engine.", "img": null}, {"id": "19-459", "deck": 19, "q": "What is the surface area of a cube where a side (edge) measures 7.25 inches?", "options": ["381.078 cu. in.", "315.375 sq. in.", "52.5625 sq. in."], "correctIndex": 1, "explanation": "Each surface of the cube is 7.252 = 52.5625 square inches\nA cube has six surfaces so the total surface area is:\n52.5625 x 6 = 315.375 square inches.", "img": null}, {"id": "19-460", "deck": 19, "q": "(Refer to Figure 54.) Compute the area of the trapezoid.", "options": ["52.5 square feet.", "60 square feet.", "76.5 square feet."], "correctIndex": 0, "explanation": "The area of a trapezoid is found by multiplying its altitude (5 feet in this problem) by the average length of the two bases (the average of 9 feet and 12 feet is 10.5 feet). The area of this trapezoid is 5 x 10.5 = 52.5 square feet.", "img": "429786_20.jpg"}, {"id": "19-461", "deck": 19, "q": "(Refer to Figure 71.) What is the volume of a sphere with a radius of 4.5 inches?", "options": ["47.71 cubic inches.", "381.7 square inches.", "381.7 cubic inches."], "correctIndex": 2, "explanation": "V = (1/6) x pD^3\nV = (1/6) x p x 9^3\nV = (1/6) x p x 729\nV = 381.7", "img": "429786_21.jpg"}, {"id": "19-462", "deck": 19, "q": "What size sheet of metal is required to fabricate a cylinder 20 inches long and 8 inches in diameter?\n(Note: C = pi x D)", "options": ["20 inches x 25-5/32 inches.", "20 inches x 24-9/64 inches.", "20 inches x 25-9/64 inches."], "correctIndex": 2, "explanation": "The sheet metal needed to fabricate a cylinder 20 inches long and 8 inches in diameter is 20 inches long and 25-9/64 inches wide.\n8 x pi (3.1416) = 25.1328\n25.1328 is slightly less than 9/64", "img": null}, {"id": "19-463", "deck": 19, "q": "(Refer to Figure 55.) Find the area of the triangle shown.", "options": ["12 square inches.", "6 square inches.", "15 square inches."], "correctIndex": 1, "explanation": "The area of a triangle is one half of the product of its base times its altitude. The base of this triangle is 4 inches and the altitude is 3 inches. The area is (4 x 3) ÷ 2 = 6 square inches.", "img": "429786_22.jpg"}, {"id": "19-464", "deck": 19, "q": "What force is exerted on the piston in a hydraulic cylinder if the area of the piston is 1.2 square inches and the fluid pressure is 850 PSI?", "options": ["1,020 pounds.", "960 pounds.", "850 pounds."], "correctIndex": 0, "explanation": "The force exerted on a piston by hydraulic fluid is found by multiplying the area of the piston by the amount of pressure acting on each square inch of the piston. In this problem the area is 1.2 square inches and a pressure of 850 pounds acts on each square inch. The force is 1,020 pounds.", "img": null}, {"id": "19-465", "deck": 19, "q": "A rectangular-shaped fuel tank measures 60 inches in length, 30 inches in width, and 12 inches in depth. How many cubic feet are within the tank?", "options": ["12.5.", "15.0.", "21.0."], "correctIndex": 0, "explanation": "The volume of a rectangular solid figure (such as this fuel tank) is found by multiplying its length, width, and depth together.\nV = L x W x D\n= (60 ÷ 12) x (30 ÷ 12) x (12 ÷ 12)\n= 5 x 2.5 x 1\n= 12.5 cubic feet\nThe volume is 12.5 cubic feet.", "img": null}, {"id": "19-466", "deck": 19, "q": "Select the container size that will be equal in volume to 60 gallons of fuel. (7.5 gal = 1 cu ft)", "options": ["7.5 cubic feet.", "8.0 cubic feet.", "8.5 cubic feet."], "correctIndex": 1, "explanation": "Since a one-cubic-foot container will hold 7.5 gallons, an 8-cubic-foot container will hold 60 gallons. 60 ÷ 7.5 = 8", "img": null}, {"id": "19-467", "deck": 19, "q": "(Refer to Figure 56.) Compute the area of the trapezoid.", "options": ["24 square feet.", "48 square feet.", "10 square feet."], "correctIndex": 2, "explanation": "The area of a trapezoid is found by multiplying its altitude (2 feet in this problem) by the average length of the two bases (the average of 4 feet and 6 feet is 5 feet). The area of this trapezoid is 10 square feet.", "img": "429786_8.jpg"}, {"id": "19-468", "deck": 19, "q": "(Refer to Figure 57.) Determine the area of the triangle formed by points A, B, and C. A to B = 7.5 inches\nA to D = 16.8 inches", "options": ["42 square inches.", "63 square inches.", "126 square inches."], "correctIndex": 1, "explanation": "The area of a triangle is equal to one-half the product of its base and its altitude. In this problem, the base is the distance A to D, which is 16.8 inches (this is the same as the distance B to C). The altitude is the distance A to B, which is 7.5 inches.\nArea = (16.8 x 7.5) ÷ 2\n= 126 ÷ 2\n= 63 square inches", "img": "429786_9.jpg"}, {"id": "19-469", "deck": 19, "q": "What is the piston displacement of a master cylinder with a 1.5-inch diameter bore and a piston stroke of 4 inches?", "options": ["9.4247 cubic inches.", "7.0686 cubic inches.", "6.1541 cubic inches."], "correctIndex": 1, "explanation": "The piston displacement of a master cylinder is found by multiplying the area of the piston head by its stroke. The area of the piston is found by squaring its diameter (1.5 inch in this problem) and multiplying this by the constant 0.7854 (one-fourth of pi). When the area of 1.767 square inches is multiplied by the stroke of 4.0 inches, we find that the displacement of the master cylinder to be 7.0686 cubic inches.\nPD = 0.7854 x B^2 x S\n= 0.7854 x 1.5^2 x 4\n= 7.0686 cubic inches", "img": null}, {"id": "19-470", "deck": 19, "q": "How many gallons of fuel will be contained in a rectangular-shaped tank which measures 2 feet in width, 3 feet in length, and 1 foot 8 inches in depth? (7.5 gal = 1 cu ft)", "options": ["66.6.", "75", "45"], "correctIndex": 1, "explanation": "The volume of a rectangular solid figure (such as this fuel tank) is found by multiplying its length, width, and depth together.\nV = L x W x D\n= 3 x 2 x (20 ÷ 12)\n= 10 cubic feet\nSince 1 cubic foot of tank space will hold 7.5 gallons, and there are 10 cubic feet of space in the tank, the tank will hold 10 times 7.5 gallons or 75 gallons of fuel.", "img": null}, {"id": "19-471", "deck": 19, "q": "A rectangular shaped fuel tank measures 27-1/2 inches in length, 3/4 foot in width, and 8-1/4 inches in depth. How many gallons will the tank contain?\n(231 cu in = 1 gal)", "options": ["7.366.", "8.83", "170.156."], "correctIndex": 1, "explanation": "The volume of a rectangular solid figure (such as this fuel tank) is found by multiplying its length, width, and depth together. All dimensions must be in the same units. 3/4 foot = 9 inches.\nV = L x W x D\n= 27.5 x 9 x 8.25\n= 2,041.875 cubic inches\nSince there are 231 cubic inches in each gallon, we must divide the total volume of 2,041.875 by 231 to find the capacity of the tank in gallons.\nCapacity = 2041.875 ÷ 231\n= 8.83 gallons\nThis tank will hold 8.83 gallons of fuel.", "img": null}, {"id": "19-472", "deck": 19, "q": "A four-cylinder aircraft engine has a cylinder bore of 3.78 inches and is 8.5 inches deep. With the piston on bottom center, the top of the piston measures 4.0 inches from the bottom of the cylinder. What is the approximate piston displacement of this engine?", "options": ["200 cubic inches.", "360 cubic inches.", "235 cubic inches."], "correctIndex": 0, "explanation": "The piston displacement of one cylinder of a reciprocating engine is found by multiplying the area of the piston head by the length of the stroke. The area of the piston is found by squaring the bore (3.78 inches in this problem) and multiplying this by the constant 0.7854 (one-fourth of pi). When the area of 11.22 square inches is multiplied by the stroke of 4.5 inches (the depth of the cylinder minus the distance from the top of the piston at BDC to the bottom of the cylinder), we find that the displacement of one cylinder is 50.49 cubic inches.|This is a four-cylinder engine, so the total displacement is four times that of a single cylinder. The total displacement is 201.96 cubic inches.\nArea = (pi ÷ 4) x B^2\n= 0.7854 x 3.78^2\n= 11.22 square inches\nStroke = 8.5 - 4 = 4.5 inches\nPD = Area x Stroke x No. cylinders\n= 11.22 x 4.5 x 4\n= 201.96 cubic inches", "img": null}, {"id": "19-473", "deck": 19, "q": "A rectangular-shaped fuel tank measures 37-1/2 inches in length, 14 inches in width, and 8-1/4 inches in depth. How many cubic inches are within the tank?", "options": ["59.75", "433.125.", "4,331.25."], "correctIndex": 2, "explanation": "The volume of a rectangular solid figure (such as this fuel tank) is found by multiplying its length, width, and depth together.\nV = L x W x D\n= 37.5 x 14 x 8.25\n= 4,331.25 cubic inches", "img": null}, {"id": "19-474", "deck": 19, "q": "A six-cylinder engine with a bore of 3.5 inches, a cylinder height of 7 inches and a stroke of 4.5 inches will have a total piston displacement of", "options": ["256.88 cubic inches.", "259.77 cubic inches.", "43.3 cubic inches."], "correctIndex": 1, "explanation": "The piston displacement of one cylinder of a reciprocating engine is found by multiplying the area of the piston head by the length of the stroke. The area of the piston is found by squaring the bore (3.5 inches in this problem) and multiplying this by the constant 0.7854 (one fourth of pi). When the area of 9.621 square inches is multiplied by the stroke of 4.5 inches, we find that the displacement of one cylinder is 43.295 cubic inches.\nThis is a six-cylinder engine, so the total displacement is six times that of a single cylinder. The total displacement is 259.77 cubic inches.\nArea = (pi ÷ 4) x B^2\n= 0.7854 x 3.5^2\n= 9.621 square inches\nStroke = 4.5 inches\nPD = Area x Stroke x No. cylinders\n= 9.621 x 4.5 x 6\n= 259.77 cubic inches", "img": null}, {"id": "19-475", "deck": 19, "q": "Select the fraction which is equal to 0.0250.", "options": ["1/4.", "1/40.", "1/400."], "correctIndex": 1, "explanation": "1/4 is euqal to 0.25. 1/40 is equal to 0.025. 1/400 is equal to 0.0025.", "img": null}, {"id": "19-476", "deck": 19, "q": "1.21875 is equal to", "options": ["83/64.", "19/16.", "39/32."], "correctIndex": 2, "explanation": "Divide the decimal fractional part of this mixed number by the decimal equivalent of 1/64.\n.21875 ÷ 0.015625 = 14\nThe common fraction equivalent to 1.21875 is 1-14/64. This is the same as 78/64 or 39/32.", "img": null}, {"id": "19-477", "deck": 19, "q": "If the volume of a cylinder with the piston at bottom center is 84 cubic inches and the piston displacement is 70 cubic inches, then the compression ratio is", "options": ["7:1.", "1.2:1.", "6:1."], "correctIndex": 2, "explanation": "The volume of a cylinder with the piston at the top of its stroke is found by subtracting the piston displacement of the cylinder from the volume of the cylinder with the piston at the bottom of its stroke. Volume at top = Volume at bottom - displacement = 84 - 70 = 14 cubic inches\nThe compression ratio of the cylinder is the ratio of the volume of the cylinder with the piston at the bottom of its stroke to the volume of the cylinder with the piston at the top of its stroke.\nC.R. = Volume at bottom ÷ volume at top = 84 ÷ 14 = 6\nThis engine has a compression ratio of 6:1.", "img": null}, {"id": "19-478", "deck": 19, "q": "Express 7/8 as a percent.", "options": ["8.75 percent.", ".875 percent.", "87.5 percent."], "correctIndex": 2, "explanation": "A percentage is a decimal fraction with 100 as its denominator. To convert 7/8 into a percentage, divide seven by eight and multiply this by 100.\n7 ÷ 8 = 0.875\n0.875 x 100 = 87.5 percent", "img": null}, {"id": "19-479", "deck": 19, "q": "What is the speed of a spur gear with 42 teeth driven by a pinion gear with 14 teeth turning 420 RPM?", "options": ["588 RPM.", "160 RPM.", "140 RPM."], "correctIndex": 2, "explanation": "The speed ratio is the reciprocal of gear ratio. The spur gear with 42 teeth is driven by a pinion gear with 14 teeth. This is a gear ratio of 3:1. The spur gear will turn at 1/3 the speed of the pinion gear. If the pinion gear turns at a speed of 420 RPM, the spur gear will turn at a speed of 420 ÷ 3 = 140 RPM.", "img": null}, {"id": "19-480", "deck": 19, "q": "An engine develops 108 horsepower at 87 percent power. What horsepower would be developed at 65 percent power?", "options": ["81.", "70.", "61."], "correctIndex": 0, "explanation": "If an engine develops 108 horsepower at 87 percent power, its 100 percent power is 108 ÷ 0.87 = 124.13 horsepower. Its horsepower at 65 percent power is found by multiplying 124.13 by 0.65, or 80.68 horsepower.", "img": null}, {"id": "19-481", "deck": 19, "q": "A certain aircraft bolt has an overall length of 1-1/2 inches, with a shank length of 1-3/16 inches, and a threaded portion length of 5/8 inch. What is the grip length?", "options": [".5625 inch.", ".8750 inch.", ".3125 inch."], "correctIndex": 0, "explanation": "The grip length of a bolt is the length of the unthreaded portion of the shank. If the shank is 1-3/16 (1.1875) inches long, and the threaded portion is 5/8 (0.625) inch, the grip length is 1.1875 - 0.625 = 0.5625 inch.", "img": null}, {"id": "19-482", "deck": 19, "q": "Select the fractional equivalent for a 0.0625 inch thick sheet of aluminum.", "options": ["1/16.", "3/64.", "1/32."], "correctIndex": 0, "explanation": "In order to change this decimal fraction into a common fraction, divide the number by the decimal equivalent of 1/64 (0.015625).\n0.0625 ÷ 0.015625 = 4/64\nThis is the same as 1/16 inch.", "img": null}, {"id": "19-483", "deck": 19, "q": "Express 5/8 as a percent.", "options": [".625 percent.", "6.25 percent.", "62.5 percent."], "correctIndex": 2, "explanation": "A percentage is a decimal fraction with 100 as its denominator. To convert 5/8 into a percentage, divide five by eight and multiply this by 100.\n5 ÷ 8 = 0.625\n0.625 x 100 = 62.5 percent", "img": null}, {"id": "19-484", "deck": 19, "q": "Select the decimal which is most nearly equal to 77/64.", "options": ["0.08311.", "0.8311.", "1.2031."], "correctIndex": 2, "explanation": "To convert a common fraction into a decimal fraction, divide the numerator by the denominator.\n77 ÷ 64 = 1.203125", "img": null}, {"id": "19-485", "deck": 19, "q": "An airplane flying a distance of 750 miles used 60 gallons of gasoline. How many gallons will it need to travel 2,500 miles?", "options": ["31,250.", "9,375.", "200"], "correctIndex": 2, "explanation": "If the airplane uses 60 gallons of gasoline while flying 750 miles, it is getting 750 ÷ 60 or 12.5 miles per gallon of fuel burned.\nAt this rate of fuel consumption, it will require 2,500 ÷ 12.5 = 200 gallons of fuel to fly 2,500 miles", "img": null}, {"id": "19-486", "deck": 19, "q": "What is the speed ratio of an input gear with 36 teeth meshed to a gear with 20 teeth?", "options": ["9:5.", "1:0.56.", "1:1.8."], "correctIndex": 2, "explanation": "The speed ratio is the reciprocal of the gear ratio. The large gear has 36 teeth and the small gear has 20 teeth. This is a gear ratio of 1.8:1, or a speed ratio of 1:1.8.", "img": null}, {"id": "19-487", "deck": 19, "q": "A pinion gear with 14 teeth is driving a spur gear with 42 teeth at 140 RPM. Determine the speed of the pinion gear.", "options": ["588 RPM.", "420 RPM.", "126 RPM."], "correctIndex": 1, "explanation": "The speed ratio is the reciprocal of the gear ratio. The spur gear with 42 teeth is driven by a pinion gear of 14 teeth. This is a gear ratio of 3:1. The spur gear will turn at 1/3 the speed of the pinion gear. If the spur gear turns at a speed of 140 RPM, the pinion gear will have to turn at a speed of 420 RPM.", "img": null}, {"id": "19-488", "deck": 19, "q": "The parts department's profit is 12 percent on a new part. How much does the part cost if the selling price is $145.60?", "options": ["$128.13.", "$125.60.", "$130.00"], "correctIndex": 2, "explanation": "In this problem, the cost of the magneto is equal to 100 percent. Since a 12 percent profit is specified, the selling price must be 112 percent. If the selling price (112%) is equal to $145.60, the cost (100%) can be found by dividing the selling price by 112% (by 1.12).\n$145.60 ÷ 1.12 = $130.00", "img": null}, {"id": "19-489", "deck": 19, "q": "If an engine is turning 1,965 rpm at 65 percent power, what is its maximum rpm?", "options": ["2,653.", "3,023.", "3,242."], "correctIndex": 1, "explanation": "1,965 rpm is 65% of 3,023 rpm.\n1,965 ÷ 0.65 = 3,023", "img": null}, {"id": "19-490", "deck": 19, "q": "An engine of 98 horsepower maximum is running at 75 percent power. What is the horsepower being developed?", "options": ["87.00.", "33.30.", "73.50."], "correctIndex": 2, "explanation": "Seventy-five percent of 98 horsepower is equal to 98 x 0.75 = 73.50 horsepower.", "img": null}, {"id": "19-491", "deck": 19, "q": "A blueprint shows a hole of 0.17187 to be drilled. Which fraction size drill bit is most nearly equal?", "options": ["11/64.", "9/32.", "11/32."], "correctIndex": 0, "explanation": "The hole specified on the blueprint has a diameter of 0.17187 inch. It could be drilled with a 11/64 drill.\n11/64 is equal to 0.171875.\n9/32 is equal to 0.28125.\n11/32 is equal to 0.34375.", "img": null}, {"id": "19-492", "deck": 19, "q": "Which decimal is most nearly equal to a bend radius of 31/64?", "options": ["0.2065.", "0.4844.", "0.3164."], "correctIndex": 1, "explanation": "To convert the common fraction 31/64 into a decimal fraction, divide the numerator, 31, by the denominator, 64.\n31 ÷ 64 = 0.484375", "img": null}, {"id": "19-493", "deck": 19, "q": "Sixty-five engines are what percent of 80 engines?", "options": ["81 percent.", "65 percent.", "52 percent."], "correctIndex": 0, "explanation": "To find the percentage of engines represented by 65 out of 80, we find the ratio of 65 to 80 by dividing 65 by 80.\n65 ÷ 80 = 0.8125\nThen we change this decimal fraction into a percentage by multiplying it by 100. Sixty-five engines is 81.25 percent of 80 engines.", "img": null}, {"id": "19-494", "deck": 19, "q": "The radius of a piece of round stock is 7/32. Select the decimal which is most nearly equal to the diameter.", "options": ["0.2187.", "0.4375.", "0.3531."], "correctIndex": 1, "explanation": "The diameter of the stock is two times the radius. We need to find the decimal equivalent of 2 x 7/32, or 7/16 inch. By dividing the numerator by the denominator, we find that we will need a piece of round stock with a diameter of 0.4375 inch.", "img": null}, {"id": "19-495", "deck": 19, "q": "Maximum life for a certain part is 1100 hours. Recently, 15 of these parts were removed from different aircraft with an average life of 835.3 hours. What percent of the maximum part life has been achieved?", "options": ["75.9 percent.", "76.9 percent.", "75.0 percent."], "correctIndex": 0, "explanation": "In this problem, 1100 hours represents 100 percent of the life of the part. The percentage represented by 835.3 hours can be found by dividing 835.3 by 1100 and multiplying this answer by 100. 835.3/1100 = 0.759 x 100 = 75.9 percent.", "img": null}, {"id": "19-496", "deck": 19, "q": "What is the ratio of 10 feet to 30 inches?", "options": ["4:1", "1:3", "3:1"], "correctIndex": 0, "explanation": "Ten feet is equal to 120 inches. The ratio of 120 ÷ 30 is 4:1.", "img": null}, {"id": "19-497", "deck": 19, "q": "How much current does a 30-volt, 1/2 horsepower motor that is 85 percent efficient draw from the bus?\n(Note: 1 horsepower = 746 watts)", "options": ["14.6 amperes.", "12.4 amperes.", "14.3 amperes."], "correctIndex": 0, "explanation": "There are 746 watts in one horsepower. The motor produces one-half horsepower (373 watts) at 100 percent efficiency, but it is only 85 percent efficient. 373 ÷ 0.85 = 438.8 watts of power used by the motor. Current drawn by the motor is found by dividing the power by the voltage:\nI = P ÷ E\nI = 438.8 ÷ 30\nI = 14.62 amps", "img": null}, {"id": "19-498", "deck": 19, "q": "Solve the equation.\n[(4 x -3)+(-9 x 2)] ÷ 2 =", "options": ["-30", "-15", "-5"], "correctIndex": 1, "explanation": "In a problem of this type, work from the inside outward:\n1. First solve the parts of the problem inside the parentheses.\n4 x -3 = -12|-9 x 2 = -18\n2. Now combine the two values just found.\n-12 + -18 = -30\n3. Divide this answer by 2.\n-30 ÷ 2 = -15", "img": null}, {"id": "19-499", "deck": 19, "q": "Solve the equation.\n(64 x 3/8) ÷ 3/4 =", "options": ["18", "24", "32"], "correctIndex": 2, "explanation": "First work the part of the problem inside the parenthesis, and then do the division.\n64 x 3/8 = 24\n24 ÷ 3/4 = 32", "img": null}, {"id": "19-500", "deck": 19, "q": "Solve the equation.\n(32 x 3/8) ÷ 1/6 =", "options": ["12", "2", "72"], "correctIndex": 2, "explanation": "1. First, work the part of the problem inside the parenthesis:\n(32 x 3/8) = 12\n2. Now divide 12 by 1/6. To divide by a fraction, invert the divisor (1/6) and multiply.\n12 ÷ 1/6 = 12 x 6 = 72.", "img": null}, {"id": "19-501", "deck": 19, "q": "What is the ratio of a gasoline fuel load of 200 gallons to one of 1,680 pounds?", "options": ["5:7", "2:3", "5:42"], "correctIndex": 0, "explanation": "Gasoline has a nominal weight of 6 pounds per gallon. So, 200 gallons of gasoline will weigh 1,200 pounds. The ratio of a load of 1,200-pound load to one of 1,680 pounds is the ratio of:\n1,200 ÷ 1,680 = 0.7142.\nThe ratio 5:7 is 0.7142.\nThe ratio of 2:3 is 0.6667.\nThe ratio of 5:42 is 0.1190.", "img": null}, {"id": "19-502", "deck": 19, "q": "Solve the equation.\n1/2 (-30 + 34) 5", "options": ["10.", "95.", "160."], "correctIndex": 0, "explanation": "First, solve the part of the problem inside the parenthesis, then multiply by 1/2 (divide by 2) and finally multiply by five.\n(-30 + 34) = 4\n4 ÷ 2 = 2\n2 x 5 = 10", "img": null}, {"id": "19-503", "deck": 19, "q": "(Refer to Figure 58.) Solve the equation.", "options": ["174.85.", "68.037.", "14.002."], "correctIndex": 2, "explanation": "1. First, solve the parts of the problem inside parentheses:\n(-35 + 25) = (-10)\n2. Combine the factors (the parts) of the first term (the part of the problem to the left of the plus sign).\n(-10) x (-7) = 70\n3. Clear the parenthesis on the right of the plus sign by raising 16 to its ^-2 power.\n16^-2 = 1/16^2 = 1/256 = 0.003906\n4. Multiply the two factors of the second term.\n(3.1416) x (0.003906) = 0.01227\n5. Add the two terms above the line.\n70 + 0.0122 = 70.0122\n6. Divide this by the square root of 25, which is 5.\n70.0122 ÷ 5 = 14.002", "img": "429786_10.jpg"}, {"id": "19-504", "deck": 19, "q": "(Refer to Figure 59.) Solve the equation.", "options": ["+31.25.", "-5.20.", "-31.25."], "correctIndex": 1, "explanation": "This problem can be rewritten as 125 ÷ -4, divided by -36 ÷ -6.\n125 ÷ -4 = -31.25\n-36 ÷ -6 = 6\n-31.25 ÷ 6 = -5.208", "img": "429786_11.jpg"}, {"id": "19-505", "deck": 19, "q": "Solve the equation.\n4 - 3[-6(2 + 3) + 4] =", "options": ["82", "-25", "-71"], "correctIndex": 0, "explanation": "1. Begin this problem by working the inside parentheses, and then work outward.\n(2 + 3) = 5\n(-6 x 5) = -30\n(-30 + 4) = -26\n2. Next, the multiplication is done.\n3 x -26 = -78\n3. Now, perform the subtraction.\n4 - (-78) = 82", "img": null}, {"id": "19-506", "deck": 19, "q": "Solve the equation.\n-6[-9(-8 + 4) - 2(7 + 3)] =", "options": ["-332", "216", "-96"], "correctIndex": 2, "explanation": "1. Begin the problem by working the inside parentheses in the first term.\n(-8 + 4) = -4\n2. Combine the factors in the first term.\n-9 x -4 = 36\n3. Clear the parenthesis in the second term.\n(7 + 3) = 10\n4. Multiply this value by 2.\n10 x 2 = 20\n5. Combine the two terms in the brackets.\n36 - 20 = 16\n6. Multiply this by -6.\n-6 x 16 = -96", "img": null}, {"id": "19-507", "deck": 19, "q": "Solve the equation.\n(-3 + 2)(-12 - 4) + (-4 + 6) x 3", "options": ["20", "22", "28"], "correctIndex": 1, "explanation": "1. Begin this problem by clearing the parentheses.\n(-3 + 2) = -1\n(-12 - 4) = -16\n(-4 +6) = 2\n2. Then perform the multiplication.\n-1 x -16 = 16\n2 x 3 = 6\n3. And finally the addition.\n16 + 6 = 22", "img": null}, {"id": "19-508", "deck": 19, "q": "(Refer to Figure 60.) Solve the equation.", "options": ["11.9.", "11.7.", "11.09."], "correctIndex": 0, "explanation": "1. Begin this problem by clearing the parentheses.\n(-5 + 23) = 18\n(3^-3) = 0.037\nThe square root of 64 = 8\n2. Perform the multiplication in the numerator.\n18 x -2 = -36\n0.037 x 8 = 0.296\n3. Perform the addition in the numerator.\n-36 + 0.296 = -35.704\n4. Perform the division in the denominator.\n-27 ÷ 9 = -3\n5. Divide the numerator by the denominator.\n-35.704 ÷ -3 = 11.90", "img": "429786_12.jpg"}, {"id": "19-509", "deck": 19, "q": "What is defined as a group of bits representing a complete piece of information?", "options": ["Byte.", "Bit.", "Word."], "correctIndex": 0, "explanation": "A byte is composed of a group of 8 bits and represents a complete piece of information in a binary system.", "img": null}, {"id": "19-510", "deck": 19, "q": "Convert the binary number 1111 to decimal form.", "options": ["14.", "15.", "16."], "correctIndex": 1, "explanation": "The binary number 1111 is converted bit by bit into decimal: 1000 = 8; 0100 = 4; 0010 = 2; and 0001 = 1; thus the entire binary number equals 8 + 4 + 2 + 1 = 15 in its decimal form.", "img": null}, {"id": "19-511", "deck": 19, "q": "(Refer to the Figure 66.) Solve the equation.", "options": ["35,998.", "36,002.", "62,208."], "correctIndex": 1, "explanation": "The problem in the figure is: -4 + 6 + 10^3(square root 1296), which simplifies to: 2 + 1,000(36), which equals 36,002.", "img": "429786_13.jpg"}, {"id": "19-512", "deck": 19, "q": "Convert 7 to binary form.", "options": ["0111.", "0011.", "1110."], "correctIndex": 0, "explanation": "The binary number system has only two digits: 0 and 1. To convert a decimal number to a binary number, the place values in the binary system are used to create a sum of numbers that equal the value of the decimal number being converted. Start with the largest binary place value and subtract from the decimal number. Continue this process until all of the binary digits are determined. 7 = 0111 in binary.", "img": null}, {"id": "19-513", "deck": 19, "q": "Examples of units used in the conventional (U.S. or English) measurement include", "options": ["inch, meter, and rod.", "inch, kilometer, and fraction.", "inch, feet, and yard."], "correctIndex": 2, "explanation": "Some of the conventional U.S. or English units of measure are: inches, feet, yards, miles, ounces, pints, gallons, and pounds.", "img": null}, {"id": "19-514", "deck": 19, "q": "(Refer to Figure 67). Solve the equation.", "options": ["5.58.", "12.16.", "0.042."], "correctIndex": 2, "explanation": "Follow the order of operations rule:\nSquare Root 31 + Square Root 43 = 5.56 + 6.56 = 12.12\n12.12 / 17^2 = 12.12 / 289 = 0.042", "img": "429786_14.jpg"}, {"id": "19-515", "deck": 19, "q": "(Refer to Figure 68.) Which results in the largest number?", "options": ["1.", "2.", "3."], "correctIndex": 1, "explanation": "1.  4.631^5 = 2129.97205201\n2.  4.631 x 10^5 = 4.631 x 1000 = 463,100\n3.  4.631 x 10^-5 = 4.631 x 0.00001 = .00004631", "img": "429786_15.jpg"}, {"id": "20-516", "deck": 20, "q": "A certificated mechanic without an inspection authorization who signs the appropriate block on FAA Form 337 is doing what?", "options": ["Certifying that the work was done in accordance with the requirements of 14 CFR part 43.", "Approving the work for return to service.", "Certifying the maintenance information used as FAA-approved data."], "correctIndex": 0, "explanation": "When a certificated mechanic without an inspection authorization signs the conformity statement in item 6 of the FAA Form 337, he or she is certifying that the repair and/or alteration made to the unit(s) identified in item 4 and described on the reverse or attachments hereto have been made in accordance with the requirements of 14 CFR Part 43 and that the information furnished herein is true and correct to the best of his or her knowledge.", "img": null}, {"id": "20-517", "deck": 20, "q": "A person installing a product, part, or appliance on a type certificated product must make certain that the item's records document what type of statement?", "options": ["The product, part, or material meets FAA airworthiness standards.", "A product produced by an owner or operator does not need a statement.", "The product or material was not produced under an FAA production approval."], "correctIndex": 0, "explanation": "Any product, part, or material installed on a type certificate product must meet FAA airworthiness standards.", "img": null}, {"id": "20-518", "deck": 20, "q": "What is the means by which the FAA notifies aircraft owners and other interested persons of unsafe conditions and prescribes the condition under which the product may continue to be operated?", "options": ["Airworthiness Directives.", "Aviation Maintenance Alerts.", "Aviation Safety Data."], "correctIndex": 0, "explanation": "If a condition is found that causes a particular design of aircraft to fail to meet its certification for airworthiness, the FAA can issue an Airworthiness Directive (AD). An Airworthiness Directive describes the conditions that must be met to allow the aircraft to continue to be operated.", "img": null}, {"id": "20-519", "deck": 20, "q": "For aircraft operated under part 91, which of the following records must be retained for at least one year, or until the work is repeated or superseded?", "options": ["Records of time since overhaul of items requiring overhaul on a time specified basis.", "Records of maintenance, alterations, preventive maintenance, 100-hour, annual, and progressive inspections.", "Records of the current inspection status of the aircraft, including time since last required inspection."], "correctIndex": 1, "explanation": "14 CFR 91.417(b)(1) states that records of the maintenance, preventive maintenance, and alteration and records of the 100-hour, annual, progressive, and other required or approved inspections, as appropriate for each aircraft (including the airframe) and each engine, propeller, rotor, and appliance of an aircraft must include the total time in service of the airframe, each engine, each propeller, and each rotor, and shall be retained until the work is repeated or superseded by other work or for 1 year after the work is performed.", "img": null}, {"id": "20-520", "deck": 20, "q": "Each person performing an annual or 100-hour inspection shall use a checklist that contains at least those items in the appendix of:", "options": ["14 CFR Part 43.", "14 CFR Part 65.", "AC 43.13-3."], "correctIndex": 0, "explanation": "All 100-hour and annual inspections must be conducted with the use of a checklist. 14 CFR Part 43, Appendix D, lists the basic areas that must be included on the inspection checklist.", "img": null}, {"id": "20-521", "deck": 20, "q": "Which of the following may a certificated airframe and powerplant mechanic perform on aircraft and approve for return to service?\n1. A 100-hour inspection.\n2. An annual inspection, under specified circumstances.\n3. A progressive inspection, under specified circumstances.", "options": ["1, 2.", "1, 3.", "1, 2, 3."], "correctIndex": 1, "explanation": "According to 14 CFR 65.85 and 65.87, a certificated mechanic with airframe and powerplant ratings may perform a 100-hour inspection on an airframe and powerplant and approve the aircraft for return for service. An Inspection Authorization is required to conduct an annual and a progressive inspection and approve the aircraft for return to service. The exception to this is found in 14 CFR 43.15(d)(2) which states, regarding a progressive inspection, \"If the aircraft is away from the station where inspections are normally conducted, an appropriately-rated mechanic, a certificated repair station, or the manufacturer of the aircraft may perform inspections in accordance with the procedures and using the forms of the person who would otherwise perform the inspection.", "img": null}, {"id": "20-522", "deck": 20, "q": "When a 100-hour inspection is completed, if separate maintenance records for the airframe, powerplant(s), and propeller(s) are maintained, where is the entry for the inspection recorded?", "options": ["In each record.", "In the airframe record only.", "In any one of the records."], "correctIndex": 0, "explanation": "Advisory Circular AC 43-9 10. d. states that if the owner maintains separate records for the airframe, powerplants, and propellers, the entry for the 100-hour inspection is entered in each, while the annual inspection is only required to be entered into the airframe record.", "img": null}, {"id": "20-523", "deck": 20, "q": "Which statement is true regarding the use of FAA Form 337?", "options": ["FAA Form 337 is authorized for use with both U.S. and foreign registered aircraft.", "FAA Form 337 is authorized for use with U.S. registered aircraft, and foreign registered aircraft when located in the United States.", "FAA Form 337 is not authorized for use with other than U.S. registered aircraft."], "correctIndex": 2, "explanation": "Advisory Circular AC 43.9-1E 6.d. states that FAA Form 337 is not authorized for use on other than U.S.-registered aircraft.", "img": null}, {"id": "20-524", "deck": 20, "q": "After making a certain repair to an aircraft engine that is to be returned to service, an FAA Form 337 is prepared. How many copies are required and what is the disposition of the completed forms?", "options": ["Two; one copy for the aircraft owner and one copy for the FAA.", "Two; one copy for the FAA and one copy for the permanent records of the repairing agency or individual.", "Three; one copy for the aircraft owner, one copy for the FAA, and one copy for the permanent records of the repairing agency or individual."], "correctIndex": 0, "explanation": "When a major repair or a major alteration has been made to any equipment that requires an FAA Form 337, the form must be prepared in duplicate. The original goes to the aircraft owner to be kept with the aircraft records. The copy is forwarded to the local FAA FSDO within 48 hours after the aircraft is approved for return to service.", "img": null}, {"id": "20-525", "deck": 20, "q": "When approving for return to service after maintenance or alteration, the approving person must enter in the maintenance record of the aircraft:", "options": ["The date the maintenance or alteration was begun, a description (or reference to acceptable data) of work performed, the name of the person performing the work (if someone else), signature, and certificate number.", "A description (or reference to acceptable data) of work performed, date of completion, the name of the person performing the work (if someone else), signature, and certificate number.", "A description (or reference to acceptable data) of work performed, date of completion, the name of the person performing the work (if someone else), signature, certificate number, and kind of certificate held."], "correctIndex": 2, "explanation": "A maintenance record entry that is made after maintenance or alteration must contain the following: 1. A description (or reference to data acceptable to the Administrator) of the work performed; 2. The date of completion of the work performed; 3. The name of the person performing the work if other than the person approving the work for return to service; and 4. The signature, certificate number, and kind of certificate held by the person approving the work for return to service.", "img": null}, {"id": "20-526", "deck": 20, "q": "Which aircraft record entry is the best description of the replacement of several damaged heli-coils in a casting?", "options": ["Eight 1/4 -- 20 inch standard heli-coils were replaced. The damaged inserts were extracted, the tapped holes gaged, then new inserts installed, and tangs removed.", "Eight 1/4 -- 20 inch standard heli-coils were installed in place of damaged ones.", "Eight 1/4 -- 20 inch standard heli-coil inserts were repaired by replacing the damaged inserts with a lock-type insert, after the tapped holes were checked for corrosion."], "correctIndex": 0, "explanation": "Heli-coils are patented, precision-formed screw-thread coils of 18-8 stainless steel wire having a diamond-shaped cross section. Heli-coil inserts are replaced by extracting the damaged insert with a special extracting tool, gaging the holes with a Heli-coil thread gage, installing the new insert using the proper inserting tool and finally, breaking off the tang with the proper break-off tool.", "img": null}, {"id": "20-527", "deck": 20, "q": "Which maintenance record entry best describes the action taken for a .125-inch deep dent in a straight section of 1/2-inch aluminum alloy tubing?", "options": ["Dented section removed and replaced with identical new tubing flared to 45°.", "Dent within acceptable limits, repair not necessary.", "Dented section removed and replaced with identical new tubing flared to 37°."], "correctIndex": 2, "explanation": "The dent is in a straight portion of the tube and is deep enough to warrant its removal. A dent of up to 0.1 inch (20 percent of the tube diameter) deep would be acceptable and would not have to be removed. The dented section would have to be removed and replaced with identical new tubing flared to 37°.", "img": null}, {"id": "20-528", "deck": 20, "q": "Which maintenance record entry best describes the action taken for a control cable showing approximately 20 percent wear on several of the individual outer wires at a fairlead?", "options": ["Wear within acceptable limits, repair not necessary.", "Removed and replaced the control cable and rerigged the system.", "Cable repositioned, worn area moved away from fairlead."], "correctIndex": 0, "explanation": "Flexible and extra-flexible control cable should be replaced when the individual wires in each strand appear to blend together (outer wires worn 40 to 50 percent). Since these wires are only worn 20 percent, the wear is within acceptable limits and repair is not necessary.", "img": null}, {"id": "20-529", "deck": 20, "q": "What is/are the appropriate action(s) concerning minor repairs performed on a certificated aircraft?\n1. FAA Form 337's must be completed.\n2. Entries must be made in the aircraft's maintenance record.\n3. The owner of the aircraft must submit a record of all minor repairs to the FAA at least annually.", "options": ["2.", "2 and 3.", "1 and 2."], "correctIndex": 0, "explanation": "When a minor repair is performed on a certificated aircraft, an entry must be made in the aircraft permanent records. A minor repair does not require the completion of an FAA Form 337.", "img": null}, {"id": "20-530", "deck": 20, "q": "After a mechanic holding an airframe and powerplant rating completes a 100-hour inspection, what action is required before the aircraft is returned to service?", "options": ["Make the proper entries in the aircraft's maintenance record.", "An operational check of all systems.", "A mechanic with an inspection authorization must approve the inspection."], "correctIndex": 0, "explanation": "After a mechanic holding the appropriate ratings completes a 100-hour inspection of an aircraft, the appropriate entries must be made in the aircraft maintenance records before the aircraft can be returned to service.", "img": null}, {"id": "20-531", "deck": 20, "q": "An aircraft was not approved for return to service after an annual inspection and the owner wanted to fly the aircraft to another maintenance base. Which statement is correct?", "options": ["The owner must obtain a special flight permit.", "The aircraft may be flown without restriction up to 10 hours to reach another maintenance base.", "The aircraft becomes a restricted category type until it is approved for return to service."], "correctIndex": 0, "explanation": "If an aircraft fails to pass an annual inspection but is considered by the technician conducting the inspection to be safe for flight, it may be issued a special flight authorization under the provision of 14 CFR 21.197(a)(1), to allow the aircraft to be flown to another maintenance base where the required maintenance can be performed.", "img": null}, {"id": "20-532", "deck": 20, "q": "Which statement is true regarding the requirements for maintenance record format?", "options": ["Any format that provides record continuity and includes the required information may be used.", "The format provided by the manufacturer of the aircraft must be retained.", "Any desired change from manufacturer provided format requires approval from the Federal Aviation Administration."], "correctIndex": 0, "explanation": "Advisory Circular AC 43-9 5.b. states that maintenance records may be kept in any format that provides record continuity; includes required contents; lends itself to the addition of new entries; provides for signature entry; and is intelligible.", "img": null}, {"id": "20-533", "deck": 20, "q": "Which maintenance action is an airframe major repair?", "options": ["Changes to the wing or to fixed or movable control surfaces which affect flutter and vibration characteristics.", "Rewinding the field coil of an electrical accessory.", "The repair of portions of skin sheets by making additional seams."], "correctIndex": 2, "explanation": "According to the list of major alterations, major repairs and preventive maintenance listed in 14 CFR Part 43, Appendix A, the repair of portions of skin sheets by making additional seams is considered to be an airframe major repair. Neither of the other alternatives listed here is an airframe major repair.", "img": null}, {"id": "20-534", "deck": 20, "q": "For aircraft operated under part 91, when is aircraft total time required to be recorded in aircraft maintenance records?", "options": ["After satisfactorily completing maintenance, preventive maintenance, rebuilding, and alteration (excluding inspections).", "After satisfactorily completing inspections.", "After satisfactorily completing airframe, component, or propeller maintenance."], "correctIndex": 1, "explanation": "14 CFR 43.11 states that the person approving for return to service an aircraft, airframe, aircraft engine, propeller, appliance, or component part after any inspection performed in accordance with Part 91... shall make an entry in the maintenance record of that equipment containing the following... (2) The date of the inspection and aircraft total time in service.", "img": null}, {"id": "20-535", "deck": 20, "q": "Who is responsible for upkeep of the required maintenance records for an aircraft?", "options": ["The maintaining repair station or authorized inspector.", "The maintaining certificated mechanic.", "The aircraft owner."], "correctIndex": 2, "explanation": "According to 14 CFR 91.417, the aircraft owner or operator is responsible for 'ensuring that maintenance personnel make appropriate entries in the aircraft and maintenance records indicating the aircraft has been approved for return to service.'", "img": null}, {"id": "20-536", "deck": 20, "q": "If work performed on an aircraft has been done satisfactorily, the signature of an authorized person on the maintenance records for maintenance or alterations performed constitutes:", "options": ["Approval of the aircraft for return to service.", "Approval for return to service only for the work performed.", "Verification that the maintenance or alterations were performed referencing approved maintenance data."], "correctIndex": 1, "explanation": "The signature constitutes the approval for return to service only for the work performed.", "img": null}, {"id": "20-537", "deck": 20, "q": "Where is the record of compliance with Airworthiness Directives or manufacturers' service bulletins normally indicated?", "options": ["FAA Form 337.", "Aircraft maintenance records.", "Flight manual."], "correctIndex": 1, "explanation": "The aircraft maintenance records (generally in the form of logbooks) are the correct place to record compliance with FAA Airworthiness Directives or manufacturer's service bulletins.", "img": null}, {"id": "20-538", "deck": 20, "q": "Which is an appliance major repair?", "options": ["Overhaul of a hydraulic pressure pump.", "Repairs to a propeller governor or its control.", "Troubleshooting and repairing broken circuits in landing light circuits."], "correctIndex": 0, "explanation": "Overhaul of pressure-type carburetors and pressure-type fuel, oil, and hydraulic pumps are examples of appliance major repairs.", "img": null}, {"id": "20-539", "deck": 20, "q": "Who is responsible for making the entry in the maintenance records after an annual, 100 hour, or progressive inspection?", "options": ["The owner or operator of the aircraft.", "The person approving or disapproving for return to service.", "The designee or inspector representing the FAA Administrator."], "correctIndex": 1, "explanation": "According to 14 CFR 43.11(a): 'The person approving or disapproving for return to service an aircraft, airframe, aircraft engine, propeller, or appliance after any annual, 100-hour, or progressive inspection required by Part 91 shall make an entry in the maintenance record of that equipment,...'", "img": null}, {"id": "20-540", "deck": 20, "q": "An aircraft owner was provided a list of discrepancies on an aircraft that was not approved for return to service after an annual inspection. Which of the following statements is/are true concerning who may correct the discrepancies?\n1. Only a mechanic with an inspection authorization.\n2. An appropriately rated mechanic.\n3. Any certificated repair station.", "options": ["2 & 3.", "2.", "1."], "correctIndex": 1, "explanation": "If an aircraft was not approved for return to service after an annual inspection, a list of discrepancies that prevented the aircraft from being airworthy is given to the aircraft owner or operator. These discrepancies may be corrected by an appropriately rated mechanic and the aircraft approved for return to service.", "img": null}, {"id": "20-541", "deck": 20, "q": "In order to reconstruct lost or destroyed aircraft maintenance records, what is it necessary to establish?", "options": ["Dates of all maintenance, preventive maintenance and alterations.", "Dates and/or times of all 100-hour, annual, or progressive inspections.", "Total time-in-service of the airframe."], "correctIndex": 2, "explanation": "Advisory Circular AC 43-9C 12. states that in order to reconstruct lost or destroyed maintenance records, it is necessary to establish the total time-in-service of the airframe.", "img": null}, {"id": "20-542", "deck": 20, "q": "What is the status of data used as a basis for approving major repairs or alterations for return to service?", "options": ["Data must be least FAA-acceptable when it is used for that purpose.", "Data must be FAA-approved prior to its use for that purpose.", "Data may be FAA-approved after its use for that purpose."], "correctIndex": 1, "explanation": "Advisory Circular AC 43.9-1E 5.h.(2) states that data used as a basis for approving major repairs or alterations for return to service must be FAA-approved prior to its use for that purpose.", "img": null}, {"id": "20-543", "deck": 20, "q": "Where should you find this entry?\n'Removed right wing from aircraft and removed skin from outer 6 feet. Repaired buckled spar 49 inches from tip in accordance with figure 8 in the manufacturer's structural repair manual No. 28-1.'", "options": ["Aircraft engine maintenance record.", "Aircraft minor repair and alteration record.", "FAA Form 337."], "correctIndex": 2, "explanation": "The description of the repair, as is shown here, would be made on FAA Form 337 (Major Repair and Alteration Form). This form must be completed when an airframe, engine, propeller, or appliance has been subjected to a major repair or major alteration.", "img": null}, {"id": "20-544", "deck": 20, "q": "For aircraft operated under part 91, what difference is there, if any, between the record entry requirements for maintenance (e.g., repair or alteration) and the record entry requirements for inspections (beyond the description of the work performed and the type and extent of inspection)?", "options": ["There is no difference.", "Aircraft total time is required to be included only in the maintenance entry.", "Aircraft total time is required to be included only in the inspection entry."], "correctIndex": 2, "explanation": "14 CFR 43.9(a)(2) states that each person who maintains, performs preventive maintenance, rebuilds or alters an aircraft, airframe, aircraft engine, propeller, appliance, or component part shall make an entry in the maintenance record of that equipment containing the following information... (2) The date of completion of the work performed.", "img": null}, {"id": "20-545", "deck": 20, "q": "An FAA Form 337 is used to record and document:", "options": ["Preventive and unscheduled maintenance and special inspections.", "Major and minor repairs, and major and minor alterations.", "Major repairs and major alterations."], "correctIndex": 2, "explanation": "FAA Form 337 is used to describe any major repairs or major alterations that have been made to an airframe, powerplant, propeller, or appliance.", "img": null}, {"id": "20-546", "deck": 20, "q": "During an annual inspection, if a defect is found which makes the aircraft unairworthy, the person disapproving must:", "options": ["Void the aircraft's Airworthiness Certificate.", "Submit a Malfunction or Defect Report.", "Provide a written notice of the defect to the owner."], "correctIndex": 2, "explanation": "If, during an annual inspection, a defect is found which makes the aircraft unairworthy, the person disapproving the aircraft must give the owner a signed and dated written list of the discrepancies that caused the unairworthy condition.", "img": null}, {"id": "20-547", "deck": 20, "q": "If more space is needed for a work description entered on FAA Form 337, what information should be included on the attached sheet(s), in addition to the rest of the work description?", "options": ["Make, model, and serial number of the aircraft.", "Aircraft nationality and registration mark, and the date the work was accomplished.", "Name, date, and office designator of the FAA inspector from the supervising district office."], "correctIndex": 1, "explanation": "Advisory Circular AC 43.9-1E 5.h.(3) states that if additional space is needed to describe the repair or alteration, attach sheets bearing he aircraft nationality and registration mark and the date the work was completed.", "img": null}, {"id": "20-548", "deck": 20, "q": "What is ATA iSpec 2200?", "options": ["Standardized electronic documentation for aircraft models.", "Fuel specifications for transport-category airplanes.", "Airline transport catalog for aircraft parts."], "correctIndex": 0, "explanation": "ATA iSpec 2200 is a compilation of what used to be ATA Spec 100 and ATA Spec 2100. This ATA iSpec 2200 standardizes the format in which maintenance information is presented in aircraft maintenance manuals, and makes it available in electronic format.", "img": null}, {"id": "20-549", "deck": 20, "q": "When a discrepancy list is provided to an aircraft owner or operator after an inspection, it says in effect that:", "options": ["The item inspected is unairworthy.", "Except for these discrepancies, the item inspected is airworthy.", "The item inspected may or may not be airworthy depending on the discrepancies found."], "correctIndex": 1, "explanation": "Advisory Circular AC43-9C 10. b. states that when a discrepancy list is provided to an owner or operator, it says, in effect, except for these discrepancies, the item inspected is airworthy.", "img": null}, {"id": "20-550", "deck": 20, "q": "When work is performed on an aircraft that necessitates the use of FAA Form 337, who should prepare the form?", "options": ["The person who performs or supervises the work.", "The person who approves for return to service.", "The aircraft owner or operator."], "correctIndex": 0, "explanation": "Advisory Circular AC 43.9-1E 5. states that the person who performs or supervises a major repair or major alteration should prepare the FAA Form 337.", "img": null}, {"id": "20-551", "deck": 20, "q": "For aircraft operated under part 91, which of the following records must be retained and transferred with the aircraft when it is sold?", "options": ["Records of maintenance, alterations, preventive maintenance, 100-hour, annual, and progressive inspections.", "Records of inspections performed in accordance with 14 CFR part 43, Appendix D.", "Records of the current status of applicable AD's, and date and time when recurring AD's are next due."], "correctIndex": 2, "explanation": "14CFR 91.417(a)(2)(v) and (b)(2) states that the among the records that must be retained and transferred with the aircraft when it is sold is the current status of the applicable airworthiness directives (AD's) including for each, the method of compliance and the AD number and revision date. If the AD involves recurring action, the time and date when the next action is required.", "img": null}, {"id": "20-552", "deck": 20, "q": "Which aircraft record entry best describes a repair of a dent in a tubular steel structure dented at a cluster?", "options": ["Removed and replaced the damaged member.", "Welded a reinforcing plate over the dented area.", "Filled the damaged area with a molten metal and dressed to the original contour."], "correctIndex": 1, "explanation": "If an aircraft welded-steel tubular structure is dented at a cluster, a patch plate of the same material and as thick as the thickest member of the cluster is cut and welded over the dented area.", "img": null}, {"id": "21-553", "deck": 21, "q": "If a double-acting actuating cylinder in a 3,000 psi system has a piston with a surface area of three square inches on the extension side, and a rod with a cross-section area of one square inch attached to the piston on the other side, approximately how much force will the actuator be able to produce when retracting?", "options": ["9,000 pounds.", "6,000 pounds.", "3,000 pounds."], "correctIndex": 1, "explanation": "The force a hydraulic actuator can exert is determined by the area of the piston and the pressure of the fluid acting on the piston.\nThe effective area on the retracting side of the piston is two square inches.\n2 sq. in. x 3,000 psi = 6,000 pounds of force", "img": null}, {"id": "21-554", "deck": 21, "q": "The boiling point of a given liquid varies", "options": ["directly with pressure.", "inversely with pressure.", "directly with density."], "correctIndex": 0, "explanation": "The boiling point of a liquid varies directly with the pressure above the liquid. The greater the pressure, the higher the boiling point.", "img": null}, {"id": "21-555", "deck": 21, "q": "Which of the following is NOT considered a method of heat transfer?", "options": ["Convection.", "Conduction.", "Diffusion."], "correctIndex": 2, "explanation": "Heat can be transferred from a body having a high level of heat energy to a body having a lower level of heat energy by three methods: conduction (actual physical contact), convection (transfer through vertical currents), and radiation (transfer by electromagnetic waves). Diffusion is not a method of heat transfer.", "img": null}, {"id": "21-556", "deck": 21, "q": "An engine that weighs 350 pounds is removed from an aircraft by means of a mobile hoist. The engine is raised 3 feet above its attachment mount, and the entire assembly is then moved forward 12 feet. A constant force of 70 pounds is required to move the loaded hoist. What is the total work input required to move the hoist?", "options": ["840 foot-pounds.", "1,890 foot-pounds.", "1,050 foot-pounds."], "correctIndex": 0, "explanation": "More information is given with this problem than is needed; therefore, it can cause confusion. The only work asked for is the amount needed to move the hoist. The hoist is moved for a distance of 12 feet and a constant force of 70 pounds is needed to move it. The work done to move the hoist is 12 x 70 = 840 foot-pounds.", "img": null}, {"id": "21-557", "deck": 21, "q": "Which condition is the actual amount of water vapor in a mixture of air and water?", "options": ["Relative humidity.", "Dewpoint.", "Absolute humidity."], "correctIndex": 2, "explanation": "Absolute humidity is the actual amount of water in a volume of air, and it is measured in such units as grams per cubic meter.", "img": null}, {"id": "21-558", "deck": 21, "q": "Under which conditions will the rate of flow of a liquid through a metering orifice (or jet) be the greatest (all other factors being equal)?", "options": ["Unmetered pressure, 18 PSI; metered pressure, 17.5 PSI; atmospheric pressure, 14.5 PSI.", "Unmetered pressure, 23 PSI; metered pressure, 12 PSI; atmospheric pressure, 14.3 PSI.", "Unmetered pressure, 17 PSI; metered pressure, 5 PSI; atmospheric pressure, 14.7 PSI."], "correctIndex": 2, "explanation": "In answering this question, we must recognize that the atmospheric pressure acts equally on both sides of the metering jet and therefore does not enter into the problem. The metering jet with the greatest pressure differential across it will have the greatest rate of flow through it. Jet A has a pressure differential of 0.5 psid. Jet B has a pressure differential of 11 psid. Jet C has a pressure differential of 12 psid.", "img": null}, {"id": "21-559", "deck": 21, "q": "(Refer to Figure 61.) The amount of force applied to rope A to lift the weight is", "options": ["12 pounds.", "15 pounds.", "20 pounds."], "correctIndex": 1, "explanation": "This block and tackle supports the weight with four ropes, and this gives it a mechanical advantage of four. To lift a 60-pound weight, a force of 15 pounds must be exerted on rope A. Rope A will have to be pulled four times the distance the weight is lifted.", "img": "429789_0.jpg"}, {"id": "21-560", "deck": 21, "q": "Which will weigh the least?", "options": ["98 parts of dry air and 2 parts of water vapor.", "35 parts of dry air and 65 parts of water vapor.", "50 parts of dry air and 50 parts of water vapor."], "correctIndex": 1, "explanation": "Water vapor is only about 5/8 as heavy as an equal volume of dry air. The more water vapor in the air, the less the air weighs. In choice A there is 2 percent water vapor. In choice B there is 65 percent water vapor. In choice C there is 50 percent water vapor.0Which is the ratio of the water vapor actually present in the atmosphere to the amount that would be present if the air were saturated at the prevailing temperature and pressure?121Absolute humidity.Relative humidity.Dewpoint.Relative humidity is the ratio of the amount of water vapor actually present in the atmosphere to the amount that would be present if the air were saturated at the prevailing temperature and pressure.", "img": null}, {"id": "21-561", "deck": 21, "q": "The speed of sound in the atmosphere", "options": ["varies according to the frequency of the sound.", "changes with a change in temperature.", "changes with a change in pressure."], "correctIndex": 1, "explanation": "The speed of sound in the atmosphere varies with the temperature of the atmosphere.", "img": null}, {"id": "21-562", "deck": 21, "q": "The speed of sound in the atmosphere is most affected by variations in which of the following?\n1. Sound frequency (cps).\n2. Ambient temperature.\n3. Barometric pressure", "options": ["1.", "2.", "3."], "correctIndex": 1, "explanation": "The speed of sound in the atmosphere varies with the ambient temperature of the atmosphere.", "img": null}, {"id": "21-563", "deck": 21, "q": "If the volume of a confined gas is doubled (without the addition of more gas), the pressure will (assume the temperature remains constant)", "options": ["increase in direct proportion to the volume increase.", "remain the same.", "be reduced to one-half its original value."], "correctIndex": 2, "explanation": "The pressure of a gas in an enclosed container varies inversely as the volume of the container, if the absolute temperature of the gas remains constant. Doubling the volume of the container will decrease the pressure of the enclosed gas to a value of one-half its original pressure.", "img": null}, {"id": "21-564", "deck": 21, "q": "If the temperature of a confined liquid is held constant and its pressure is tripled, the volume will", "options": ["triple.", "be reduced to one-third its original volume.", "remain the same."], "correctIndex": 2, "explanation": "A liquid is considered to be a noncompressible fluid. Its volume changes with a change in its temperature but it remains relatively constant as its pressure changes. If the pressure on a confined liquid is tripled, the volume of the liquid will remain virtually the same.", "img": null}, {"id": "21-565", "deck": 21, "q": "How much work input is required to lower (not drop) a 120-pound weight from the top of a 3-foot table to the floor?", "options": ["120 pounds of force.", "360 foot-pounds.", "40 foot-pounds."], "correctIndex": 1, "explanation": "Work is the product of the amount of force applied to an object times the distance through which the force causes the object to move. As much force is needed to hold back an object when it is being lowered as it does to raise the object. If 120 pounds of force is needed to hold back a weight as it is lowered for 3 feet, 360 foot-pounds of work has been done.", "img": null}, {"id": "21-566", "deck": 21, "q": "Which atmospheric conditions will cause the true landing speed of an aircraft to be the greatest?", "options": ["Low temperature with low humidity.", "High temperature with low humidity.", "High temperature with high humidity."], "correctIndex": 2, "explanation": "The true landing speed of an aircraft is determined by the density of the air. The amount of aerodynamic lift produced by the wing of an airplane or the rotor of a helicopter is determined by several things. Among these are the shape of the airfoil, the speed of the airfoil through the air, and the density of the air. The denser the air, the lower the speed that will produce the same amount of lift. Density of the air depends upon both its temperature and its humidity. The hotter the air, the less dense. The more water vapor in the air (the higher its humidity), the less dense the air. An airplane will have to fly the fastest to produce the required lift under conditions of high temperature and high humidity.", "img": null}, {"id": "21-567", "deck": 21, "q": "If the fluid pressure is 800 PSI in a 1/2-inch line supplying an actuating cylinder with a piston area of 10 square inches, the force exerted on the piston will be", "options": ["4,000 pounds.", "8,000 pounds.", "800 pounds."], "correctIndex": 1, "explanation": "The size of the line that supplies fluid to an actuating cylinder has nothing to do with the amount of force the piston in the cylinder can exert. When a pressure of 800 psi acts on a piston with an area of 10 square inches, a force of 800 x 10 = 8,000 pounds is produced.", "img": null}, {"id": "21-568", "deck": 21, "q": "In physics, which of the following factors are necessary to determine power?\n1. Force exerted.\n2. Distance moved.\n3. Time required.", "options": ["1 and 2.", "2 and 3.", "1, 2, and 3."], "correctIndex": 2, "explanation": "Power is the time rate of doing work.\nIn order to determine the amount of work done, we must know the amount of force used and the distance through which this force acted. Force times distance is equal to work. The amount of power needed is found by dividing the amount of work done by the time used in doing the work. To find the amount of power needed to do a job, we must know the force, the distance and the time.", "img": null}, {"id": "21-569", "deck": 21, "q": "What force must be applied to roll a 120-pound barrel up an inclined plane 9 feet long to a height of 3 feet (disregard friction)?\nL ÷ I = R ÷ E\nL = Length of ramp, measured along the slope.\nI = Height of ramp.\nR = Weight of object to be raised or lowered.\nE = Force required to raise or lower object.", "options": ["40 pounds.", "120 pounds.", "360 pounds."], "correctIndex": 0, "explanation": "This is a simple mechanical advantage problem. We roll the barrel three times as far as we lift it, so the force we must exert to roll the barrel up the inclined plane is only one third of the weight of the barrel. We must exert a force of 40 pounds to roll a 120-pound barrel up the 9-foot inclined plane to lift it 3 feet.", "img": null}, {"id": "21-570", "deck": 21, "q": "Which statement concerning heat and/or temperature is true?", "options": ["There is an inverse relationship between temperature and heat.", "Temperature is a measure of the kinetic energy of the molecules of any substance.", "Temperature is a measure of the potential energy of the molecules of any substance."], "correctIndex": 1, "explanation": "Heat is a form of energy, and temperature is a measure of the intensity of the kinetic energy of the molecules in a substance. Heat energy, in the form of latent heat, can be added to an object or taken from it without changing its temperature. But, the temperature of an object changes directly with the amount of sensible heat put into it or taken from it.", "img": null}, {"id": "21-571", "deck": 21, "q": "What is absolute humidity?", "options": ["The temperature to which humid air must be cooled at constant pressure to become saturated.", "The actual amount of the water vapor in a mixture of air and water.", "The ratio of the water vapor actually present in the atmosphere to the amount that would be present if the air were saturated at the prevailing temperature and pressure."], "correctIndex": 1, "explanation": "Absolute humidity is the actual amount of water in a volume of air. It is measured in such units as grams per cubic meter.", "img": null}, {"id": "21-572", "deck": 21, "q": "The temperature to which humid air must be cooled at constant pressure to become saturated is called", "options": ["dewpoint.", "absolute humidity.", "relative humidity."], "correctIndex": 0, "explanation": "The temperature to which a body of air must be lowered before the water vapor in the air condenses out as visible, liquid water is called the dew point of the air.", "img": null}, {"id": "21-573", "deck": 21, "q": "If both the volume and the absolute temperature of a confined gas are doubled, the pressure will", "options": ["not change.", "be halved.", "become four times as great."], "correctIndex": 0, "explanation": "The pressure exerted by a confined gas is directly proportional to its absolute temperature. If the absolute temperature is doubled, the pressure will also double. The pressure exerted by a confined gas is inversely proportional to its volume. If its volume is doubled, the pressure will decrease to a value that is one half of the original. If both the volume and the absolute temperature of a confined gas are doubled, the two changes will cancel each other, so the pressure of the gas will not change.", "img": null}, {"id": "21-574", "deck": 21, "q": "If all, or a significant part of a stall strip is missing on an airplane wing, a likely result will be", "options": ["asymmetrical lateral control at or near stall angles of attack.", "decreased lift in the area of installation at high angles of attack.", "asymmetrical lateral control at low angles of attack."], "correctIndex": 0, "explanation": "\"Stall strips are small triangular spoilers, or wedges, attached to the leading edge in the root area of a wing that has a tendency to stall at the tip before the root. Stalls beginning at the tip cause a loss of aileron effectiveness, and therefore lateral control, when it is most needed.", "img": null}, {"id": "21-575", "deck": 21, "q": "The purpose of stall strips on airplane wings is to", "options": ["increase lift in the areas of installation.", "prevent stall in the areas of installation.", "ensure that the wing root areas stall first."], "correctIndex": 2, "explanation": "Stall strips are small triangular spoilers, or wedges, attached to the leading edge at the root area of a wing that has a tendency to stall at the tip before the root. Stalls beginning at the tip cause a loss of aileron effectiveness, and therefore lateral control, when it is most needed.\nAt high angles of attack, stall strips disrupt the airflow over the wing root and force it to stall before the portion of the wing ahead of the aileron.", "img": null}, {"id": "21-576", "deck": 21, "q": "An airplane wing is designed to produce lift resulting from", "options": ["positive air pressure below and above the wing's surface along with the downward deflection of air.", "positive air pressure below the wing's surface and negative air pressure above the wing's surface along with the downward deflection of air.", "negative air pressure below the wing's surface and positive air pressure above the wing's surface along with the downward deflection of air."], "correctIndex": 1, "explanation": "Aerodynamic lift is produced on an airfoil by the pressure difference across the airfoil along with the downward deflection of air. The pressure below the wing surface is greater than that above the wing. The pressure below the wing may be considered positive and that above the wing negative.", "img": null}, {"id": "21-577", "deck": 21, "q": "The purpose of aircraft wing dihedral is to", "options": ["increase lateral stability.", "increase longitudinal stability.", "increase lift coefficient of the wing."], "correctIndex": 0, "explanation": "Dihedral or the upward slant of the wing from the fuselage is used to increase the lateral stability. Lateral stability is roll stability and is stability about the longitudinal axis.", "img": null}, {"id": "21-578", "deck": 21, "q": "Aspect ratio of a wing is defined as the ratio of the", "options": ["wingspan to the wing root.", "square of the chord to the wingspan.", "wingspan to the mean chord."], "correctIndex": 2, "explanation": "The aspect ratio of a wing is the ratio of the wing span to the mean, or average, chord. For a nonrectangular wing, aspect ratio is found by dividing the square of the wing span by the wing area.", "img": null}, {"id": "21-579", "deck": 21, "q": "A wing with a very high aspect ratio (in comparison with a low aspect ratio wing) will have", "options": ["increased drag at high angles of attack.", "a low stall speed.", "poor control qualities at low airspeeds."], "correctIndex": 1, "explanation": "Wings with a high aspect ratio have low drag at high angles of attack, low stalling speed, and good control at low airspeeds. Sailplanes have very high aspect ratios and fly slowly.", "img": null}, {"id": "21-580", "deck": 21, "q": "The desired effect of using winglets on an aircraft's wingtips is to", "options": ["increase the lift to drag ratio.", "reduce the aspect ratio.", "optimize wing dihedral and improve lateral stability"], "correctIndex": 0, "explanation": "Winglets, small upturned vertical surfaces mounted on the wing tips, reduce drag by reducing the spanwise flow of air, therefore reducing vortices. The desired effect of using winglets on an aircraft's wingtips is to increase the lift to drag (L/D) ratio of the wing.", "img": null}, {"id": "21-581", "deck": 21, "q": "Which of the following is Newton's First Law of Motion, generally termed the Law of Inertia?", "options": ["To every action there is an equal and opposite reaction.", "Force is proportional to the product of mass and acceleration.", "Every body persists in its state of rest, or of motion in a straight line, unless acted upon by some outside force."], "correctIndex": 2, "explanation": "Newton's first law explains that when an object is at rest, it tries to remain at rest. But when it is moving, it tries to keep moving in a straight line and will not speed up, slow down, or turn unless it is acted upon by an outside force. This tendency of the object to remain in its original condition of motion is called inertia.", "img": null}, {"id": "21-582", "deck": 21, "q": "The main rotor system on a helicopter is classified in three groups. Which of those listed is NOT one of these groups?", "options": ["The fully articulated rotor system.", "The flexible-beam rotor system.", "The semi-rigid rotor system."], "correctIndex": 1, "explanation": "The classification of main rotor systems is based on how the blades move relative to the main rotor hub. The principal classifications are known as fully articulated, semi-rigid, and rigid.", "img": null}, {"id": "21-583", "deck": 21, "q": "Which of the following statements are correct?", "options": ["When the cyclic pitch control lever is raised, the blade angle of all the rotor blades increases uniformly and they create the lift that allows the helicopter to take off vertically.", "When the collective pitch control lever is raised, the blade angle of all the rotor blades increases uniformly and they create the lift that allows the helicopter to take off vertically.", "When the collective pitch control lever is raised, the blade angle of the aft rotor blades decreases uniformly and they create the lift that allows the helicopter to take off vertically."], "correctIndex": 1, "explanation": "The primary flight controls on a helicopter are the collective and cyclic control levers and anti-torque pedals. When the collective pitch control lever is raised, the blade angle of all the rotor blades increases uniformly and they create the lift that allows the helicopter to take off vertically.  The cyclic pitch control lever, like the yoke of an airplane, can be pulled back or pushed forward (for backward or forward motion), and can be moved left and right (to bank left or right).", "img": null}, {"id": "22-584", "deck": 22, "q": "What does the acronym TSO mean regarding a type certificated aircraft part, material, component and/or process?", "options": ["Training Specific Organization.", "Type Supplement Original.", "Technical Standard Order."], "correctIndex": 2, "explanation": "A Technical Standard Order (TSO) is an approval for the manufacture of a component for use on certificated aircraft.", "img": null}, {"id": "22-585", "deck": 22, "q": "What does the Type Certificate Data Sheet designation code '2 PCSM' mean?", "options": ["Two place (number of seats), closed, sea, monoplane.", "Two wing (biplane), primary category, semimonocoque (airframe).", "Neither of the other two choices."], "correctIndex": 0, "explanation": "The FAA uses coded information for the configuration of aircraft and engines in the Type Certificate Data Sheets. The code 2PCSM identifies the aircraft as a two-place, closed, sea, monoplane.", "img": null}, {"id": "22-586", "deck": 22, "q": "Under the Federal Aviation Regulations, an aviation maintenance technician is required to perform maintenance on an aircraft so that it:", "options": ["Always meets its original type design.", "Is at least equal to its original or properly altered condition.", "Exceeds minimum standards with regard to aerodynamic function, structural strength, resistance to vibration, and other qualities affecting airworthiness."], "correctIndex": 1, "explanation": "Each person maintaining or altering, or performing preventive maintenance, shall do that work in such a manner and use materials of such a quality, that the condition of the aircraft, airframe, aircraft engine, propeller or appliance worked on will be at least equal to its original or properly altered condition (with regard to aerodynamic function, structural strength, resistance to vibration and deterioration, and other qualities affecting airworthiness).", "img": null}, {"id": "22-587", "deck": 22, "q": "An aircraft mechanic is privileged to perform major alterations on U.S. certificated aircraft; however, the work must be done in accordance with FAA-approved technical data before the aircraft can be returned to service. Which is NOT approved data?", "options": ["Airworthiness Directives.", "AC 43.13-2A.", "Supplemental Type Certificates."], "correctIndex": 1, "explanation": "The FAA issues or approves two types of data for aircraft: 1. Regulatory data is approved data that specifies the way something will be done. It is specific and it must be complied with as it applies. 2. Data in Advisory Circulars, such as that in AC 43.13-2A, is advisory in nature and is 'acceptable data.' While it shows a way that things can be done, it is neither specific nor mandatory. It is not considered to be 'approved data.'", "img": null}, {"id": "22-588", "deck": 22, "q": "A Technical Standard Order (TSO) is issued by whom?", "options": ["The Aircraft industry.", "Part manufacturers.", "The Administrator."], "correctIndex": 2, "explanation": "TSOs are issued by the Administrator under 14 CFR Part 21.", "img": null}, {"id": "22-589", "deck": 22, "q": "The Air Transport Association of America (ATA) Specification No. 100\n(1) Establishes a standard for the presentation of technical data in maintenance manuals.\n(2) Divides the aircraft into numbered systems and subsystems in order to simplify locating maintenance instructions.\nRegarding the above statements:", "options": ["Both No. 1 and No. 2 are true.", "Neither No. 1 nor No. 2 is true.", "Only No. 1 is true."], "correctIndex": 0, "explanation": "Statement (1) is true. The ATA Specification 100 is a standard for arranging and presenting technical data in maintenance manuals. Statement (2) is also true. The ATA Specification 100 divides the aircraft into numbered systems and subsystems to simplify locating maintenance instructions.", "img": null}, {"id": "22-590", "deck": 22, "q": "An aircraft Type Certificate Data Sheet contains:", "options": ["Maximum fuel grade to be used.", "Control surface adjustment points.", "Location of the datum."], "correctIndex": 2, "explanation": "Since the location of all items in an aircraft are measured from the datum and this datum can be at any location the aircraft manufacturer chooses, the technician must know exactly where this reference is located. The location of the datum is included in the information furnished on a Type Certificate Data Sheet.", "img": null}, {"id": "22-591", "deck": 22, "q": "Suitability for use of a specific propeller with a particular engine-airplane combination can be determined by reference to what informational source?", "options": ["Propeller Specifications or Propeller Type Certificate Data Sheet.", "Aircraft Specifications or Aircraft Type Certificate Data Sheet.", "Alphabetical Index of Current Propeller Type Certificate Data Sheets, Specifications, and Listings."], "correctIndex": 1, "explanation": "The Aircraft Specifications or Type Certificate Data Sheets list all of the allowable engine-propeller combinations approved for a specific aircraft.", "img": null}, {"id": "22-592", "deck": 22, "q": "(Refer to Figure 62, 62A, & 62B as necessary.) How many parts will need to be fabricated by the mechanic in the construction and installation of one doubler?", "options": ["2.", "3.", "4."], "correctIndex": 1, "explanation": "The mechanic must fabricate three parts to install the doubler. For the -100 installation, one doubler -101 and two clips -103 are needed. For the -200 installation, one doubler -102 and two clips -103 are needed.", "img": "429790_4.jpg"}, {"id": "22-593", "deck": 22, "q": "How long are AD compliance records required to be kept?", "options": ["Until the work is repeated or superseded by other work.", "For one year after the work is performed, or until the work is repeated or superseded by other work.", "They shall be retained, and then transferred with the aircraft when it is sold."], "correctIndex": 2, "explanation": "14 CFR Part 91.417(b)(2)(v) states that the record of the current status of applicable airworthiness directives (AD) including, for each, the method of compliance, the AD number, and revision date be retained and transferred with the aircraft at the time the aircraft is sold.", "img": null}, {"id": "22-594", "deck": 22, "q": "Which regulation provides information regarding instrument range markings for an airplane certificated in the normal category?", "options": ["14 CFR Part 21.", "14 CFR Part 25.", "14 CFR Part 23."], "correctIndex": 2, "explanation": "Information regarding instrument range markings that must be used on aircraft certificated in the normal category is found in 14 CFR Part 23, 'Airworthiness Standards: Normal, Utility, Acrobatic and Commuter Category Airplanes.'", "img": null}, {"id": "22-595", "deck": 22, "q": "Which of the following are sometimes used as authorization to deviate from an aircraft's original type design? \n1. FAA Form 337.\n2. Supplemental Type Certificate.\n3. Airworthiness Directive.\n4. Technical Standard Order", "options": ["1, 2, 3, and 4.", "1, 2, and 4.", "1, 2, and 3."], "correctIndex": 2, "explanation": "The FAA Form 337 is the form which the FAA uses to authorize a major alteration that may deviate from the aircraft's original type design. A Supplemental Type Certificate (STC) is an authorization for a major change in the type design that is not great enough to require a new application for a type certificate. An Airworthiness Directive (AD) identifies an unsafe condition that exists in a product and that is likely to exist or develop in other products of the same type design. AD's may require alterations that deviate from the aircraft's original type design .", "img": null}, {"id": "22-596", "deck": 22, "q": "The action required by an AD may take what form? \n1. Inspection.\n2. Part(s) replacement.\n3. Design modification.\n4. Change in operating procedure(s).\n5. Overall change in the content, form and disposition of aircraft maintenance records.", "options": ["1, 2, 3, and/or 4.", "1, 2, 3, and/or 5.", "1, 2, 3, 4, and/or 5."], "correctIndex": 0, "explanation": "The action required by an AD is described in the Compliance statement which specifies the action that is required by the AD, and specifies the method of compliance. An AD does not specify an overall change in maintenance records.", "img": null}, {"id": "22-597", "deck": 22, "q": "(1) The Federal Aviation Regulations require approval after compliance with the data of a Supplemental Type Certificate.\n(2) An installation of an item manufactured in accordance with the Technical Standard Order system requires no further approval for installation in a particular aircraft.\nRegarding the above statements:", "options": ["Only No. 2 is true.", "Neither No. 1 nor No. 2 is true.", "Only No. 1 is true."], "correctIndex": 2, "explanation": "Statement (1) is true. After an aircraft has been altered in accordance with a Supplemental Type Certificate, it must be inspected for conformity with the information included in the STC before it can be approved for return to service. Statement (2) is not true. Even though a part has been manufactured according to a Technical Standard Order, it is not necessarily approved for installation on a particular civil aircraft.", "img": null}, {"id": "22-598", "deck": 22, "q": "(1) Manufacturer's data and FAA publications such as Airworthiness Directives, Type Certificate Data Sheets, and advisory circulars are all approved data.\n(2) FAA publications such as Technical Standard Orders, Airworthiness Directives, Type Certificate Data Sheets, and Aircraft Specifications and Supplemental Type Certificates are all approved data.\nRegarding the above statements:", "options": ["Both No. 1 and No. 2 are true.", "Only No. 1 is true.", "Only No. 2 is true."], "correctIndex": 2, "explanation": "Statement (1) is not true. Not all manufacturer's data is FAA approved and Advisory Circulars are not considered to be approved data. Statement (2) is true. All of the items listed in this statement are considered to be approved data.", "img": null}, {"id": "22-599", "deck": 22, "q": "(Refer to Figure 62.) The -100 in the title block (Area 1) is applicable to which doubler part number(s)?", "options": ["-101.", "-102.", "Both."], "correctIndex": 0, "explanation": "In Figure 62, follow the column for the -100 assembly upward to see the components it requires. The -101 doubler is in this column.", "img": "429790_4.jpg"}, {"id": "22-600", "deck": 22, "q": "Airworthiness Directives are issued primarily to:", "options": ["Provide information about malfunction or defect trends.", "Present recommended maintenance procedures for correcting potentially hazardous defects.", "Correct an unsafe condition."], "correctIndex": 2, "explanation": "The FAA issues Airworthiness Directives to correct unsafe conditions that have been discovered on certificated aircraft, engines, propellers, or appliances. An unsafe condition causes the device to fail to meet the conditions for its certification. An Airworthiness Directive specifies the corrective action that must be taken to return the device to the conditions specified for its certification.", "img": null}, {"id": "22-601", "deck": 22, "q": "Technical information about older aircraft models, of which no more than 50 remain in service, can be found in the:", "options": ["Aircraft Listing.", "Summary of Deleted and Discontinued Aircraft Specifications.", "Index of Antique Aircraft."], "correctIndex": 0, "explanation": "The certification specifications for aircraft of which there are fewer than 50 currently in service, or of which there were fewer than 50 certificated, are found in the Aircraft Listing.", "img": null}, {"id": "22-602", "deck": 22, "q": "When an airworthy (at the time of sale) aircraft is sold, the Airworthiness Certificate:", "options": ["Becomes invalid until the aircraft is reinspected and approved for return to service.", "Is voided and a new certificate is issued upon application by the new owner.", "Is transferred with the aircraft."], "correctIndex": 2, "explanation": "The Airworthiness Certificate issued to an aircraft is transferred with the aircraft to the new owner when the aircraft is sold.", "img": null}, {"id": "22-603", "deck": 22, "q": "The following words are an example of what kind of statement in an AD? 'Required within the next 25 hours time-in-service after the effective date of this AD, unless already accomplished.", "options": ["Amendment.", "Compliance.", "Applicability."], "correctIndex": 1, "explanation": "'Within the next 25 hours time-in-service after the effective date of this AD,' is a statement of compliance time or date.", "img": null}, {"id": "22-604", "deck": 22, "q": "Type Certificate Data Sheets are issued for which of the following products?", "options": ["Aircraft, engines, and propellers.", "Aircraft, engines, and appliances.", "Aircraft, engines, propellers, and appliances."], "correctIndex": 0, "explanation": "Type Certificate Data Sheets (TCDS) and Specifications set forth essential factors and other conditions which are necessary for U.S. airworthiness certification of aircraft, engines and propellers.", "img": null}, {"id": "22-605", "deck": 22, "q": "A complete detailed inspection and adjustment of the valve mechanism will be made at the first 25 hours after the engine has been placed in service. Subsequent inspections of the valve mechanism will be made each second 50-hour period.\nFrom the above statement, at what intervals will valve mechanism inspections be performed?", "options": ["100 hours.", "50 hours.", "125 hours."], "correctIndex": 0, "explanation": "Since the valve mechanism is required to be inspected only every second 50-hour period, the engine can operate for 100 hours between valve mechanism inspections.", "img": null}, {"id": "22-606", "deck": 22, "q": "The issuance of an Airworthiness Certificate is governed by:", "options": ["14 CFR Part 23.", "14 CFR Part 21.", "14 CFR Part 39."], "correctIndex": 1, "explanation": "14 CFR Part 21 entitled 'Certification Procedures for Products and Parts' governs the issuance of an Airworthiness Certificate.", "img": null}, {"id": "22-607", "deck": 22, "q": "The following is a table of airspeed limits as given in an FAA-issued aircraft specification:\nNormal operating speed 260 knots\nNever-exceed speed 293 knots\nMaximum landing gear operation speed 174 knots\nMaximum flap extended speed 139 knots\nThe high end of the white arc on the airspeed instrument would be at:", "options": ["260 knots.", "293 knots.", "139 knots."], "correctIndex": 2, "explanation": "The maximum flap extended speed is marked on an aircraft airspeed indicator by the top of the white arc. The white arc would extend to 139 knots.", "img": null}, {"id": "22-608", "deck": 22, "q": "Aviation Maintenance Alerts (formerly General Aviation Airworthiness Alerts)", "options": ["Provide mandatory procedures to prevent or correct serious aircraft problems.", "Provide information about aircraft problems and suggested corrective actions.", "Provide temporary emergency procedures until Airworthiness Directives can be issued."], "correctIndex": 1, "explanation": "Aviation Maintenance Alerts, formerly General Aviation Airworthiness Alerts, provide a common communication channel through which the aviation community can economically interchange service experience and thereby cooperate in the improvement of aeronautical product durability, reliability, and safety. The contents include items that have been reported to be significant but have not been evaluated fully by the time the material went to press.", "img": null}, {"id": "22-609", "deck": 22, "q": "(1) Propellers are NOT included in the Airworthiness Directive system.\n(2) A certificated powerplant mechanic may make a minor repair on an aluminum propeller and approve for return to service.\nRegarding the above statements:", "options": ["Only No. 2 is true.", "Both No. 1 and No. 2 are true.", "Neither No. 1 nor No. 2 is true."], "correctIndex": 0, "explanation": "Statement (1) is false. Propellers are included in the Airworthiness Directive system. Statement (2) is true. A certificated powerplant mechanic can make a minor repair to an aluminum propeller and can approve it for return to service.", "img": null}, {"id": "22-610", "deck": 22, "q": "Where are technical descriptions of certificated propellers found?", "options": ["Applicable Airworthiness Directives.", "Aircraft Specifications.", "Propeller Type Certificate Data Sheets."], "correctIndex": 2, "explanation": "Technical specifications for certificated aircraft propellers are found in the Propeller Type Certificate Data Sheets.", "img": null}, {"id": "22-611", "deck": 22, "q": "Primary responsibility for compliance with Airworthiness Directives lies with the:", "options": ["Aircraft owner or operator.", "Certificated mechanic holding an Inspection Authorization who conducts appropriate inspections.", "Certificated mechanic who maintains the aircraft."], "correctIndex": 0, "explanation": "The aircraft owner or operator is responsible for determining that the aircraft continues to meet the requirements for its certification. This includes the compliance with all Airworthiness Directives.", "img": null}, {"id": "22-612", "deck": 22, "q": "(Refer to Figure 62, 62A, and 62B as necessary.) Using only the information given (when bend allowance, set back, etc. have been calculated) which doubler is it possible to construct and install?", "options": ["-101.", "-102.", "Both."], "correctIndex": 0, "explanation": "There is enough information given here to construct and install the -101 doubler. There is not enough information to construct the stronger -102 doubler in the -200 installation. The -102 doubler requires certain Process Specifications that are not furnished.", "img": "429790_6.jpg"}, {"id": "22-613", "deck": 22, "q": "Which of the following includes all the regulatory definitions of 'maintenance'?", "options": ["Overhaul, repair, parts replacement, and preservation, and preventive maintenance.", "Overhaul, repair, parts replacement, preservation, inspection, and preventive maintenance.", "Overhaul, repair, parts replacement, inspection, and preservation."], "correctIndex": 2, "explanation": "14 CFR Part 1 defines maintenance as inspection, overhaul, repair, preservation, and the replacement of parts, but excludes preventive maintenance.", "img": null}, {"id": "22-614", "deck": 22, "q": "When is a mechanic responsible for checking AD compliance?", "options": ["Never, the owner or operator is solely responsible.", "When performing an inspection required under part 91, 125, or 135.", "Anytime an aircraft or portion thereof is returned to service."], "correctIndex": 1, "explanation": "It is the responsibility of the mechanic performing an inspection required under part 91, 125, or 135 of 14 CFR to determine the status of any AD affecting the airframe, engine, propeller, rotor, and any installed appliances.", "img": null}, {"id": "22-615", "deck": 22, "q": "Placards required on an aircraft are specified in:", "options": ["AC 43.13-1B.", "The Federal Aviation Regulations under which the aircraft was type certificated.", "Aircraft Specifications or Type Certificate Data Sheets."], "correctIndex": 2, "explanation": "Placards that furnish information vital to the safety of flight and that must be installed in a certificated aircraft are specified in the Type Certificate Data Sheets for the aircraft.", "img": null}, {"id": "22-616", "deck": 22, "q": "(1) A Supplemental Type Certificate may be issued to more than one applicant for the same design change, providing each applicant shows compliance with the applicable airworthiness requirement.\n(2) An installation of an item manufactured in accordance with the Technical Standard Order system requires no further approval for installation in a particular aircraft.\nRegarding the above statements:", "options": ["Both No. 1 and No. 2 are true.", "Neither No. 1 nor No. 2 is true.", "Only No. 1 is true."], "correctIndex": 2, "explanation": "Statement (1) is true. More than one person may apply for a Supplemental Type Certificate that covers the same change to an aircraft. An STC is not a patent and it is not protected. Each applicant must furnish proof that his alteration meets all of the applicable airworthiness requirements. Statement (2) is not true. A part produced according to a Technical Standard Order (TSO) requires specific approval for installation on a particular aircraft. Even though the part is built according to a TSO, it may be neither suitable nor approved for the particular aircraft.", "img": null}, {"id": "22-617", "deck": 22, "q": "Specifications pertaining to an aircraft model manufactured under a type certificate, of which less than 50 are shown on the FAA Aircraft Registry, can be found in the:", "options": ["Aircraft Listing.", "Summary of Discontinued Aircraft Specifications.", "FAA Statistical Handbook of Civil Aircraft Specifications."], "correctIndex": 0, "explanation": "The certification specifications for aircraft of which there are fewer than 50 currently in service or of which there were fewer than 50 certificated are found in the Aircraft Listing.", "img": null}, {"id": "22-618", "deck": 22, "q": "What is the maximum penalty for cheating or other unauthorized conduct when taking an FAA mechanic test?", "options": ["Ineligibility to receive any certificate or rating for one year.", "Ineligibility to receive any certificate or rating for one year, and suspension or revocation of any certificate held.", "Ineligibility to receive any certificate or rating for one year, and suspension of any certificate held."], "correctIndex": 1, "explanation": "14 CFR 65.18(b) states that no person who cheats, gives or receives help from another, takes a part of the test for another, uses unauthorized material during the test is eligible for any airman or ground instructor certificate or rating for a period of one year after the date of that act. In addition, the commission of that act is a basis for suspending or revoking any airman or ground instructor certificate held by that person.", "img": null}, {"id": "22-619", "deck": 22, "q": "What is the maintenance recording responsibility of the person who complies with an Airworthiness Directive?", "options": ["Advise the aircraft owner/operator of the work performed.", "Make an entry in the maintenance record of that equipment.", "Advise the FAA district office of the work performed, by submitting an FAA Form 337."], "correctIndex": 1, "explanation": "When a technician complies with an Airworthiness Directive, it is his or her responsibility to make an entry in the maintenance record of the affected equipment. This entry must include the method of compliance and the date of compliance.", "img": null}, {"id": "22-620", "deck": 22, "q": "An aircraft has a total time in service of 468 hours. The Airworthiness Directive given was initially complied with at 454 hours in service. How many additional hours in service may be accumulated before the Airworthiness Directive must again be complied with?\nThe following is the compliance portion of an Airworthiness Directive. 'Compliance required as indicated, unless already accomplished.\nI. Aircraft with less that 500-hours' total time in service: Inspect in accordance with instructions below at 500-hours' total time, or within the next 50-hours' time in service after the effective date of this AD, and repeat after each subsequent 200 hours in service.\nII. Aircraft with 500-hours' through 1,000-hours' total time in service: Inspect in accordance with instructions below within the next 50-hours' time in service after the effective date of this AD, and repeat after each subsequent 200 hours in service.\nIII. Aircraft with more than 1,000-hours' time in service: Inspect in accordance with instructions below within the next 25-hours' time in service after the effective date of this AD, and repeat after each subsequent 200 hours in service.'", "options": ["46.", "200.", "186."], "correctIndex": 2, "explanation": "The aircraft has less than 500 hours total time in service, so compliance with the AD falls in category I. The AD has been complied with and the aircraft has operated for 14 hours since the compliance. The AD must be complied with each 200 hours of time in service, so the aircraft can operate for another 186 hours before the AD note must be complied with again.", "img": null}, {"id": "22-621", "deck": 22, "q": "(Refer to Figure 62, 62A, and 62B as necessary.) Which doubler(s) require(s) heat treatment before installation?", "options": ["-101.", "-102.", "Both."], "correctIndex": 1, "explanation": "Doubler -102 is made of .040 7075-O Alclad. This material is in its annealed (-O) condition, and it must be heat-treated to its -T6 condition before it is installed. Doubler -101 is made of 2024-T3 Alclad which is already heat-treated. According to General Notes-200 in Figure 62A, the -102 doubler should be heat-treated to -T6 condition in accordance with Process Specification 5602.", "img": "429790_4.jpg"}, {"id": "22-622", "deck": 22, "q": "What information is generally contained in Aircraft Specifications or Type Certificate Data Sheets?", "options": ["Empty weight of the aircraft.", "Useful load of aircraft.", "Control surface movements."], "correctIndex": 2, "explanation": "The amount of control surface movement determines the structural loads that can be put on an aircraft and also the flight characteristics of the aircraft. Because this information is so critical, it is included on the Type Certificate Data Sheets of an aircraft.", "img": null}, {"id": "22-623", "deck": 22, "q": "Which regulation provides the airworthiness standards for an airplane certificated in the normal category?", "options": ["14 CFR Part 27.", "14 CFR Part 25.", "14 CFR Part 23."], "correctIndex": 2, "explanation": "14 CFR Part 27 provides the airworthiness standards for normal category rotorcraft. 14 CFR Part 25 provides airworthiness standards for transport category airplanes. 14 CFR Part 23 provides airworthiness standards for normal, utility, acrobatic, and commuter category airplanes.", "img": null}, {"id": "22-624", "deck": 22, "q": "Check thrust bearing nuts for tightness on new or newly overhauled engines at the first 50-hour inspection following installation. Subsequent inspections on thrust bearing nuts will be made at each third 50-hour inspection.\nFrom the above statement, at what intervals should you check the thrust bearing nut for tightness?", "options": ["150 hours.", "200 hours.", "250 hours."], "correctIndex": 0, "explanation": "Since the thrust bearing nuts must be checked for tightness after the first 50 hours in service and then on every third 50-hour inspection, the engine can operate for 150 hours between inspections of tightness of the thrust bearing nuts.", "img": null}, {"id": "22-625", "deck": 22, "q": "What regulations are covered by 14 CFR Part 1?", "options": ["Certification of airmen other than crewmembers.", "General operating and flight rules.", "Definitions and abbreviations."], "correctIndex": 2, "explanation": "14 CFR part 1 covers definitions and abbreviations. This regulation is helpful for learning the legal terms and their associated meanings as well as the many acronyms used in aviation.", "img": null}, {"id": "23-626", "deck": 23, "q": "Certificated mechanics with a powerplant rating may perform", "options": ["any inspection required by the Federal Aviation Regulations on a powerplant or propeller or any component thereof, and may release the same to service.", "100-hour and/or annual inspections required by the Federal Aviation Regulations on powerplants, propellers, or any components thereof, and may release the same to service.", "100-hour inspections required by the Federal Aviation Regulations on powerplants, propellers, or any components thereof, and may release the same to service."], "correctIndex": 2, "explanation": "A certificated mechanic holding a powerplant rating is authorized to perform a 100-hour inspection on a powerplant or propeller or any component thereof and may release the same for service.", "img": null}, {"id": "23-627", "deck": 23, "q": "A repair, as performed on an airframe, shall mean", "options": ["the upkeep and preservation of the airframe including the component parts thereof.", "the restoration of the airframe to a condition for safe operation after damage or deterioration.", "simple or minor preservation operations and the replacement of small standard parts not involving complex assembly operations."], "correctIndex": 1, "explanation": "A repair to an aircraft structure is an operation that restores the structure to a condition for safe operation after it has become deteriorated or has been damaged.", "img": null}, {"id": "23-628", "deck": 23, "q": "The replacement of fabric on fabric-covered parts such as wings, fuselages, stabilizers, or control surfaces is considered to be a", "options": ["minor repair unless the new cover is different in any way from the original cover.", "minor repair unless the underlying structure is altered or repaired.", "major repair even though no other alteration or repair is performed."], "correctIndex": 2, "explanation": "Replacing the fabric on fabric-covered parts such as wings, fuselages, stabilizers, or control surfaces is considered to be a major repair even though no other alteration or repair is performed.", "img": null}, {"id": "23-629", "deck": 23, "q": "Which is classified as a major repair?", "options": ["The splicing of skin sheets.", "Installation of new engine mounts obtained from the aircraft manufacturer.", "Any repair of damaged stressed metal skin."], "correctIndex": 0, "explanation": "14 CFR Part 43, Appendix A (b)(1)(xxiv) lists the splicing of skin sheets as an airframe major repair.", "img": null}, {"id": "23-630", "deck": 23, "q": "The 100-hour inspection required by Federal Aviation Regulations for certain aircraft being operated for hire may be performed by", "options": ["persons working under the supervision of an appropriately rated mechanic, but the aircraft must be approved by the mechanic for return to service.", "appropriately rated mechanics only if they have an inspection authorization.", "appropriately rated mechanics and approved by them for return to service."], "correctIndex": 2, "explanation": "A 100-hour inspection of an aircraft that is operated for hire may be performed by an appropriately rated mechanic and approved by him or her for return to service.", "img": null}, {"id": "23-631", "deck": 23, "q": "A person working under the supervision of a certificated mechanic with an airframe and powerplant rating is not authorized to perform", "options": ["repair of a wing brace strut by welding.", "a 100-hour inspection.", "repair of an engine mount by riveting."], "correctIndex": 1, "explanation": "A 100-hour inspection is the only procedure listed in these alternatives that a person working under the supervision of an appropriately rated mechanic is not allowed to perform.\nOnly a mechanic holding the appropriate ratings can perform the inspection.", "img": null}, {"id": "23-632", "deck": 23, "q": "Certificated mechanics, under their general certificate privileges, may", "options": ["perform minor repairs to instruments.", "perform 100-hour inspection of instruments.", "perform minor alterations to instruments."], "correctIndex": 1, "explanation": "A properly certificated mechanic may perform a 100-hour inspection of instruments, but he or she may not make any repair or alteration to an instrument.", "img": null}, {"id": "23-633", "deck": 23, "q": "An Airworthiness Directive requires that a propeller be altered. Certificated mechanics could", "options": ["perform and approve the work for return to service if it is a minor alteration.", "not perform the work because it is an alteration.", "not perform the work because they are not allowed to perform and approve for return to service, repairs or alterations to propellers."], "correctIndex": 0, "explanation": "A certificated mechanic with a powerplant rating is authorized to perform the work called for in an Airworthiness Directive on a propeller that requires a minor alteration to the propeller. After complying with the Airworthiness Directive, the mechanic can approve the propeller for return to service.", "img": null}, {"id": "23-634", "deck": 23, "q": "The replacement of a damaged vertical stabilizer with a new identical stabilizer purchased from the aircraft manufacturer is considered a", "options": ["minor alteration.", "major repair.", "minor repair."], "correctIndex": 2, "explanation": "The replacement of a damaged vertical stabilizer with a new identical stabilizer purchased from the aircraft manufacturer is a minor repair. A rule of thumb for determining whether a repair is minor or major is that if the part can be bolted on and not require any riveting or welding, the repair is minor. This rule of thumb might well have exceptions.", "img": null}, {"id": "23-635", "deck": 23, "q": "FAA certificated mechanics may", "options": ["approve for return to service a major repair for which they are rated.", "supervise and approve a 100-hour inspection.", "approve for return to service a minor alteration they have performed appropriate to the rating(s) they hold."], "correctIndex": 2, "explanation": "FAA-certificated mechanics may approve for return to service a minor alteration they have performed appropriate to the rating(s) they hold. This privilege, of course, assumes that the mechanic understands the current instructions of the manufacturer and has the maintenance manuals for the specific operation concerned. A certificated mechanic is not authorized to supervise a 100-hour inspection.", "img": null}, {"id": "23-636", "deck": 23, "q": "A certificated mechanic with a powerplant rating may perform the", "options": ["annual inspection required by the Federal Aviation Regulations on a powerplant or any component thereof and approve and return the same to service.", "100-hour inspection required by the Federal Aviation Regulations on a powerplant or any component thereof and approve and return the same to service.", "100-hour inspection required by the Federal Aviation Regulations on an airframe, powerplant or any other component thereof and approve and return the same to service."], "correctIndex": 1, "explanation": "A certificated mechanic with a powerplant rating is authorized to conduct a 100-hour inspection on a powerplant or any component thereof and approve the return to service of the same.", "img": null}, {"id": "23-637", "deck": 23, "q": "What part of the Federal Aviation Regulations prescribes the requirements for issuing mechanic certificates and associated ratings and the general operating rules for the holders of these certificates and ratings?", "options": ["14 CFR Part 43.", "14 CFR Part 91.", "14 CFR Part 65."], "correctIndex": 2, "explanation": "14 CFR Part 65, 'Certification: Airmen Other Than Flight Crewmembers' prescribes the requirements for the issuance of mechanic certificates and associated ratings and the general operating rules for the holders of these certificates and ratings.", "img": null}, {"id": "23-638", "deck": 23, "q": "A certificated mechanic shall not exercise the privileges of the certificate and rating unless, within the preceding 24 months, the Administrator has found that the certificate holder is able to do the work or the certificate holder has", "options": ["served as a mechanic under the certificate and rating for at least 18 months.", "served as a mechanic under the certificate and rating for at least 12 months.", "served as a mechanic under the certificate and rating for at least 6 months."], "correctIndex": 2, "explanation": "A certificated mechanic shall not exercise the privileges of the certificate and rating unless, within the preceding 24 months, the Administrator has found that the certificate holder is able to do the work or the certificate holder has served as a mechanic of the certificate and rating for at least six months.", "img": null}, {"id": "23-639", "deck": 23, "q": "Under Title 14 of the Code of Federal Regulations, what is the maximum penalty for falsification, alteration, or fraudulent reproduction of certificates, logbooks, reports, and records?", "options": ["Ineligibility to receive any certificate or rating for one year.", "Imprisonment for one year and a $5,000.00 fine.", "Suspension or revocation of any certificate held."], "correctIndex": 2, "explanation": "14 CFR 65.20 states that any person who falsifies or makes a fraudulent entry in a logbook, report, or record is subject to the suspension or revocation of any airman or ground instructor certificate or rating held by that person.", "img": null}, {"id": "23-640", "deck": 23, "q": "How long does the holder of a certificate issued under 14 CFR part 65 have to notify the FAA after any change in permanent mailing address?", "options": ["30 days.", "60 days.", "90 days."], "correctIndex": 0, "explanation": "14 CFR 65.21 states that within 30 days after any change in his permanent mailing address, the holder of a certificate issued under this part shall notify the Department of Transportation, Federal Aviation Administration, Airman Certification Branch, Post Office Box 25082, Oklahoma City, OK 73125 in writing, of his new address.", "img": null}, {"id": "23-641", "deck": 23, "q": "How long is a mechanic certificate with airframe and/or powerplant ratings valid?", "options": ["Until the holder is relieved of duties for which the holder was employed and certificated.", "Until surrendered, suspended, or revoked.", "Until 24 months after the holder has last exercised the privileges of the certificate."], "correctIndex": 1, "explanation": "14 CFR 65.15 states that a mechanic certificate with airframe and/or powerplant rating is effective until it is surrendered, suspended, or revoked.", "img": null}, {"id": "23-642", "deck": 23, "q": "Why is a mechanic applicant issued a temporary certificate after successful completion of the required tests?", "options": ["To allow for review of his/her application and supplementary documents.", "So that a background check/ investigation may be completed.", "Both of the other two choices."], "correctIndex": 0, "explanation": "14 CFR 65.13 provides for a temporary certificate and rating effective for a period of 120 days to be issued to a qualified applicant, pending review of his  application and supplementary documents and the issue of the certificate and ratings for which he applied.", "img": null}, {"id": "23-643", "deck": 23, "q": "What is the maximum duration of a temporary airman certificate?", "options": ["60 days.", "90 days.", "120 days."], "correctIndex": 2, "explanation": "14 CFR 65.13 provides for a temporary certificate and rating effective for a period of 120 days to be issued to a qualified applicant.", "img": null}, {"id": "23-644", "deck": 23, "q": "When may an otherwise qualified mechanic who does not read, write, speak, and understand the English language be eligible to apply for a mechanic certificate?", "options": ["When a special authorization has been granted by the Administrator.", "When employed outside the United States by a U.S. air carrier.", "When employed outside the United States."], "correctIndex": 1, "explanation": "14 CFR 65.71(a)(2) requires that the applicant for a mechanic certificate be able to read, write, speak, and understand the English language, or in the case of an applicant who is employed outside of the United States by a U. S. air carrier, have his certificate endorsed 'Valid only outside the United States.'", "img": null}, {"id": "23-645", "deck": 23, "q": "Which of the following statements is true for a certificated and appropriately rated mechanic regarding repairs and alterations?", "options": ["He/she may perform an airframe major repair or major alteration, but cannot approve the work for return to service.", "He/she may perform airframe minor repairs and minor alterations and approve the work for return to service, but cannot perform an airframe major repair or major alteration.", "He/she may perform an airframe major repair or major alteration and approve the work, but not the entire aircraft, for return to service."], "correctIndex": 0, "explanation": "14 CFR 65.81(a) states that a certificated mechanic may perform or supervise the maintenance, preventive maintenance or alteration of an aircraft or appliance, or a part thereof for which he is rated (but excluding major repairs to or major alterations of propellers, and any  repair to, or alteration of instruments).\nThe mechanic must complete the FAA Form 337, filling in the compliance statement, but the person approving the work for return to service must hold an Inspection Authorization", "img": null}, {"id": "23-646", "deck": 23, "q": "(1) Certificated mechanics with an airframe rating may perform a minor repair to an airspeed indicator providing they have the necessary equipment available.\n(2) Certificated mechanics with a powerplant rating may perform a major repair to a propeller providing they have the necessary equipment available.\nRegarding the above statements,", "options": ["only No. 1 is true.", "neither No. 1 nor No. 2 is true.", "only No. 2 is true."], "correctIndex": 1, "explanation": "Statement (1) is not true. No certificated mechanic, regardless of his or her ratings, is allowed to perform minor or major repairs, or minor or major alterations to instruments. Statement (2) is not true. A mechanic holding a powerplant rating cannot perform major repairs or major alterations to propellers.", "img": null}, {"id": "23-647", "deck": 23, "q": "Who is responsible for determining that materials used in aircraft maintenance and repair are of the proper type and conform to the appropriate standards?", "options": ["The installing person or agency.", "The owner or operator  of the aircraft.", "The manufacturer of the aircraft."], "correctIndex": 0, "explanation": "It is the responsibility of the person or agency (the certificated mechanic or the approved repair station) performing aircraft maintenance or making repairs to an aircraft, to make sure that all of the materials used in the maintenance or repair conform to the appropriate standards.", "img": null}, {"id": "23-648", "deck": 23, "q": "Which of these publications contains standards for protrusion of bolts, studs, and screws through self-locking nuts?", "options": ["AC 43.13-1B.", "AC 43.13-2.", "Aircraft Specifications or Type Certificate Data Sheets."], "correctIndex": 0, "explanation": "AC 43.13-1B, on page 7-11 states that 'After the nut has been tightened, make sure that the bolt or stud has at least one thread showing past the nut.'", "img": null}, {"id": "23-649", "deck": 23, "q": "The replacement of a damaged engine mount with a new identical engine mount purchased from the aircraft manufacturer is considered a", "options": ["major or minor repair, depending upon the complexity of the installation.", "major repair.", "minor repair."], "correctIndex": 2, "explanation": "The replacement of a part such as an engine mount with a new, identical part obtained from the aircraft manufacturer is considered to be an airframe minor repair.", "img": null}, {"id": "23-650", "deck": 23, "q": "Who has the authority to approve for return to service a propeller after a 100-hour inspection?\n1. A mechanic with a powerplant rating.\n2. Any certificated repairman.\n3. A non-certificated mechanic working under the supervision of a certificated mechanic with airframe and powerplant ratings.", "options": ["1.", "2.", "1 and 3."], "correctIndex": 0, "explanation": "A certificated mechanic holding a powerplant rating is authorized to perform a 100-hour inspection on a propeller and may approve the same for return to service.", "img": null}, {"id": "23-651", "deck": 23, "q": "Instrument repairs may be performed", "options": ["by the instrument manufacturer only.", "by an FAA-approved instrument repair station.", "on airframe instruments by mechanics with an airframe rating."], "correctIndex": 1, "explanation": "Repairs to an instrument, either major or minor repairs, may be performed only by an FAA-approved instrument repair station. The manufacturer of the instrument has this type of rating.", "img": null}, {"id": "23-652", "deck": 23, "q": "How is a quality system assured?", "options": ["By an indepedent organization.", "By a dependent organization.", "By an internal reporting and auditing system."], "correctIndex": 2, "explanation": "A quality system must include procedures for planning, conducting, and documenting internal audits to ensure compliance with the approved quality system. The procedures must include reporting results of internal audits to the manager responsible for implementing corrective and preventive actions.", "img": null}, {"id": "23-653", "deck": 23, "q": "According to Dr. James Reason, there are two types of human failure which can occur. They are:", "options": ["active and latent.", "mental and physical.", "proper and improper."], "correctIndex": 0, "explanation": "There are two types of failure which can occur - active and latent. An active failure is one in which the effects are immediate. A latent failure occurs as a result of a decision made or action takenlong before the incident or accident actually occurs.", "img": null}, {"id": "23-654", "deck": 23, "q": "Many areas of aviation have shifted their focus from eliminating error to", "options": ["preventing and managing error.", "identifying and mitigating error.", "reducing and containing error."], "correctIndex": 0, "explanation": "The goal of the Maintenance Error Decision Aid (MEDA) is to investigate errors, understand root causes, prevent and manage accident (most of the factors that contribute to an error can be managed).", "img": null}, {"id": "23-655", "deck": 23, "q": "When we think of aviation safety in a contemporary way, human error is", "options": ["the starting point.", "the ending point.", "the intervention point."], "correctIndex": 0, "explanation": "The \"SHEL\" model is another concept for investigating and evaluating maintenance errors. The acronym SHEL represents software, hardware, environment and liveware -- with the human as the starting point for all.", "img": null}, {"id": "23-656", "deck": 23, "q": "All of the following are consequences of human error, except", "options": ["mental stressor.", "catastrophic.", "personal injury."], "correctIndex": 0, "explanation": "Human error is defined as a human action with unintended consequences. There are four consequences of human error: little or no effect, damage to equipment/hardware, personal injury, or catastrophic damage.", "img": null}, {"id": "23-657", "deck": 23, "q": "The positive aspects of human factor issues are referred to as the", "options": ["Magnificent Seven.", "Dirty Dozen.", "MEDA."], "correctIndex": 0, "explanation": "|Subsequent to the development of the \"Dirty Dozen,\" the \"Magnificent Seven\" list of human factors issues was developed and focused on positive aspects. These seven issues are: \n1. We work to accentuate the positive and eliminate the negative. \n2. Safety is not a game because the price of losing is too high. \n3. Just for today - zero error. \n4. We all do our part to prevent Murphy from hitting the jackpot. \n5. Our signature is our word and more precious than gold. \n6. We are all part of the team. \n7. We always work with a safety net.", "img": null}, {"id": "23-658", "deck": 23, "q": "The \"SHEL\" model is another human factors tool. The goal is to determine not only what the problem is, but also", "options": ["where and why it exists.", "how we prevent the problem.", "how many factors contribute to the error."], "correctIndex": 0, "explanation": "The goal of the SHEL (software/procedures, hardware/machines, environment/ambient, liveware/personnel) model is to determine not only what the problem is, but where and why it exists.", "img": null}, {"id": "23-659", "deck": 23, "q": "The three types of human error are", "options": ["omission, commission, and extraneous.", "active, latent, and stressor.", "mental, situational, and physiological."], "correctIndex": 0, "explanation": "Human error is the unintentional act of performing a task incorrectly that can potentially degrade the system. There are three types of human error: \n1. Omission: not performing an act or task. \n2. Commission: accomplishing a task incorrectly. \n3. Extraneous: performing a task not authorized.", "img": null}, {"id": "23-660", "deck": 23, "q": "14 CFR Part 65 contains information for the certification of", "options": ["pilots, flight Instructors, and ground instructors.", "airmen other than flight crewmembers.", "flight crewmembers other than pilots."], "correctIndex": 1, "explanation": "14 CFR Part 65, \"Certification: Airmen Other Than Flight Crewmembers,\" prescribes the requirements for the issuance of mechanic certificates and associated ratings, air traffic control operators, aircraft dispatchers, repairmen, and parachute riggers and the general operating rules for the holders of these certificates and ratings.", "img": null}, {"id": "23-661", "deck": 23, "q": "Which of the following is an instance when a special flight permit may not be issued?", "options": ["Flying passengers on a scheduled operation.", "Flying the aircraft to a location where repairs or maintenance can be performed.", "Flying a customer demonstration flight."], "correctIndex": 0, "explanation": "A special flight permit may be issued for an aircraft that may not currently meet applicable airworthiness requirements but is capable of safe flight, for the following purposes:\n1. Flying the aircraft to a base where repairs, alterations, or maintenance are to be performed, or to a point of storage.\n2. Delivering or exporting the aircraft.\n3. Production flight testing new production aircraft.\n4. Evacuating aircraft from areas of impending danger.\n5. Conducting customer demonstration flights in new production aircraft that have satisfactorily completed production flight tests.\n6. Operating an aircraft at a weight in excess of its maximum certificated takeoff weight under specific circumstances.\nTo request a special flight permit, the applicant must submit to the FAA: the purpose of the flight, the proposed itinerary, the crew required to operate the aircraft and its equipment, the ways in which the aircraft does not comply with the applicable airworthiness requirements, any restrictions the FAA deems necessary for the purpose of prescribing operating limitations. Flying passengers on a scheduled operation is not one of the allowed reasons for a special flight permit.", "img": null}, {"id": "23-662", "deck": 23, "q": "John and Nancy have been tasked with completing a hydraulic pump inspection. John is 5 feet 9 inches tall. Nancy is 5 feet 6 inches tall. What could result if Nancy is not tall enough to accomplish the task?", "options": ["Personal reference.", "Human error.", "Complacency."], "correctIndex": 1, "explanation": "Human error is the unintentional act of performing a task incorrectly that can potentially degrade the system.", "img": null}, {"id": "23-663", "deck": 23, "q": "14 CFR Part 65 Subpart D contains regulations regarding the certification of", "options": ["repairman.", "pilots.", "mechanics."], "correctIndex": 2, "explanation": "14 CFR Part 65, \"Certification: Airmen Other Than Flight Crewmembers,\" prescribes the requirements for the issuance of mechanic certificates and associated ratings, air traffic control operators, aircraft dispatchers, repairmen, and parachute riggers and the general operating rules for the holders of these certificates and ratings. Subpart D specifically covers mechanics. Subpart E specifically covers repairman. Pilot certification is covered in 14 CFR Part 61.", "img": null}];
